import { User, Permission, Teacher, Mentor, Management } from './models';
import { db } from './services/db';
import { trackDeviceLogin } from './deviceTracking';

const STORAGE_KEY = 'hcms_current_user';
const TEACHER_STORAGE_KEY = 'hcms_current_teacher';
const MENTOR_STORAGE_KEY = 'hcms_current_mentor';
const MANAGEMENT_STORAGE_KEY = 'hcms_current_management';
const LAST_ACTIVITY_KEY = 'hcms_last_activity';
const INACTIVITY_TIMEOUT = 10 * 60 * 60 * 1000; // 10 hours in milliseconds

export const hashPassword = async (password: string): Promise<string> => {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
};

export const login = async (username: string, password: string): Promise<{ user: User; permissions: Permission; error?: string } | null> => {
  try {
    const user = await db.findOne<User>('users', { username });
    if (!user) {
      return { user: {} as User, permissions: {} as Permission, error: 'Invalid username or password' };
    }
    const hashedPassword = await hashPassword(password);
    if (user.password_hash !== hashedPassword) {
      return { user: {} as User, permissions: {} as Permission, error: 'Invalid username or password' };
    }
    if (!user.is_active) {
      return { user: {} as User, permissions: {} as Permission, error: 'Account is inactive' };
    }
    let permissions = await db.findOne<Permission>('permissions', { user_id: user.id });
    if (!permissions) {
      permissions = getDefaultPermissions(user.id!);
    }
    const deviceCheck = await trackDeviceLogin(user.id!);
    if (!deviceCheck.allowed) {
      return { user, permissions, error: deviceCheck.reason };
    }
    const userWithPermissions = { user, permissions };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(userWithPermissions));
    updateLastActivity();
    return userWithPermissions;
  } catch (error: any) {
    console.error('Login error:', error);
    return { user: {} as User, permissions: {} as Permission, error: error.message || 'Login failed' };
  }
};

export const teacherLogin = async (phone: string): Promise<Teacher | null> => {
  try {
    const teacher = await db.findOne<Teacher>('teachers', { phone });
    if (!teacher) {
      return null;
    }
    localStorage.setItem(TEACHER_STORAGE_KEY, JSON.stringify(teacher));
    updateLastActivity();
    return teacher;
  } catch (error) {
    console.error('Teacher login error:', error);
    return null;
  }
};

export const mentorLogin = async (phone: string): Promise<Mentor | null> => {
  try {
    const mentor = await db.findOne<Mentor>('mentors', { phone });
    if (!mentor) {
      return null;
    }
    if (mentor.status !== 'active') {
      return null;
    }
    localStorage.setItem(MENTOR_STORAGE_KEY, JSON.stringify(mentor));
    updateLastActivity();
    return mentor;
  } catch (error) {
    console.error('Mentor login error:', error);
    return null;
  }
};

export const managementLogin = async (phone: string): Promise<Management | null> => {
  try {
    const management = await db.findOne<Management>('management', { phone });
    if (!management) {
      return null;
    }
    if (management.status !== 'active') {
      return null;
    }
    localStorage.setItem(MANAGEMENT_STORAGE_KEY, JSON.stringify(management));
    updateLastActivity();
    return management;
  } catch (error) {
    console.error('Management login error:', error);
    return null;
  }
};

export const logout = () => {
  localStorage.removeItem(STORAGE_KEY);
  localStorage.removeItem(TEACHER_STORAGE_KEY);
  localStorage.removeItem(MENTOR_STORAGE_KEY);
  localStorage.removeItem(MANAGEMENT_STORAGE_KEY);
  localStorage.removeItem(LAST_ACTIVITY_KEY);
};

export const getCurrentUser = (): { user: User; permissions: Permission } | null => {
  const stored = localStorage.getItem(STORAGE_KEY);
  if (!stored) return null;
  try {
    return JSON.parse(stored);
  } catch {
    return null;
  }
};

export const getCurrentTeacher = (): Teacher | null => {
  const stored = localStorage.getItem(TEACHER_STORAGE_KEY);
  if (!stored) return null;
  try {
    return JSON.parse(stored);
  } catch {
    return null;
  }
};

export const getCurrentMentor = (): Mentor | null => {
  const stored = localStorage.getItem(MENTOR_STORAGE_KEY);
  if (!stored) return null;
  try {
    return JSON.parse(stored);
  } catch {
    return null;
  }
};

export const getCurrentManagement = (): Management | null => {
  const stored = localStorage.getItem(MANAGEMENT_STORAGE_KEY);
  if (!stored) return null;
  try {
    return JSON.parse(stored);
  } catch {
    return null;
  }
};

export const generateUsername = (fullName: string): string => {
  const cleaned = fullName.toLowerCase().replace(/[^a-z0-9]/g, '');
  const random = Math.floor(Math.random() * 1000);
  return `${cleaned}${random}`;
};

export const generatePassword = (): string => {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz23456789';
  let password = '';
  for (let i = 0; i < 12; i++) {
    password += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return password;
};

const getDefaultPermissions = (userId: string): Permission => ({
  id: '',
  user_id: userId,
  can_delete_schools: false,
  can_manage_users: false,
  can_assign_training: false,
  can_view_reports: false,
  can_manage_schools: false,
  can_manage_teachers: false,
  can_manage_mentors: false,
  can_manage_admin_personnel: false,
  can_manage_training_programs: false,
});

export const updateLastActivity = (): void => {
  localStorage.setItem(LAST_ACTIVITY_KEY, Date.now().toString());
};

export const checkSessionTimeout = (): boolean => {
  const lastActivity = localStorage.getItem(LAST_ACTIVITY_KEY);
  if (!lastActivity) return false;
  const timeSinceLastActivity = Date.now() - parseInt(lastActivity, 10);
  return timeSinceLastActivity > INACTIVITY_TIMEOUT;
};

import 'dotenv/config';
import express, { Request, Response, NextFunction } from 'express';
import { fileURLToPath } from 'url';
import cors from 'cors';
import { mongodb } from './config/mongodb';
import { db } from './services/db';
import { Collections } from './config/mongodb';
import bcrypt from 'bcryptjs';

const app = express();
const PORT = process.env.PORT || 5000;

// Middleware
app.use(cors());
app.use(express.json({ limit: '50mb' }));

// Async wrapper
const asyncHandler = (fn: Function) => (req: Request, res: Response, next: NextFunction) =>
    Promise.resolve(fn(req, res, next)).catch(next);

// Connect to MongoDB on-demand in route handlers, not on module load
// This prevents crashes in serverless cold starts

app.get('/', (req, res) => {
    res.json({ status: 'ok', message: 'HCMS API Server is running' });
});

// Simple health check endpoint
app.get('/api/health', (req, res) => {
    res.json({
        status: 'ok',
        timestamp: new Date().toISOString(),
        env: {
            hasMongoUri: !!process.env.MONGODB_URI,
            hasMongoDbName: !!process.env.MONGODB_DB_NAME
        }
    });
});

// Login for admin or teacher (role = 'admin' | 'teacher')
app.post('/api/auth/login', asyncHandler(async (req: Request, res: Response) => {
    const { username, password, role } = req.body;

    // Connect to MongoDB on-demand
    await mongodb.connect();

    // Choose collection based on role
    const collection = role === 'teacher' ? Collections.TEACHERS : Collections.USERS;

    const user = await db.findOne(collection, { username, is_active: true });

    if (!user) {
        return res.status(401).json({
            error: 'Invalid username or password'
        });
    }

    const isValid = await bcrypt.compare(password, user.password_hash);
    if (!isValid) {
        return res.status(401).json({
            error: 'Invalid username or password'
        });
    }

    // Admins get permissions, teachers do not
    const permissions = role === 'teacher' ? null : await db.findOne(Collections.PERMISSIONS, { user_id: user.id });
    res.json({ user, permissions });
}));

// Teacher login via phone (existing route, keep unchanged)
app.post('/api/auth/teacher-login', asyncHandler(async (req: Request, res: Response) => {
    const { phone } = req.body;

    const teacher = await db.findOne(Collections.TEACHERS, {
        phone,
        is_active_login: true,
        status: 'active',
    });

    if (!teacher) {
        return res.status(401).json({ error: 'Invalid phone number or inactive account' });
    }

    res.json({ teacher });
}));

// Seed admin user endpoint
app.get('/api/seed-admin', asyncHandler(async (req: Request, res: Response) => {
    const username = 'admin';
    const password = 'admin123';
    const passwordHash = await bcrypt.hash(password, 10);

    const existingUser = await db.findOne(Collections.USERS, { username });
    let userId: string;

    if (existingUser) {
        await db.updateOne(Collections.USERS, { username }, {
            $set: {
                password_hash: passwordHash,
                is_active: true,
                updated_at: new Date().toISOString()
            }
        });
        userId = existingUser.id!;
    } else {
        const newUser: any = await db.insertOne(Collections.USERS, {
            username,
            password_hash: passwordHash,
            full_name: 'System Admin',
            role: 'admin',
            is_active: true,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
        });
        userId = newUser.id;
    }

    const permissions = {
        user_id: userId,
        can_delete_schools: true,
        can_manage_users: true,
        can_assign_training: true,
        can_view_reports: true,
        can_manage_schools: true,
        can_manage_teachers: true,
        can_manage_mentors: true,
        can_manage_admin_personnel: true,
        can_manage_training_programs: true,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString()
    };

    const existingPerms = await db.findOne(Collections.PERMISSIONS, { user_id: userId });
    if (existingPerms) {
        await db.updateOne(Collections.PERMISSIONS, { user_id: userId }, { $set: permissions });
    } else {
        await db.insertOne(Collections.PERMISSIONS, permissions);
    }

    res.json({
        success: true,
        message: 'Admin user created/updated',
        credentials: { username: 'admin', password: 'admin123' }
    });
});

/* ==================== TRAINING JOIN ==================== */

app.post(
    '/api/training/join',
    asyncHandler(async (req: Request, res: Response) => {
        const { teacherId, assignmentId } = req.body;

        // Verify teacher exists and is active
        const teacher = await db.findOne(Collections.TEACHERS, { id: teacherId, status: 'active' });
        if (!teacher) return res.status(404).json({ error: 'Teacher not found' });

        // Verify assignment exists and belongs to this teacher
        const assignment = await db.findOne(Collections.TRAINING_ASSIGNMENTS, {
            id: assignmentId,
            teacher_id: teacherId,
        });
        if (!assignment) return res.status(404).json({ error: 'Assignment not found or not assigned to this teacher' });

        // Insert attendance if not already present
        const existing = await db.findOne(Collections.TRAINING_ATTENDANCE, {
            teacher_id: teacherId,
            assignment_id: assignmentId,
        });
        if (existing) return res.status(200).json({ message: 'Already joined', attendance: existing });

        const attendance = await db.insertOne(Collections.TRAINING_ATTENDANCE, {
            teacher_id: teacherId,
            assignment_id: assignmentId,
            status: 'in_progress',
            joined_at: new Date().toISOString(),
        });

        res.status(201).json({ message: 'Joined training', attendance });
    })
);

/* ==================== GENERIC CRUD ==================== */

// Count documents
app.get(
    '/api/:collection/count',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection } = req.params;
        const { filter } = req.query;

        let filterObj = {};
        try {
            filterObj = filter ? JSON.parse(filter as string) : {};
        } catch {
            filterObj = {};
        }

        const count = await db.count(collection, filterObj);
        res.json({ count });
    })
);

// Get all documents
app.get(
    '/api/:collection',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection } = req.params;
        const { filter, sort, limit, skip } = req.query;

        const filterObj = filter ? JSON.parse(filter as string) : {};
        const sortObj = sort ? JSON.parse(sort as string) : undefined;
        const limitNum = limit ? parseInt(limit as string) : undefined;
        const skipNum = skip ? parseInt(skip as string) : undefined;

        const results = await db.find(collection, filterObj, {
            sort: sortObj,
            limit: limitNum,
            skip: skipNum,
        });
        res.json(results);
    })
);

// Get single document by id
app.get(
    '/api/:collection/:id',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection, id } = req.params;
        const result = await db.findById(collection, id);
        if (!result) return res.status(404).json({ error: 'Document not found' });
        res.json(result);
    })
);

// Create document
app.post(
    '/api/:collection',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection } = req.params;
        const document = req.body;
        const result = await db.insertOne(collection, document);
        res.status(201).json(result);
    })
);

// Bulk create
app.post(
    '/api/:collection/bulk',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection } = req.params;
        const documents = req.body;
        const results = await db.insertMany(collection, documents);
        res.status(201).json(results);
    })
);

// Update by id
app.put(
    '/api/:collection/:id',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection, id } = req.params;
        const updates = req.body;
        const success = await db.updateById(collection, id, updates);
        if (!success) return res.status(404).json({ error: 'Document not found or not updated' });
        res.json({ success: true, id });
    })
);

// Delete by id
app.delete(
    '/api/:collection/:id',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection, id } = req.params;
        const success = await db.deleteById(collection, id);
        if (!success) return res.status(404).json({ error: 'Document not found' });
        res.json({ success: true, id });
    })
);

// Upsert
app.post(
    '/api/:collection/upsert',
    asyncHandler(async (req: Request, res: Response) => {
        const { collection } = req.params;
        const { filter, document } = req.body;
        const result = await db.upsert(collection, filter, document);
        res.json(result);
    })
);

/* ==================== DASHBOARD STATS ==================== */

app.get(
    '/api/dashboard/stats',
    asyncHandler(async (req: Request, res: Response) => {
        const { role, assignedSchools } = req.query;

        let schoolFilter = {};
        let teacherFilter = {};

        if (role !== 'admin' && assignedSchools) {
            const schoolIds = JSON.parse(assignedSchools as string);
            schoolFilter = { id: { $in: schoolIds } };
            teacherFilter = { school_id: { $in: schoolIds } };
        }

        const [schools, teachers, mentors, programs, assignments] = await Promise.all([
            db.count(Collections.SCHOOLS, schoolFilter),
            db.count(Collections.TEACHERS, teacherFilter),
            db.count(Collections.MENTOR_SCHOOLS, {}),
            db.count(Collections.TRAINING_PROGRAMS, { status: 'active' }),
            db.find(Collections.TRAINING_ASSIGNMENTS, {}),
        ]);

        res.json({ schools, teachers, mentors, programs, assignments });
    })
);

/* ==================== ERROR HANDLING ==================== */

app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
    console.error('Error:', err);
    res.status(500).json({ error: err.message || 'Internal server error' });
});

/* ==================== SERVER START ==================== */
// For Vercel serverless, we only export the app
// Local development: run this file directly with tsx/ts-node

export default app;

import { Document, Filter, UpdateFilter, OptionalId, ObjectId } from 'mongodb';
import { mongodb, ensureConnected } from '../config/mongodb';

function toAppFormat<T extends { _id?: ObjectId; id?: string }>(doc: T | null): T | null {
    if (!doc) return null;
    const { _id, ...rest } = doc;
    return {
        ...rest,
        id: rest.id || _id?.toString(),
    } as T;
}

function isValidObjectId(id: string): boolean {
    return /^[0-9a-fA-F]{24}$/.test(id);
}

/**
 * Generic MongoDB database service  
 * Provides CRUD operations for all collections
 */
export class DatabaseService {
    async find<T extends Document>(
        collectionName: string,
        filter: Filter<T> = {},
        options: {
            sort?: Record<string, 1 | -1>;
            limit?: number;
            skip?: number;
        } = {}
    ): Promise<T[]> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        let cursor = collection.find(filter);

        if (options.sort) cursor = cursor.sort(options.sort);
        if (options.skip) cursor = cursor.skip(options.skip);
        if (options.limit) cursor = cursor.limit(options.limit);

        const results = await cursor.toArray();
        return results.map(doc => toAppFormat(doc as any) as T);
    }

    async findOne<T extends Document>(
        collectionName: string,
        filter: Filter<T>
    ): Promise<T | null> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);
        const result = await collection.findOne(filter);
        return toAppFormat(result as any) as T | null;
    }

    async findById<T extends Document>(
        collectionName: string,
        id: string
    ): Promise<T | null> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        // Handle both MongoDB ObjectIds and UUIDs
        let filter: any;
        if (isValidObjectId(id)) {
            filter = { _id: new ObjectId(id) };
        } else {
            // For UUIDs or other ID formats, search by id field
            filter = { id: id };
        }

        const result = await collection.findOne(filter);
        return toAppFormat(result as any) as T | null;
    }

    async insertOne<T extends Document>(
        collectionName: string,
        document: OptionalId<T>
    ): Promise<T> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        const docToInsert = {
            ...document,
            created_at: document.created_at || new Date().toISOString(),
            updated_at: document.updated_at || new Date().toISOString(),
        } as OptionalId<T>;

        const result = await collection.insertOne(docToInsert as any);
        return {
            ...docToInsert,
            _id: result.insertedId,
            id: result.insertedId.toString(),
        } as T;
    }

    async insertMany<T extends Document>(
        collectionName: string,
        documents: OptionalId<T>[]
    ): Promise<T[]> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        const docsToInsert = documents.map(doc => ({
            ...doc,
            created_at: doc.created_at || new Date().toISOString(),
            updated_at: doc.updated_at || new Date().toISOString(),
        }));

        const result = await collection.insertMany(docsToInsert as any);
        return docsToInsert.map((doc, index) => ({
            ...doc,
            _id: result.insertedIds[index],
            id: result.insertedIds[index].toString(),
        })) as T[];
    }

    async updateOne<T extends Document>(
        collectionName: string,
        filter: Filter<T>,
        update: UpdateFilter<T>
    ): Promise<boolean> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        const updateDoc = {
            ...update,
            $set: {
                ...((update as any).$set || {}),
                updated_at: new Date().toISOString(),
            },
        };

        const result = await collection.updateOne(filter, updateDoc);
        return result.modifiedCount > 0;
    }

    async updateById<T extends Document>(
        collectionName: string,
        id: string,
        update: Partial<T>
    ): Promise<boolean> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        // Handle both MongoDB ObjectIds and UUIDs
        let filter: any;
        if (isValidObjectId(id)) {
            filter = { _id: new ObjectId(id) };
        } else {
            // For UUIDs or other ID formats, search by id field
            filter = { id: id };
        }

        const result = await collection.updateOne(
            filter,
            {
                $set: {
                    ...update,
                    updated_at: new Date().toISOString(),
                } as any,
            }
        );

        return result.modifiedCount > 0;
    }

    async deleteOne<T extends Document>(
        collectionName: string,
        filter: Filter<T>
    ): Promise<boolean> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);
        const result = await collection.deleteOne(filter);
        return result.deletedCount > 0;
    }

    async deleteById(collectionName: string, id: string): Promise<boolean> {
        await ensureConnected();
        const collection = mongodb.getCollection(collectionName);

        // Handle both MongoDB ObjectIds and UUIDs
        let filter: any;
        if (isValidObjectId(id)) {
            filter = { _id: new ObjectId(id) };
        } else {
            // For UUIDs or other ID formats, search by id field
            filter = { id: id };
        }

        const result = await collection.deleteOne(filter);
        return result.deletedCount > 0;
    }

    async count<T extends Document>(
        collectionName: string,
        filter: Filter<T> = {}
    ): Promise<number> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);
        return await collection.countDocuments(filter);
    }

    async upsert<T extends Document>(
        collectionName: string,
        filter: Filter<T>,
        document: Partial<T>
    ): Promise<T> {
        await ensureConnected();
        const collection = mongodb.getCollection<T>(collectionName);

        const result = await collection.findOneAndUpdate(
            filter,
            {
                $set: {
                    ...document,
                    updated_at: new Date().toISOString(),
                } as any,
                $setOnInsert: {
                    created_at: new Date().toISOString(),
                } as any,
            },
            { upsert: true, returnDocument: 'after' }
        );

        return toAppFormat(result as any) as T;
    }
}

export const db = new DatabaseService();

import 'dotenv/config';
import express, { Request, Response } from 'express';
import { mongodb } from '../server/src/config/mongodb';
import { db } from '../server/src/services/db';
import { Collections } from '../server/src/config/mongodb';
import bcrypt from 'bcryptjs';
import serverless from 'serverless-http';

const app = express();

app.get('/api/seed-admin', async (req: Request, res: Response) => {
    try {
        await mongodb.connect();

        const username = 'admin';
        const password = 'admin123';
        const passwordHash = await bcrypt.hash(password, 10);

        // Check if user exists
        const existingUser = await db.findOne(Collections.USERS, { username });

        let userId: string;

        if (existingUser) {
            const success = await db.updateOne(Collections.USERS, { username }, {
                $set: {
                    password_hash: passwordHash,
                    is_active: true,
                    updated_at: new Date().toISOString()
                }
            });
            userId = existingUser.id!;
        } else {
            const newUser: any = await db.insertOne(Collections.USERS, {
                username,
                password_hash: passwordHash,
                full_name: 'System Admin',
                role: 'admin',
                is_active: true,
                created_at: new Date().toISOString(),
                updated_at: new Date().toISOString()
            });
            userId = newUser.id;
        }

        // Update permissions
        const permissions = {
            user_id: userId,
            can_delete_schools: true,
            can_manage_users: true,
            can_assign_training: true,
            can_view_reports: true,
            can_manage_schools: true,
            can_manage_teachers: true,
            can_manage_mentors: true,
            can_manage_admin_personnel: true,
            can_manage_training_programs: true,
            created_at: new Date().toISOString(),
            updated_at: new Date().toISOString()
        };

        const existingPerms = await db.findOne(Collections.PERMISSIONS, { user_id: userId });

        if (existingPerms) {
            await db.updateOne(Collections.PERMISSIONS, { user_id: userId }, {
                $set: permissions
            });
        } else {
            await db.insertOne(Collections.PERMISSIONS, permissions);
        }

        res.json({
            success: true,
            message: 'Admin user seeded successfully',
            credentials: {
                username: 'admin',
                password: 'admin123'
            }
        });

