async function debug() {
    console.log('--- Debugging Parveen Followups ---');

    // Find Parveen
    const users = await db.find<any>(Collections.USERS, {});
    const parveen = users.find((u: any) => u.full_name?.toLowerCase().includes('parveen'));

    if (!parveen) {
