    // 1. Get Supabase Teachers
    const supabaseTeachers = await fetchAllTeachersFromSupabase();
    console.log(`Supabase Count: ${supabaseTeachers.length}`);

    // 2. Get Firestore Teachers
    const serviceAccountPath = path.join(__dirname, '../../hcms-680e6-firebase-adminsdk-fbsvc-2ecb819931.json');
    const serviceAccount = JSON.parse(fs.readFileSync(serviceAccountPath, 'utf8'));

    initializeApp({
        credential: cert(serviceAccount)
    });
    const db = getFirestore();

    const snapshot = await db.collection('teachers').get();
    console.log(`Firestore Count: ${snapshot.size}`);

    // 3. Compare
    const supabaseIds = new Set(supabaseTeachers.map(t => t.id));
    const firestoreIds = new Set(snapshot.docs.map(d => d.id));

    const missingInFirestore = supabaseTeachers.filter(t => !firestoreIds.has(t.id));
    const missingInSupabase = snapshot.docs.filter(d => !supabaseIds.has(d.id));

    console.log(`\nMissing in Firestore: ${missingInFirestore.length}`);
    console.log(`Missing in Supabase: ${missingInSupabase.length}`);

    if (missingInFirestore.length > 0) {
        console.log('\nFirst 5 missing IDs:');
        missingInFirestore.slice(0, 5).forEach(t => console.log(`- ${t.id}`));

        // Save missing IDs to file for next step
        const missingIds = missingInFirestore.map(t => t.id);
        fs.writeFileSync(path.join(__dirname, 'missing_teacher_ids.json'), JSON.stringify(missingIds, null, 2));
        console.log(`\nSaved ${missingIds.length} missing IDs to missing_teacher_ids.json`);
    }
}

