async function getB4Phones() {
    try {
        console.log('Initializing Firebase Admin...');
        const serviceAccountPath = path.resolve(__dirname, '../../hcms-680e6-firebase-adminsdk-fbsvc-2ecb819931.json');

        if (!fs.existsSync(serviceAccountPath)) {
