import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import {
    BarChart3,
    LineChart,
    Download,
    TrendingUp,
    Users,
    BookOpen,
    Filter,
    AlertCircle,
    Search,
    Clock
} from 'lucide-react';
import {
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    LineChart as RechartsLineChart,
    Line
} from 'recharts';
import { TrainingProgram, TrainingAssignment, MentorTrainingAssignment, User, Teacher, Mentor, School, TrainingAttendance } from '../lib/models';

interface Props {
    currentUser: User;
}

export default function AcademicsAnalytics({ currentUser }: Props) {
    const [loading, setLoading] = useState(true);
    const [stats, setStats] = useState({
        totalParticipants: 0,
        avgPhonics: 0,
        avgVocabulary: 0,
        phonicsDistribution: [] as any[],
        vocabularyDistribution: [] as any[],
        schoolPerformance: [] as any[],
    });
    const [atRiskParticipants, setAtRiskParticipants] = useState<any[]>([]);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => {
        if (currentUser) {
            loadData();
        }
    }, [currentUser]);

    const loadData = async () => {
        setLoading(true);
        try {
            // 1. Fetch Training Programs
            const allPrograms = await db.find<TrainingProgram>(Collections.TRAINING_PROGRAMS, {});
            const c10Programs = allPrograms.filter(p =>
                (p.title || '').toLowerCase().includes('c10') ||
                (p.title || '').toLowerCase().includes('c.10')
            );

            if (c10Programs.length === 0) {
                setLoading(false);
                return;
            }

            const c10ProgramIds = c10Programs.map(p => p.id!);

            // 2. Fetch Assignments & Attendance
            const [
                teacherAssignments,
                mentorAssignments,
                schoolsData,
                teachersData,
                mentorsData,
                schoolAssignments,
                teacherAttendance,
                mentorAttendance
            ] = await Promise.all([
                db.find<TrainingAssignment>(Collections.TRAINING_ASSIGNMENTS, { training_program_id: { $in: c10ProgramIds } }),
                db.find<MentorTrainingAssignment>(Collections.MENTOR_TRAINING_ASSIGNMENTS, { training_program_id: { $in: c10ProgramIds } }),
                db.find<School>(Collections.SCHOOLS, {}),
                db.find<Teacher>(Collections.TEACHERS, {}),
                db.find<Mentor>(Collections.MENTORS, {}),
                db.find(Collections.SCHOOL_ASSIGNMENTS, { employee_id: currentUser.id }),
                db.find<TrainingAttendance>(Collections.TRAINING_ATTENDANCE, { training_program_id: { $in: c10ProgramIds } }),
                db.find<any>(Collections.MENTOR_TRAINING_ATTENDANCE, { training_program_id: { $in: c10ProgramIds } })
            ]);

            // Determine visible schools for the current user
            let visibleSchoolIds: string[] = [];
            if (currentUser.role === 'admin') {
                visibleSchoolIds = schoolsData.map(s => s.id!);
            } else {
                visibleSchoolIds = schoolAssignments.map((sa: any) => sa.school_id);
            }

            const allAssignments = [...(teacherAssignments || []), ...(mentorAssignments || [])];
            const allAttendance = [...(teacherAttendance || []), ...(mentorAttendance || [])];

            let totalPhonics = 0;
            let totalVocabulary = 0;
            let countPhonics = 0;
            let countVocabulary = 0;

            const phonicsScores: number[] = [];
            const vocabScores: number[] = [];
            const riskyList: any[] = [];

            allAssignments.forEach(assignment => {
                // Identify User
                const isTeacher = 'teacher_id' in assignment;
                const userId = isTeacher ? (assignment as TrainingAssignment).teacher_id : (assignment as MentorTrainingAssignment).mentor_id;
                const user = isTeacher ? teachersData.find(t => t.id === userId) : mentorsData.find(m => m.id === userId);

                if (!user || (user.school_id && !visibleSchoolIds.includes(user.school_id))) {
                    return; // Skip if user not managed by this employee
                }

                const school = schoolsData.find(s => s.id === user.school_id);
                const marks = assignment.marks_data || {};
                const phonicsKey = Object.keys(marks).find(k => k.toLowerCase().includes('phonics'));
                const vocabKey = Object.keys(marks).find(k => k.toLowerCase().includes('vocabulary'));

                let phonicsScore = 0;
                let vocabScore = 0;
                let hasPhonics = false;
                let hasVocab = false;

                // Marks Processing
                if (phonicsKey && typeof marks[phonicsKey] === 'number') {
                    const score = marks[phonicsKey];
                    const program = c10Programs.find(p => p.id === assignment.training_program_id);
                    const subject = program?.marks_configuration?.subjects.find(s => s.name === phonicsKey);

                    let normalized = score;
                    if (subject && subject.max_marks > 0) {
                        normalized = Math.round((score / subject.max_marks) * 100);
                    }
                    phonicsScore = normalized;
                    totalPhonics += normalized;
                    countPhonics++;
                    phonicsScores.push(normalized);
                    hasPhonics = true;
                }

                if (vocabKey && typeof marks[vocabKey] === 'number') {
                    const score = marks[vocabKey];
                    const program = c10Programs.find(p => p.id === assignment.training_program_id);
                    const subject = program?.marks_configuration?.subjects.find(s => s.name === vocabKey);

                    let normalized = score;
                    if (subject && subject.max_marks > 0) {
                        normalized = Math.round((score / subject.max_marks) * 100);
                    }
                    vocabScore = normalized;
                    totalVocabulary += normalized;
                    countVocabulary++;
                    vocabScores.push(normalized);
                    hasVocab = true;
                }

                // Attendance Processing
                // C10 has fixed 16 sessions
                const totalSessions = 16;
                const userAttendance = allAttendance.filter(r =>
                    (isTeacher ? r.teacher_id === userId : r.mentor_id === userId) &&
                    r.training_program_id === assignment.training_program_id &&
                    (r.status === 'present' || r.status === 'late')
                );
                const presentCount = userAttendance.length;
                const attendancePercentage = Math.round((presentCount / totalSessions) * 100);


                // Check for Risk (Score < 60% OR Attendance < 75%)
                const lowPhonics = hasPhonics && phonicsScore < 60;
                const lowVocab = hasVocab && vocabScore < 60;
                const lowAttendance = attendancePercentage < 75;

                if (lowPhonics || lowVocab || lowAttendance) {
                    riskyList.push({
                        id: assignment.id,
                        name: `${user.first_name} ${user.last_name}`,
                        role: isTeacher ? 'Teacher' : 'Mentor',
                        schoolName: school?.name || 'Unknown School',
                        phonics: hasPhonics ? phonicsScore : 'N/A',
                        vocabulary: hasVocab ? vocabScore : 'N/A',
                        attendance: attendancePercentage,
                        lowPhonics,
                        lowVocab,
                        lowAttendance,
                        programName: c10Programs.find(p => p.id === assignment.training_program_id)?.title || 'Unknown Program'
                    });
                }
            });

            // Prepare Chart Data
            const buckets = ['0-20', '21-40', '41-60', '61-80', '81-100'];
            const phonicsDist = buckets.map(bucket => ({ name: bucket, count: 0 }));
            const vocabDist = buckets.map(bucket => ({ name: bucket, count: 0 }));

            phonicsScores.forEach(score => {
                let idx = 0;
                if (score > 80) idx = 4;
                else if (score > 60) idx = 3;
                else if (score > 40) idx = 2;
                else if (score > 20) idx = 1;
                else idx = 0;
                phonicsDist[idx].count++;
            });

            vocabScores.forEach(score => {
                let idx = 0;
                if (score > 80) idx = 4;
                else if (score > 60) idx = 3;
                else if (score > 40) idx = 2;
                else if (score > 20) idx = 1;
                else idx = 0;
                vocabDist[idx].count++;
            });

            setStats({
                totalParticipants: phonicsScores.length, // Approx
                avgPhonics: countPhonics > 0 ? Math.round(totalPhonics / countPhonics) : 0,
                avgVocabulary: countVocabulary > 0 ? Math.round(totalVocabulary / countVocabulary) : 0,
                phonicsDistribution: phonicsDist,
                vocabularyDistribution: vocabDist,
                schoolPerformance: [],
            });

            setAtRiskParticipants(riskyList);

        } catch (error) {
            console.error('Error loading analytics data:', error);
        }
        setLoading(false);
    };

    const filteredRiskyList = atRiskParticipants.filter(p =>
        p.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
        p.schoolName.toLowerCase().includes(searchTerm.toLowerCase())
    );

    if (loading) {
        return <div className="flex justify-center items-center h-screen">Loading...</div>;
    }

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="bg-white rounded-lg shadow-md p-6">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="bg-indigo-100 p-3 rounded-lg">
                            <TrendingUp className="text-indigo-600" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-gray-900">Academics Analytics</h3>
                            <p className="text-sm text-gray-600">Performance analytics for C10 Training (Phonics & Vocabulary)</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* KPI Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Total Participants</p>
                            <p className="text-3xl font-bold text-gray-900">{stats.totalParticipants}</p>
                        </div>
                        <Users className="text-gray-400" size={40} />
                    </div>
                </div>
                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Avg. Phonics Score</p>
                            <p className="text-3xl font-bold text-blue-600">{stats.avgPhonics}%</p>
                        </div>
                        <BookOpen className="text-blue-400" size={40} />
                    </div>
                </div>
                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Avg. Vocabulary Score</p>
                            <p className="text-3xl font-bold text-green-600">{stats.avgVocabulary}%</p>
                        </div>
                        <BookOpen className="text-green-400" size={40} />
                    </div>
                </div>
            </div>

            {/* Charts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

                {/* Phonics Distribution */}
                <div className="bg-white rounded-lg shadow-md p-6">
                    <h4 className="font-semibold text-gray-900 mb-6 flex items-center gap-2">
                        <BarChart3 size={20} className="text-blue-600" />
                        Phonics Score Distribution
                    </h4>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={stats.phonicsDistribution}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                <XAxis dataKey="name" label={{ value: 'Score Range (%)', position: 'insideBottom', offset: -5 }} />
                                <YAxis allowDecimals={false} label={{ value: 'Participants', angle: -90, position: 'insideLeft' }} />
                                <Tooltip
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{ fill: '#eff6ff' }}
                                />
                                <Bar dataKey="count" name="Participants" fill="#3B82F6" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                {/* Vocabulary Distribution */}
                <div className="bg-white rounded-lg shadow-md p-6">
                    <h4 className="font-semibold text-gray-900 mb-6 flex items-center gap-2">
                        <BarChart3 size={20} className="text-green-600" />
                        Vocabulary Score Distribution
                    </h4>
                    <div className="h-[300px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={stats.vocabularyDistribution}>
                                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                                <XAxis dataKey="name" label={{ value: 'Score Range (%)', position: 'insideBottom', offset: -5 }} />
                                <YAxis allowDecimals={false} label={{ value: 'Participants', angle: -90, position: 'insideLeft' }} />
                                <Tooltip
                                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                                    cursor={{ fill: '#eff6ff' }}
                                />
                                <Bar dataKey="count" name="Participants" fill="#10B981" radius={[4, 4, 0, 0]} />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            </div>

            {/* Teachers Needing Support */}
            <div className="bg-white rounded-lg shadow-md overflow-hidden">
                <div className="p-6 border-b border-gray-200">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <div>
                            <h4 className="flex items-center gap-2 text-lg font-bold text-red-600">
                                <AlertCircle size={20} />
                                Teachers Needing Support
                            </h4>
                            <p className="text-sm text-gray-600 mt-1">Participants with scores below 60% or attendance below 75%</p>
                        </div>

                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
                            <input
                                type="text"
                                placeholder="Search teacher or school..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-500"
                            />
                        </div>
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Teacher/Mentor</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">School</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Phonics</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Vocabulary</th>
                                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Attendance</th>
                                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                            </tr>
                        </thead>
                        <tbody className="bg-white divide-y divide-gray-200">
                            {filteredRiskyList.length === 0 ? (
                                <tr>
                                    <td colSpan={6} className="px-6 py-12 text-center text-gray-500">
                                        No participants found needing support based on current criteria.
                                    </td>
                                </tr>
                            ) : (
                                filteredRiskyList.map((item) => (
                                    <tr key={item.id} className="hover:bg-red-50 transition-colors">
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-medium text-gray-900">{item.name}</div>
                                            <div className="text-xs text-gray-500">{item.role}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-600">{item.schoolName}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-center">
                                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${item.lowPhonics ? 'bg-red-100 text-red-800' : 'bg-gray-100 text-gray-800'
                                                }`}>
                                                {item.phonics !== 'N/A' ? `${item.phonics}%` : 'N/A'}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-center">
                                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${item.lowVocab ? 'bg-red-100 text-red-800' : 'bg-gray-100 text-gray-800'
                                                }`}>
                                                {item.vocabulary !== 'N/A' ? `${item.vocabulary}%` : 'N/A'}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap text-center">
                                            <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${item.lowAttendance ? 'bg-red-100 text-red-800' : 'bg-green-100 text-green-800'
                                                }`}>
                                                {item.attendance}%
                                            </span>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="flex flex-col gap-1">
                                                {item.lowPhonics && (
                                                    <span className="text-xs text-red-600 flex items-center gap-1">
                                                        <AlertCircle size={12} /> Low Phonics
                                                    </span>
                                                )}
                                                {item.lowVocab && (
                                                    <span className="text-xs text-red-600 flex items-center gap-1">
                                                        <AlertCircle size={12} /> Low Vocabulary
                                                    </span>
                                                )}
                                                {item.lowAttendance && (
                                                    <span className="text-xs text-red-600 flex items-center gap-1">
                                                        <Clock size={12} /> Low Attendance
                                                    </span>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Shield, Search, Filter } from 'lucide-react';

export default function ActivityLogs() {
    const [logs, setLogs] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [roleFilter, setRoleFilter] = useState('all');
    const [actionFilter, setActionFilter] = useState('all');

    useEffect(() => { loadLogs(); }, []);

    const loadLogs = async () => {
        try {
            setLoading(true);
            const data = await db.find('activity_logs', {});
            setLogs(data.sort((a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()));
        } catch (error) {
            console.error('Error loading logs:', error);
        } finally {
            setLoading(false);
        }
    };

    const actions = [...new Set(logs.map(l => l.action).filter(Boolean))];
    const roles = [...new Set(logs.map(l => l.user_role).filter(Boolean))];

    const filtered = logs.filter(log => {
        const matchSearch = (log.user_name || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
            (log.action || '').toLowerCase().includes(searchTerm.toLowerCase());
        const matchRole = roleFilter === 'all' || log.user_role === roleFilter;
        const matchAction = actionFilter === 'all' || log.action === actionFilter;
        return matchSearch && matchRole && matchAction;
    });

    return (
        <div className="p-6">
            <div className="flex items-center gap-3 mb-6">
                <Shield className="text-blue-600" size={28} />
                <h2 className="text-2xl font-bold text-gray-800">Activity Logs</h2>
                <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-sm">{logs.length} entries</span>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6 flex flex-wrap gap-3">
                <div className="relative flex-1 min-w-[200px]">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
                <select value={roleFilter} onChange={e => setRoleFilter(e.target.value)} className="px-3 py-2 border rounded-lg">
                    <option value="all">All Roles</option>
                    {roles.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
                <select value={actionFilter} onChange={e => setActionFilter(e.target.value)} className="px-3 py-2 border rounded-lg">
                    <option value="all">All Actions</option>
                    {actions.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
            </div>

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-gray-50">
                                <tr>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">User</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Role</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Action</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">View</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Date</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {filtered.slice(0, 200).map((log, idx) => (
                                    <tr key={log.id || idx} className="hover:bg-gray-50">
                                        <td className="px-4 py-3 text-sm font-medium text-gray-800">{log.user_name || '-'}</td>
                                        <td className="px-4 py-3"><span className="px-2 py-1 bg-blue-100 text-blue-700 rounded-full text-xs capitalize">{log.user_role || '-'}</span></td>
                                        <td className="px-4 py-3 text-sm text-gray-600">{log.action || '-'}</td>
                                        <td className="px-4 py-3 text-sm text-gray-500">{log.view || '-'}</td>
                                        <td className="px-4 py-3 text-sm text-gray-400">{log.created_at ? new Date(log.created_at).toLocaleString() : '-'}</td>
                                    </tr>
                                ))}
                                {filtered.length === 0 && <tr><td colSpan={5} className="text-center py-8 text-gray-500">No activity logs found</td></tr>}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { AdminPersonnel, Permission } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Plus, Edit2, Trash2, Briefcase } from 'lucide-react';
import ConfirmDialog from './ConfirmDialog';

interface Props {
  currentPermissions: Permission;
}

export default function AdminPersonnelManagement({ currentPermissions }: Props) {
  const [personnel, setPersonnel] = useState<AdminPersonnel[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [confirmDialog, setConfirmDialog] = useState<{ isOpen: boolean; title: string; message: string; onConfirm: () => void } | null>(null);
  const [editingPersonnel, setEditingPersonnel] = useState<AdminPersonnel | null>(null);
  const [formData, setFormData] = useState({
    first_name: '',
    last_name: '',
    email: '',
    phone: '',
    position: '',
    department: '',
    hire_date: '',
    status: 'active' as 'active' | 'inactive',
  });

  const canManage = currentPermissions.can_manage_admin_personnel;

  useEffect(() => {
    loadPersonnel();
  }, []);

  const loadPersonnel = async () => {
    setLoading(true);
    const data = await db.find<AdminPersonnel>(Collections.ADMIN_PERSONNEL, {}, { sort: { last_name: 1 } });
    setPersonnel(data);
    setLoading(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const data = {
      ...formData,
      hire_date: formData.hire_date || null,
    };

    if (editingPersonnel && editingPersonnel.id) {
      await db.updateById<AdminPersonnel>(Collections.ADMIN_PERSONNEL, editingPersonnel.id, data);
    } else {
      await db.insertOne<AdminPersonnel>(Collections.ADMIN_PERSONNEL, {
        ...data,
        created_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      } as any);
    }

    loadPersonnel();
    resetForm();
  };

  const handleDelete = async (id: string) => {
    setConfirmDialog({
      isOpen: true,
      title: 'Delete Personnel',
      message: 'Are you sure you want to delete this personnel record? This action cannot be undone.',
      onConfirm: async () => {
        await db.deleteById(Collections.ADMIN_PERSONNEL, id);
        setConfirmDialog(null);
        loadPersonnel();
      }
    });
  };

  const resetForm = () => {
    setFormData({
      first_name: '',
      last_name: '',
      email: '',
      phone: '',
      position: '',
      department: '',
      hire_date: '',
      status: 'active',
    });
    setEditingPersonnel(null);
    setShowModal(false);
  };

  const openEditModal = (person: AdminPersonnel) => {
    setEditingPersonnel(person);
    setFormData({
      first_name: person.first_name,
      last_name: person.last_name,
      email: person.email,
      phone: person.phone,
      position: person.position,
      department: person.department,
      hire_date: person.hire_date || '',
      status: person.status,
    });
    setShowModal(true);
  };

  const groupByDepartment = () => {
    const grouped: Record<string, AdminPersonnel[]> = {};
    personnel.forEach(person => {
      const dept = person.department || 'Unassigned';
      if (!grouped[dept]) grouped[dept] = [];
      grouped[dept].push(person);
    });
    return grouped;
  };

  if (loading) {
    return <div className="flex justify-center items-center h-64">Loading...</div>;
  }

  const groupedPersonnel = groupByDepartment();

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Administrative Personnel</h2>
          <p className="text-gray-600 mt-1">Manage administrative and management staff</p>
        </div>
        {canManage && (
          <button
            onClick={() => setShowModal(true)}
            className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
          >
            <Plus size={20} />
            Add Personnel
          </button>
        )}
      </div>

      <div className="space-y-6">
        {Object.entries(groupedPersonnel).map(([department, people]) => (
          <div key={department} className="bg-white rounded-lg shadow overflow-hidden">
            <div className="bg-gray-50 px-6 py-3 border-b border-gray-200">
              <h3 className="text-lg font-semibold text-gray-900">{department}</h3>
              <p className="text-sm text-gray-600">{people.length} {people.length === 1 ? 'person' : 'people'}</p>
            </div>
            <div className="divide-y divide-gray-200">
              {people.map((person) => (
                <div key={person.id} className="p-6 hover:bg-gray-50 transition-colors">
                  <div className="flex items-start justify-between">
                    <div className="flex items-start gap-4">
                      <div className="bg-orange-100 p-3 rounded-lg">
                        <Briefcase className="text-orange-600" size={24} />
                      </div>
                      <div>
                        <h4 className="font-bold text-lg text-gray-900">{person.first_name} {person.last_name}</h4>
                        <p className="text-sm text-gray-600 mb-2">{person.position || 'No position specified'}</p>
                        <div className="grid grid-cols-2 gap-x-6 gap-y-1 text-sm text-gray-600">
                          <div>
                            <span className="font-medium">Email:</span> {person.email || 'N/A'}
                          </div>
                          <div>
                            <span className="font-medium">Phone:</span> {person.phone || 'N/A'}
                          </div>
                          {person.hire_date && (
                            <div>
                              <span className="font-medium">Hire Date:</span> {new Date(person.hire_date).toLocaleDateString()}
                            </div>
                          )}
                          <div>
                            <span className={`px-2 py-1 text-xs rounded-full ${person.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'
                              }`}>
                              {person.status}
                            </span>
                          </div>
                        </div>
                      </div>
                    </div>
                    {canManage && (
                      <div className="flex gap-2">
                        <button
                          onClick={() => openEditModal(person)}
                          className="text-blue-600 hover:text-blue-900 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                          <Edit2 size={18} />
                        </button>
                        <button
                          onClick={() => handleDelete(person.id!)}
                          className="text-red-600 hover:text-red-900 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        >
                          <Trash2 size={18} />
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      {personnel.length === 0 && (
        <div className="text-center py-12 bg-gray-50 rounded-lg">
          <Briefcase className="mx-auto text-gray-400 mb-4" size={48} />
          <p className="text-gray-600">No administrative personnel found. Add your first record to get started.</p>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
            <h3 className="text-xl font-bold mb-4">{editingPersonnel ? 'Edit Personnel' : 'Add New Personnel'}</h3>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">First Name *</label>
                  <input
                    type="text"
                    required
                    value={formData.first_name}
                    onChange={(e) => setFormData({ ...formData, first_name: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Last Name *</label>
                  <input
                    type="text"
                    required
                    value={formData.last_name}
                    onChange={(e) => setFormData({ ...formData, last_name: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Email</label>
                  <input
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                  <input
                    type="tel"
                    value={formData.phone}
                    onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Position</label>
                  <input
                    type="text"
                    value={formData.position}
                    onChange={(e) => setFormData({ ...formData, position: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Department</label>
                  <input
                    type="text"
                    value={formData.department}
                    onChange={(e) => setFormData({ ...formData, department: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Hire Date</label>
                  <input
                    type="date"
                    value={formData.hire_date}
                    onChange={(e) => setFormData({ ...formData, hire_date: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value as any })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    <option value="active">Active</option>
                    <option value="inactive">Inactive</option>
                  </select>
                </div>
              </div>

              <div className="flex gap-2 pt-4">
                <button
                  type="button"
                  onClick={resetForm}
                  className="flex-1 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors"
                >
                  {editingPersonnel ? 'Update' : 'Create'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {confirmDialog && (
        <ConfirmDialog
          isOpen={confirmDialog.isOpen}
          title={confirmDialog.title}
          message={confirmDialog.message}
          confirmText="Delete"
          cancelText="Cancel"
          onConfirm={confirmDialog.onConfirm}
          onCancel={() => setConfirmDialog(null)}
          type="danger"
        />
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { MessageSquare, Search, Check, Clock, Trash2 } from 'lucide-react';

export function AdminSuggestions() {
    const [suggestions, setSuggestions] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    useEffect(() => { loadSuggestions(); }, []);

    const loadSuggestions = async () => {
        try {
            setLoading(true);
            const data = await db.find('suggestions', {});
            setSuggestions(data.sort((a: any, b: any) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()));
        } catch (error) {
            console.error('Error loading suggestions:', error);
        } finally {
            setLoading(false);
        }
    };

    const updateStatus = async (id: string, status: string) => {
        try {
            await db.update('suggestions', id, { status, updated_at: new Date().toISOString() });
            loadSuggestions();
        } catch (error) {
            console.error('Error updating suggestion:', error);
        }
    };

    const deleteSuggestion = async (id: string) => {
        if (!confirm('Delete this suggestion?')) return;
        try {
            await db.delete('suggestions', id);
            loadSuggestions();
        } catch (error) {
            console.error('Error deleting:', error);
        }
    };

    const filtered = suggestions.filter(s =>
        (s.content || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
        (s.user_name || '').toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-6">
            <div className="flex items-center gap-3 mb-6">
                <MessageSquare className="text-blue-600" size={28} />
                <h2 className="text-2xl font-bold text-gray-800">Employee Suggestions</h2>
                <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-sm">{suggestions.length}</span>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6">
                <div className="relative">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search suggestions..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="space-y-3">
                    {filtered.map(s => (
                        <div key={s.id} className="bg-white rounded-xl shadow-sm border p-5">
                            <div className="flex items-start justify-between">
                                <div className="flex-1">
                                    <div className="flex items-center gap-2 mb-2">
                                        <span className="font-semibold text-gray-800">{s.user_name || 'Anonymous'}</span>
                                        <span className={`px-2 py-0.5 rounded-full text-xs ${s.status === 'reviewed' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'}`}>
                                            {s.status || 'pending'}
                                        </span>
                                    </div>
                                    <p className="text-sm text-gray-600">{s.content}</p>
                                    <p className="text-xs text-gray-400 mt-2">{s.created_at ? new Date(s.created_at).toLocaleString() : ''}</p>
                                </div>
                                <div className="flex gap-2 ml-4">
                                    {s.status !== 'reviewed' && (
                                        <button onClick={() => updateStatus(s.id, 'reviewed')} className="p-2 text-green-600 hover:bg-green-50 rounded-lg" title="Mark reviewed">
                                            <Check size={16} />
                                        </button>
                                    )}
                                    <button onClick={() => deleteSuggestion(s.id)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg" title="Delete">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                    {filtered.length === 0 && <p className="text-center text-gray-500 py-8">No suggestions found</p>}
                </div>
            )}
        </div>
    );
}

import { useState, useRef, useEffect } from 'react';
import { Clock } from 'lucide-react';

interface Props {
    value: string; // HH:MM format
    onChange: (time: string) => void;
    label: string;
}

export default function AnalogTimePicker({ value, onChange, label }: Props) {
    const [isOpen, setIsOpen] = useState(false);
    const [hour, setHour] = useState(0);
    const [minute, setMinute] = useState(0);
    const [isDragging, setIsDragging] = useState<'hour' | 'minute' | null>(null);
    const clockRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (value) {
            const [h, m] = value.split(':').map(Number);
            setHour(h);
            setMinute(m);
        }
    }, [value]);

    const getAngle = (clientX: number, clientY: number) => {
        if (!clockRef.current) return 0;

        const rect = clockRef.current.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;

        const deltaX = clientX - centerX;
        const deltaY = clientY - centerY;

        let angle = Math.atan2(deltaY, deltaX) * (180 / Math.PI);
        angle = (angle + 90 + 360) % 360;

        return angle;
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (!isDragging) return;

        const angle = getAngle(e.clientX, e.clientY);

        if (isDragging === 'hour') {
            const newHour = Math.round((angle / 360) * 12) % 12;
            const displayHour = hour >= 12 ? newHour + 12 : newHour;
            setHour(displayHour);
        } else if (isDragging === 'minute') {
            const newMinute = Math.round((angle / 360) * 60) % 60;
            setMinute(newMinute);
        }
    };

    const handleMouseUp = () => {
        if (isDragging) {
            const timeString = `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
            onChange(timeString);
        }
        setIsDragging(null);
    };

    useEffect(() => {
        if (isDragging) {
            window.addEventListener('mousemove', handleMouseMove);
            window.addEventListener('mouseup', handleMouseUp);

            return () => {
                window.removeEventListener('mousemove', handleMouseMove);
                window.removeEventListener('mouseup', handleMouseUp);
            };
        }
    }, [isDragging, hour, minute]);

    const hourAngle = ((hour % 12) / 12) * 360;
    const minuteAngle = (minute / 60) * 360;

    const formatTime = (h: number, m: number) => {
        const period = h >= 12 ? 'PM' : 'AM';
        const displayHour = h % 12 || 12;
        return `${displayHour}:${String(m).padStart(2, '0')} ${period}`;
    };

    const toggleAMPM = () => {
        setHour((prev) => {
            const newHour = prev < 12 ? prev + 12 : prev - 12;
            const timeString = `${String(newHour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
            onChange(timeString);
            return newHour;
        });
    };

    return (
        <div className="relative">
            <label className="block text-sm font-medium text-gray-700 mb-1">
                {label}
            </label>

            <button
                type="button"
                onClick={() => setIsOpen(!isOpen)}
                className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-white hover:bg-gray-50 flex items-center justify-between"
            >
                <span className="flex items-center gap-2">
                    <Clock size={18} className="text-gray-500" />
                    <span className="font-medium">{formatTime(hour, minute)}</span>
                </span>
            </button>

            {isOpen && (
                <>
                    <div
                        className="fixed inset-0 z-40"
                        onClick={() => setIsOpen(false)}
                    />
                    <div className="absolute z-50 mt-2 bg-white rounded-xl shadow-2xl border border-gray-200 p-6 w-80">
                        <div className="text-center mb-4">
                            <div className="text-3xl font-bold text-gray-900">
                                {formatTime(hour, minute)}
                            </div>
                        </div>

                        {/* Analog Clock */}
                        <div className="relative mx-auto" style={{ width: '240px', height: '240px' }}>
                            <div
                                ref={clockRef}
                                className="absolute inset-0 rounded-full bg-gradient-to-br from-blue-50 to-indigo-100 border-4 border-blue-200 shadow-inner"
                            >
                                {/* Hour markers */}
                                {Array.from({ length: 12 }).map((_, i) => {
                                    const angle = (i / 12) * 360;
                                    const radian = (angle - 90) * (Math.PI / 180);
                                    const x = 50 + 40 * Math.cos(radian);
                                    const y = 50 + 40 * Math.sin(radian);

                                    return (
                                        <div
                                            key={i}
                                            className="absolute text-sm font-bold text-gray-700"
                                            style={{
                                                left: `${x}%`,
                                                top: `${y}%`,
                                                transform: 'translate(-50%, -50%)',
                                            }}
                                        >
                                            {i === 0 ? 12 : i}
                                        </div>
                                    );
                                })}

                                {/* Minute markers */}
                                {Array.from({ length: 60 }).map((_, i) => {
                                    if (i % 5 === 0) return null;
                                    const angle = (i / 60) * 360;
                                    const radian = (angle - 90) * (Math.PI / 180);
                                    const x = 50 + 45 * Math.cos(radian);
                                    const y = 50 + 45 * Math.sin(radian);

                                    return (
                                        <div
                                            key={i}
                                            className="absolute w-1 h-1 bg-gray-400 rounded-full"
                                            style={{
                                                left: `${x}%`,
                                                top: `${y}%`,
                                                transform: 'translate(-50%, -50%)',
                                            }}
                                        />
                                    );
                                })}

                                {/* Center dot */}
                                <div className="absolute top-1/2 left-1/2 w-3 h-3 bg-blue-600 rounded-full transform -translate-x-1/2 -translate-y-1/2 z-20" />

                                {/* Hour hand */}
                                <div
                                    className="absolute top-1/2 left-1/2 origin-bottom cursor-grab active:cursor-grabbing"
                                    style={{
                                        width: '6px',
                                        height: '60px',
                                        marginLeft: '-3px',
                                        transform: `translateY(-100%) rotate(${hourAngle}deg)`,
                                        transition: isDragging === 'hour' ? 'none' : 'transform 0.3s ease',
                                    }}
                                    onMouseDown={() => setIsDragging('hour')}
                                >
                                    <div className="w-full h-full bg-gradient-to-t from-blue-600 to-blue-500 rounded-full shadow-lg" />
                                </div>

                                {/* Minute hand */}
                                <div
                                    className="absolute top-1/2 left-1/2 origin-bottom cursor-grab active:cursor-grabbing"
                                    style={{
                                        width: '4px',
                                        height: '80px',
                                        marginLeft: '-2px',
                                        transform: `translateY(-100%) rotate(${minuteAngle}deg)`,
                                        transition: isDragging === 'minute' ? 'none' : 'transform 0.3s ease',
                                    }}
                                    onMouseDown={() => setIsDragging('minute')}
                                >
                                    <div className="w-full h-full bg-gradient-to-t from-indigo-600 to-indigo-500 rounded-full shadow-lg" />
                                </div>
                            </div>
                        </div>

                        {/* AM/PM Toggle & Manual Input */}
                        <div className="mt-4 space-y-3">
                            <div className="flex items-center justify-center gap-2">
                                <button
                                    type="button"
                                    onClick={toggleAMPM}
                                    className={`px-4 py-2 rounded-lg font-semibold transition-colors ${hour < 12
                                            ? 'bg-blue-600 text-white'
                                            : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                                        }`}
                                >
                                    AM
                                </button>
                                <button
                                    type="button"
                                    onClick={toggleAMPM}
                                    className={`px-4 py-2 rounded-lg font-semibold transition-colors ${hour >= 12
                                            ? 'bg-blue-600 text-white'
                                            : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                                        }`}
                                >
                                    PM
                                </button>
                            </div>

                            <div className="flex gap-2">
                                <input
                                    type="number"
                                    min="1"
                                    max="12"
                                    value={hour % 12 || 12}
                                    onChange={(e) => {
                                        const val = parseInt(e.target.value) || 1;
                                        const newHour = hour >= 12 ? (val % 12) + 12 : val % 12;
                                        setHour(newHour);
                                    }}
                                    onBlur={() => {
                                        const timeString = `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
                                        onChange(timeString);
                                    }}
                                    className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-center font-semibold"
                                />
                                <span className="flex items-center text-2xl font-bold text-gray-400">:</span>
                                <input
                                    type="number"
                                    min="0"
                                    max="59"
                                    value={minute}
                                    onChange={(e) => {
                                        const val = parseInt(e.target.value) || 0;
                                        setMinute(Math.min(59, Math.max(0, val)));
                                    }}
                                    onBlur={() => {
                                        const timeString = `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
                                        onChange(timeString);
                                    }}
                                    className="flex-1 px-3 py-2 border border-gray-300 rounded-lg text-center font-semibold"
                                />
                            </div>

                            <button
                                type="button"
                                onClick={() => setIsOpen(false)}
                                className="w-full bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 font-semibold"
                            >
                                Done
                            </button>
                        </div>
                    </div>
                </>
            )}
        </div>
    );
}

import { useEffect, useState } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { TrainingProgram, TrainingAttendance, TrainingAssignment } from '../lib/models';
import { BarChart3, Users, UserCheck, UserX, Calendar } from 'lucide-react';

interface DayData {
  date: string;
  assigned: number;
  present: number;
  absent: number;
  totalAttendance: number;
}

export default function AttendanceAnalytics() {
  const [attendanceData, setAttendanceData] = useState<DayData[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedProgram, setSelectedProgram] = useState<string>('all');
  const [programs, setPrograms] = useState<TrainingProgram[]>([]);
  const [totalStats, setTotalStats] = useState({
    totalAssigned: 0,
    attendanceRate: 0,
  });
  const [isAnimating, setIsAnimating] = useState(false);

  useEffect(() => {
    loadPrograms();
  }, []);

  useEffect(() => {
    if (programs.length > 0) {
      loadAttendanceData();
    }
  }, [selectedProgram, programs]);

  const loadPrograms = async () => {
    try {
      // Fetch ALL programs (not just active) to ensure we can display any attendance data
      const data = await db.find<TrainingProgram>(
        Collections.TRAINING_PROGRAMS,
        {},  // No status filter - get all programs
        { sort: { created_at: -1 } }
      );

      console.log('[AttendanceAnalytics] Loaded programs:', data?.length || 0);
      setPrograms(data || []);

      // Default to "Refresher" program if found (as requested by user)
      const refresherProgram = data?.find(p => p.title.toLowerCase().includes('refresher'));
      if (refresherProgram && refresherProgram.id) {
        setSelectedProgram(refresherProgram.id);
      }
    } catch (error) {
      console.error('Error loading programs:', error);
    }
  };

  const loadAttendanceData = async () => {
    setLoading(true);

    try {
      const attendanceFilter: any = {};
      if (selectedProgram !== 'all') {
        attendanceFilter.training_program_id = selectedProgram;
      }

      // Fetch both teacher and mentor attendance records
      const [teacherAttendanceRecords, mentorAttendanceRecords] = await Promise.all([
        db.find<TrainingAttendance>(Collections.TRAINING_ATTENDANCE, attendanceFilter),
        db.find<any>(Collections.MENTOR_TRAINING_ATTENDANCE, attendanceFilter)
      ]);

      // Combine both attendance records
      const allAttendanceRecords = [
        ...(teacherAttendanceRecords || []),
        ...(mentorAttendanceRecords || [])
      ];

      console.log('[AttendanceAnalytics] Teacher attendance:', teacherAttendanceRecords?.length || 0);
      console.log('[AttendanceAnalytics] Mentor attendance:', mentorAttendanceRecords?.length || 0);

      const assignmentsFilter: any = {};
      if (selectedProgram !== 'all') {
        assignmentsFilter.training_program_id = selectedProgram;
      }

      // Fetch both teacher and mentor training assignments
      const [teacherAssignments, mentorAssignments] = await Promise.all([
        db.find<TrainingAssignment>(Collections.TRAINING_ASSIGNMENTS, assignmentsFilter),
        db.find<any>(Collections.MENTOR_TRAINING_ASSIGNMENTS, assignmentsFilter)
      ]);

      const totalAssigned = (teacherAssignments?.length || 0) + (mentorAssignments?.length || 0);

      console.log('[AttendanceAnalytics] Teacher assignments:', teacherAssignments?.length || 0);
      console.log('[AttendanceAnalytics] Mentor assignments:', mentorAssignments?.length || 0);

      const dateMap = new Map<string, DayData>();

      allAttendanceRecords?.forEach((record) => {
        const dateStr = record.attendance_date;
        if (!dateMap.has(dateStr)) {
          dateMap.set(dateStr, {
            date: dateStr,
            assigned: totalAssigned,
            present: 0,
            absent: 0,
            totalAttendance: 0,
          });
        }

        const dayData = dateMap.get(dateStr)!;
        dayData.totalAttendance++;

        if (record.status === 'present' || record.status === 'late') {
          dayData.present++;
        } else if (record.status === 'absent') {
          dayData.absent++;
        }
      });

      const sortedData = Array.from(dateMap.values()).sort((a, b) => {
        // Parse dates in local timezone by appending time component
        const dateA = new Date(a.date + 'T00:00:00');
        const dateB = new Date(b.date + 'T00:00:00');
        return dateA.getTime() - dateB.getTime();
      });

      setAttendanceData(sortedData);

      const totalPresent = sortedData.reduce((sum, day) => sum + day.present, 0);
      const totalPossible = sortedData.reduce((sum, day) => sum + day.assigned, 0);
      const attendanceRate = totalPossible > 0 ? Math.round((totalPresent / totalPossible) * 100) : 0;

      setTotalStats({
        totalAssigned: totalAssigned,
        attendanceRate,
      });

    } catch (error) {
      console.error('Error loading analytics:', error);
    } finally {
      setLoading(false);
      // Trigger animation after data loads
      setTimeout(() => setIsAnimating(true), 100);
    }
  };

  const maxValue = Math.max(...attendanceData.map(d => Math.max(d.assigned, d.present, d.absent)), 1);

  if (loading) {
    return (
      <div className="bg-white rounded-lg shadow-md p-6">
        <div className="flex justify-center items-center h-64">
          <div className="text-gray-500">Loading attendance analytics...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
            <div className="bg-blue-100 p-3 rounded-lg">
              <BarChart3 className="text-blue-600" size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-gray-900">Training Attendance Analytics</h3>
              <p className="text-sm text-gray-600">Day-wise attendance breakdown</p>
            </div>
          </div>

          <select
            value={selectedProgram}
            onChange={(e) => setSelectedProgram(e.target.value)}
            className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="all">All Programs</option>
            {programs.map((program) => (
              <option key={program.id} value={program.id}>
                {program.title}
              </option>
            ))}
          </select>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
          <div className="bg-gradient-to-br from-blue-50 to-blue-100 rounded-lg p-4 border border-blue-200 transform transition-all duration-500 hover:scale-105">
            <div className="flex items-center gap-3">
              <div className="bg-blue-600 p-2 rounded-lg animate-pulse">
                <Users className="text-white" size={20} />
              </div>
              <div>
                <p className="text-sm font-medium text-gray-600">Total Teachers Assigned</p>
                <p className="text-2xl font-bold text-gray-900 transition-all duration-1000">
                  {isAnimating ? totalStats.totalAssigned : 0}
                </p>
              </div>
            </div>
          </div>

          <div className="bg-gradient-to-br from-yellow-50 to-yellow-100 rounded-lg p-4 border border-yellow-200 transform transition-all duration-500 hover:scale-105">
            <div className="flex items-center gap-3">
              <div className="bg-yellow-600 p-2 rounded-lg animate-pulse">
                <Calendar className="text-white" size={20} />
              </div>
              <div>
                <p className="text-sm font-medium text-gray-600">Overall Attendance Rate</p>
                <p className="text-2xl font-bold text-gray-900 transition-all duration-1000">
                  {isAnimating ? totalStats.attendanceRate : 0}%
                </p>
              </div>
            </div>
          </div>
        </div>

        {attendanceData.length > 0 ? (
          <div className="space-y-6">
            <div className="flex items-center gap-4 text-sm">
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 bg-blue-500 rounded"></div>
                <span className="text-gray-700">Assigned</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 bg-green-500 rounded"></div>
                <span className="text-gray-700">Present</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 bg-red-500 rounded"></div>
                <span className="text-gray-700">Absent</span>
              </div>
            </div>

            <div className="overflow-x-auto pb-4">
              <div className="inline-flex gap-4 px-4" style={{ minWidth: '100%' }}>
                {attendanceData.map((day, index) => {
                  const assignedHeight = Math.max((day.assigned / maxValue) * 240, day.assigned > 0 ? 20 : 0);
                  const presentHeight = Math.max((day.present / maxValue) * 240, day.present > 0 ? 20 : 0);
                  const absentHeight = Math.max((day.absent / maxValue) * 240, day.absent > 0 ? 20 : 0);

                  return (
                    <div key={index} className="flex flex-col items-center gap-3" style={{ minWidth: '100px' }}>
                      <div className="flex items-end gap-2 h-64">
                        <div className="flex flex-col items-center gap-2">
                          <div className="relative group flex flex-col justify-end" style={{ height: '240px' }}>
                            <div
                              className="bg-blue-500 hover:bg-blue-600 rounded-t cursor-pointer transition-all duration-1000 ease-out"
                              style={{
                                height: isAnimating ? `${assignedHeight}px` : '0px',
                                width: '24px'
                              }}
                            >
                              <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                                Assigned: {day.assigned}
                              </div>
                            </div>
                          </div>
                          <span className="text-xs font-semibold text-blue-600 transition-all duration-500">{isAnimating ? day.assigned : 0}</span>
                        </div>

                        <div className="flex flex-col items-center gap-2">
                          <div className="relative group flex flex-col justify-end" style={{ height: '240px' }}>
                            <div
                              className="bg-green-500 hover:bg-green-600 rounded-t cursor-pointer transition-all duration-1000 ease-out"
                              style={{
                                height: isAnimating ? `${presentHeight}px` : '0px',
                                width: '24px',
                                transitionDelay: '100ms'
                              }}
                            >
                              <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                                Present: {day.present}
                              </div>
                            </div>
                          </div>
                          <span className="text-xs font-semibold text-green-600 transition-all duration-500">{isAnimating ? day.present : 0}</span>
                        </div>

                        <div className="flex flex-col items-center gap-2">
                          <div className="relative group flex flex-col justify-end" style={{ height: '240px' }}>
                            <div
                              className="bg-red-500 hover:bg-red-600 rounded-t cursor-pointer transition-all duration-1000 ease-out"
                              style={{
                                height: isAnimating ? `${absentHeight}px` : '0px',
                                width: '24px',
                                transitionDelay: '200ms'
                              }}
                            >
                              <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 px-2 py-1 bg-gray-900 text-white text-xs rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10">
                                Absent: {day.absent}
                              </div>
                            </div>
                          </div>
                          <span className="text-xs font-semibold text-red-600 transition-all duration-500">{isAnimating ? day.absent : 0}</span>
                        </div>
                      </div>

                      <div className="text-xs font-medium text-gray-700 text-center">
                        {new Date(day.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        ) : (
          <div className="text-center py-12 text-gray-500">
            <BarChart3 size={48} className="mx-auto mb-4 opacity-50" />
            <p>No attendance data available for this training program</p>
          </div>
        )}
      </div>
    </div>
  );
}

