                    </table>
                </div>
            )}
        </div>
    );
}

import { useState } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { User, Permission, School, Teacher, Mentor } from '../lib/models';
import { Upload, Download, AlertCircle, CheckCircle2, X } from 'lucide-react';
import LoadingSpinner from './LoadingSpinner';

interface Props {
  currentUser: User;
  currentPermissions: Permission;
}

type UploadType = 'schools' | 'teachers' | 'mentors';

interface UploadResult {
  success: number;
  failed: number;
  errors: string[];
}

export default function BulkUpload({ currentUser, currentPermissions }: Props) {
  const [uploadType, setUploadType] = useState<UploadType>('schools');
  const [uploading, setUploading] = useState(false);
  const [result, setResult] = useState<UploadResult | null>(null);

  const canManage = currentUser.role === 'admin';

  const downloadTemplate = (type: UploadType) => {
    let csvContent = '';
    let filename = '';

    switch (type) {
      case 'schools':
        csvContent = 'name,code,address,phone,email,h1_count,h2_count,h3_count,principal_name\n';
        csvContent += 'Example School,SCH001,"123 Main St, City",555-0100,school@example.com,100,200,300,John Doe\n';
        filename = 'schools_template.csv';
        break;
      case 'teachers':
        csvContent = 'first_name,last_name,email,phone,school_code,subject_specialization,qualification,hire_date,status\n';
        csvContent += 'Jane,Smith,jane@example.com,555-0101,SCH001,Mathematics,B.Ed,2020-01-15,active\n';
        filename = 'teachers_template.csv';
        break;
      case 'mentors':
        csvContent = 'first_name,last_name,email,phone,school_code,specialization,years_of_experience\n';
        csvContent += 'Bob,Johnson,bob@example.com,555-0102,SCH001,Educational Leadership,10\n';
        filename = 'mentors_template.csv';
        break;
    }

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    a.click();
    window.URL.revokeObjectURL(url);
  };

  const parseCSV = (text: string): string[][] => {
    const lines = text.split('\n').filter(line => line.trim());
    return lines.map(line => {
      const values: string[] = [];
      let current = '';
      let inQuotes = false;

      for (let i = 0; i < line.length; i++) {
        const char = line[i];
        if (char === '"') {
          inQuotes = !inQuotes;
        } else if (char === ',' && !inQuotes) {
          values.push(current.trim());
          current = '';
        } else {
          current += char;
        }
      }
      values.push(current.trim());
      return values;
    });
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setUploading(true);
    setResult(null);

    try {
      const text = await file.text();
      const rows = parseCSV(text);
      const headers = rows[0];
      const data = rows.slice(1);

      let success = 0;
      let failed = 0;
      const errors: string[] = [];

      for (let i = 0; i < data.length; i++) {
        const row = data[i];
        if (row.length === 0 || row.every(cell => !cell)) continue;

        try {
          if (uploadType === 'schools') {
            const schoolData = {
              name: row[0],
              code: row[1],
              address: row[2],
              phone: row[3],
              email: row[4],
              h1_count: parseInt(row[5]) || 0,
              h2_count: parseInt(row[6]) || 0,
              h3_count: parseInt(row[7]) || 0,
              principal_name: row[8],
              created_by: currentUser.id,
              created_at: new Date().toISOString(),
            };

            await db.insertOne(Collections.SCHOOLS, schoolData);
            success++;
          } else if (uploadType === 'teachers') {
            const schoolCode = row[4];
            const schools = await db.find<School>(Collections.SCHOOLS, { code: schoolCode });
            const school = schools[0];

            if (!school) {
              throw new Error(`School with code ${schoolCode} not found`);
            }

            const teacherData = {
              first_name: row[0],
              last_name: row[1],
              email: row[2] || '',
              phone: row[3] || '',
              school_id: school.id,
              subject_specialization: row[5] || null,
              qualification: row[6] || null,
              hire_date: row[7] || null,
              status: row[8] || 'active',
              created_at: new Date().toISOString(),
            };

            await db.insertOne(Collections.TEACHERS, teacherData);
            success++;
          } else if (uploadType === 'mentors') {
            const schoolCode = row[4];
            const schools = await db.find<School>(Collections.SCHOOLS, { code: schoolCode });
            const school = schools[0];

            if (!school) {
              throw new Error(`School with code ${schoolCode} not found`);
            }

            const mentorData = {
              first_name: row[0],
              last_name: row[1],
              email: row[2] || '',
              phone: row[3] || '',
              specialization: row[5] || '',
              school_id: school.id || null,
              years_of_experience: parseInt(row[6]) || 0,
              status: 'active' as 'active' | 'inactive',
              created_at: new Date().toISOString(),
              updated_at: new Date().toISOString(),
            };

            await db.insertOne<Mentor>(Collections.MENTORS, mentorData);
            success++;
          }
        } catch (error) {
          failed++;
          errors.push(`Row ${i + 2}: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
      }

      setResult({ success, failed, errors });
    } catch (error) {
      setResult({
        success: 0,
        failed: 0,
        errors: [`File parsing error: ${error instanceof Error ? error.message : 'Unknown error'}`],
      });
    } finally {
      setUploading(false);
      event.target.value = '';
    }
  };

  if (!canManage) {
    return (
      <div className="flex justify-center items-center h-64">
        <p className="text-gray-500">You do not have permission to bulk upload data.</p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-900">Bulk Upload</h2>
        <p className="text-gray-600 mt-1">Upload multiple records at once using CSV files</p>
      </div>

      <div className="bg-white rounded-lg shadow-md p-6">
        <div className="space-y-6">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Select Upload Type
            </label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {(['schools', 'teachers', 'mentors'] as UploadType[]).map((type) => (
                <button
                  key={type}
                  onClick={() => setUploadType(type)}
                  className={`p-4 rounded-lg border-2 transition-all ${uploadType === type
                    ? 'border-blue-600 bg-blue-50'
                    : 'border-gray-200 hover:border-gray-300'
                    }`}
                >
                  <p className="font-medium text-gray-900 capitalize">{type}</p>
                </button>
              ))}
            </div>
          </div>

          <div className="border-t pt-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Instructions</h3>
            <ol className="list-decimal list-inside space-y-2 text-sm text-gray-600">
              <li>Download the CSV template for {uploadType}</li>
              <li>Fill in your data following the template format</li>
              <li>Save the file as CSV</li>
              <li>Upload the file using the button below</li>
            </ol>

            <button
              onClick={() => downloadTemplate(uploadType)}
              className="mt-4 flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors"
            >
              <Download size={20} />
              Download {uploadType} Template
            </button>
          </div>

          <div className="border-t pt-6">
            <h3 className="text-lg font-semibold text-gray-900 mb-4">Upload File</h3>
            <div className="flex items-center justify-center w-full">
              <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-gray-300 border-dashed rounded-lg cursor-pointer bg-gray-50 hover:bg-gray-100 transition-colors">
                <div className="flex flex-col items-center justify-center pt-5 pb-6">
                  <Upload className="w-10 h-10 mb-3 text-gray-400" />
                  <p className="mb-2 text-sm text-gray-500">
                    <span className="font-semibold">Click to upload</span> or drag and drop
                  </p>
                  <p className="text-xs text-gray-500">CSV files only</p>
                </div>
                <input
                  type="file"
                  className="hidden"
                  accept=".csv"
                  onChange={handleFileUpload}
                  disabled={uploading}
                />
              </label>
            </div>
          </div>

          {uploading && (
            <div className="flex items-center justify-center py-4 bg-white/50 rounded-xl">
              <LoadingSpinner size="small" label="Uploading Records" />
            </div>
          )}

          {result && (
            <div className="border-t pt-6">
              <div className="bg-gray-50 rounded-lg p-4">
                <div className="flex items-center gap-3 mb-4">
                  {result.failed === 0 ? (
                    <CheckCircle2 className="text-green-600" size={24} />
                  ) : (
                    <AlertCircle className="text-yellow-600" size={24} />
                  )}
                  <h3 className="text-lg font-semibold text-gray-900">Upload Results</h3>
                </div>

                <div className="grid grid-cols-2 gap-4 mb-4">
                  <div className="bg-green-50 rounded-lg p-3">
                    <p className="text-sm text-gray-600">Successful</p>
                    <p className="text-2xl font-bold text-green-600">{result.success}</p>
                  </div>
                  <div className="bg-red-50 rounded-lg p-3">
                    <p className="text-sm text-gray-600">Failed</p>
                    <p className="text-2xl font-bold text-red-600">{result.failed}</p>
                  </div>
                </div>

                {result.errors.length > 0 && (
                  <div className="mt-4">
                    <p className="text-sm font-medium text-gray-700 mb-2">Errors:</p>
                    <div className="bg-white rounded border border-red-200 max-h-48 overflow-y-auto">
                      {result.errors.map((error, index) => (
                        <div key={index} className="p-2 text-sm text-red-600 border-b border-red-100 last:border-b-0">
                          {error}
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                <button
                  onClick={() => setResult(null)}
                  className="mt-4 flex items-center gap-2 text-gray-600 hover:text-gray-900"
                >
                  <X size={16} />
                  Clear Results
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Bot, Plus, Search, Edit, Trash2, X, Save } from 'lucide-react';

interface ContentItem {
    id?: string;
    title: string;
    content: string;
    category: string;
    tags: string[];
    status: 'published' | 'draft';
    created_at: string;
    updated_at: string;
}

export default function CoraCMS() {
    const [items, setItems] = useState<ContentItem[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showForm, setShowForm] = useState(false);
    const [editingItem, setEditingItem] = useState<ContentItem | null>(null);
    const [formData, setFormData] = useState({ title: '', content: '', category: 'general', tags: '', status: 'draft' as const });

    useEffect(() => { loadItems(); }, []);

    const loadItems = async () => {
        try {
            setLoading(true);
            const data = await db.find<ContentItem>('cora_content', {});
            setItems(data.sort((a, b) => new Date(b.updated_at).getTime() - new Date(a.updated_at).getTime()));
        } catch (error) {
            console.error('Error:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        try {
            const now = new Date().toISOString();
            const payload = { ...formData, tags: formData.tags.split(',').map(t => t.trim()).filter(Boolean) };
            if (editingItem) {
                await db.update('cora_content', editingItem.id!, { ...payload, updated_at: now });
            } else {
                await db.create('cora_content', { ...payload, created_at: now, updated_at: now });
            }
            setShowForm(false);
            setEditingItem(null);
            setFormData({ title: '', content: '', category: 'general', tags: '', status: 'draft' });
            loadItems();
        } catch (error) {
            console.error('Error saving:', error);
        }
    };

    const handleEdit = (item: ContentItem) => {
        setEditingItem(item);
        setFormData({ title: item.title, content: item.content, category: item.category, tags: (item.tags || []).join(', '), status: item.status });
        setShowForm(true);
    };

    const handleDelete = async (id: string) => {
        if (!confirm('Delete this content?')) return;
        await db.delete('cora_content', id);
        loadItems();
    };

    const filtered = items.filter(i => i.title.toLowerCase().includes(searchTerm.toLowerCase()) || i.content.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="p-6">
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                    <Bot className="text-blue-600" size={28} />
                    <h2 className="text-2xl font-bold text-gray-800">Cora CMS</h2>
                </div>
                <button onClick={() => { setShowForm(true); setEditingItem(null); setFormData({ title: '', content: '', category: 'general', tags: '', status: 'draft' }); }} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">
                    <Plus size={18} /> Add Content
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6">
                <div className="relative">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search content..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
            </div>

            {showForm && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl p-6 max-h-[80vh] overflow-y-auto">
                        <div className="flex justify-between mb-4">
                            <h3 className="text-lg font-bold">{editingItem ? 'Edit' : 'Add'} Content</h3>
                            <button onClick={() => setShowForm(false)}><X size={20} /></button>
                        </div>
                        <div className="space-y-3">
                            <input placeholder="Title" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <textarea placeholder="Content..." value={formData.content} onChange={e => setFormData({ ...formData, content: e.target.value })} className="w-full px-3 py-2 border rounded-lg h-40 resize-none" />
                            <div className="grid grid-cols-2 gap-3">
                                <select value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })} className="px-3 py-2 border rounded-lg">
                                    <option value="general">General</option>
                                    <option value="announcement">Announcement</option>
                                    <option value="guide">Guide</option>
                                    <option value="faq">FAQ</option>
                                </select>
                                <select value={formData.status} onChange={e => setFormData({ ...formData, status: e.target.value as any })} className="px-3 py-2 border rounded-lg">
                                    <option value="draft">Draft</option>
                                    <option value="published">Published</option>
                                </select>
                            </div>
                            <input placeholder="Tags (comma separated)" value={formData.tags} onChange={e => setFormData({ ...formData, tags: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <button onClick={handleSave} className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700"><Save size={16} /> Save</button>
                        </div>
                    </div>
                </div>
            )}

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="grid gap-4 md:grid-cols-2">
                    {filtered.map(item => (
                        <div key={item.id} className="bg-white rounded-xl shadow-sm border p-5 hover:shadow-md transition-shadow">
                            <div className="flex items-start justify-between mb-2">
                                <h3 className="font-bold text-gray-800">{item.title}</h3>
                                <span className={`px-2 py-0.5 rounded-full text-xs ${item.status === 'published' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-600'}`}>{item.status}</span>
                            </div>
                            <p className="text-sm text-gray-600 line-clamp-3 mb-3">{item.content}</p>
                            <div className="flex items-center justify-between">
                                <div className="flex gap-1">{(item.tags || []).map((t, i) => <span key={i} className="px-2 py-0.5 bg-blue-50 text-blue-600 rounded text-xs">{t}</span>)}</div>
                                <div className="flex gap-1">
                                    <button onClick={() => handleEdit(item)} className="p-1.5 hover:bg-gray-100 rounded"><Edit size={14} /></button>
                                    <button onClick={() => handleDelete(item.id!)} className="p-1.5 hover:bg-red-50 text-red-600 rounded"><Trash2 size={14} /></button>
                                </div>
                            </div>
                        </div>
                    ))}
                    {filtered.length === 0 && <p className="text-gray-500 col-span-full text-center py-8">No content found</p>}
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import {
  TrainingProgram,
  User,
  Permission,
  TrainingAttendance,
  Teacher,
  School,
  SchoolAssignment,
  TrainingAssignment,
  Mentor,
  MentorTrainingAttendance,
  MentorTrainingAssignment
} from '../lib/models';
import { Calendar, Users, FileText, Download, FileDown } from 'lucide-react';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

interface Props {
  currentUser: User;
  currentPermissions: Permission;
}

interface DailyAttendance {
  attendance_date: string;
  training_program_id: string;
  training_program_name: string;
  total_assigned: number;
  present: number;
  absent: number;
  late: number;
  excused: number;
  attendance_percentage: number;
}

interface AttendanceDetail {
  id: string;
  name: string;
  email: string;
  school_name: string;
  role: 'Teacher' | 'Mentor';
  status: string;
  notes: string;
  recorded_by_name: string;
}

interface ConsolidatedAttendance {
  trainee_id: string;
  name: string;
  role: 'Teacher' | 'Mentor';
  school_name: string;
  total_sessions: number;
  present_count: number;
  attendance_percentage: number;
  marks: number | null;
  status: string;
}

const getLocalDate = () => {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

export default function DailyAttendanceReport({ currentUser, currentPermissions }: Props) {
  const [programs, setPrograms] = useState<TrainingProgram[]>([]);
  const [selectedDate, setSelectedDate] = useState(getLocalDate());
  const [selectedProgram, setSelectedProgram] = useState<string>('all');
  const [dailyReports, setDailyReports] = useState<DailyAttendance[]>([]);
  const [attendanceDetails, setAttendanceDetails] = useState<AttendanceDetail[]>([]);
  const [loading, setLoading] = useState(false);
  const [reportType, setReportType] = useState<'daily' | 'consolidated'>('daily');
  const [consolidatedReports, setConsolidatedReports] = useState<ConsolidatedAttendance[]>([]);
  const [showDetails, setShowDetails] = useState(false);

  const canViewReports = currentUser.role === 'admin' || currentUser.role === 'employee' || currentPermissions.can_view_reports;

  useEffect(() => {
    loadPrograms();
  }, []);

  useEffect(() => {
    if (reportType === 'daily') {
      if (selectedDate) loadDailyReport();
    } else {
      if (selectedProgram !== 'all') loadConsolidatedReport();
    }
  }, [selectedDate, selectedProgram, reportType]);

  const loadPrograms = async () => {
    const data = await db.find<TrainingProgram>(Collections.TRAINING_PROGRAMS, {});
    if (data) {
      // Sort client-side to avoid Firestore index requirements
      const sortedData = data.sort((a, b) => a.title.localeCompare(b.title));
      setPrograms(sortedData);
    }
  };

  const loadDailyReport = async () => {
    setLoading(true);

    try {
      let assignedSchoolIds: string[] = [];

      if (currentUser.role !== 'admin') {
        const userAssignments = await db.find<SchoolAssignment>(Collections.SCHOOL_ASSIGNMENTS, { employee_id: currentUser.id });
        assignedSchoolIds = userAssignments?.map(a => a.school_id) || [];
      }

      const attendanceFilter: any = { attendance_date: selectedDate };
      if (selectedProgram !== 'all') {
        attendanceFilter.training_program_id = selectedProgram;
      }

      // Fetch both teacher and mentor attendance
      const [teacherAttendance, mentorAttendance] = await Promise.all([
        db.find<TrainingAttendance>(Collections.TRAINING_ATTENDANCE, attendanceFilter),
        db.find<MentorTrainingAttendance>(Collections.MENTOR_TRAINING_ATTENDANCE, attendanceFilter)
      ]);

      const allAttendance = [
        ...(teacherAttendance || []).map(a => ({ ...a, type: 'teacher' as const })),
        ...(mentorAttendance || []).map(a => ({ ...a, type: 'mentor' as const }))
      ];

      // Fetch related data
      const [teachers, mentors, schools, allPrograms, users] = await Promise.all([
        db.find<Teacher>(Collections.TEACHERS, {}),
        db.find<Mentor>(Collections.MENTORS, {}),
        db.find<School>(Collections.SCHOOLS, {}),
        db.find<TrainingProgram>(Collections.TRAINING_PROGRAMS, {}),
        db.find<User>(Collections.USERS, {})
      ]);

      const filteredAttendance = currentUser.role === 'admin'
        ? allAttendance
        : allAttendance.filter((record) => {
          if (record.type === 'teacher') {
            const teacher = teachers?.find(t => t.id === (record as any).teacher_id);
            return teacher && teacher.school_id && assignedSchoolIds.includes(teacher.school_id);
          } else {
            // For mentors, check if they are assigned to any of the user's schools
            // This logic might need refinement based on how mentors are assigned to schools
            const mentor = mentors?.find(m => m.id === (record as any).mentor_id);
            return mentor && mentor.school_id && assignedSchoolIds.includes(mentor.school_id);
          }
        });

      const programMap = new Map<string, DailyAttendance>();

      for (const record of filteredAttendance) {
        const programId = record.training_program_id;
        const program = allPrograms?.find(p => p.id === programId);
        const programName = program?.title || 'Unknown Program';

        if (!programMap.has(programId)) {
          // Fetch assignments to calculate totals
          const [teacherAssignments, mentorAssignments] = await Promise.all([
            db.find<TrainingAssignment>(Collections.TRAINING_ASSIGNMENTS, { training_program_id: programId }),
            db.find<MentorTrainingAssignment>(Collections.MENTOR_TRAINING_ASSIGNMENTS, { training_program_id: programId })
          ]);

          let totalAssigned = 0;

          if (currentUser.role === 'admin') {
            totalAssigned = (teacherAssignments?.length || 0) + (mentorAssignments?.length || 0);
          } else {
            const filteredTeacherAssignments = (teacherAssignments || []).filter(a => {
              const teacher = teachers?.find(t => t.id === a.teacher_id);
              return teacher && teacher.school_id && assignedSchoolIds.includes(teacher.school_id);
            });

            const filteredMentorAssignments = (mentorAssignments || []).filter(a => {
              const mentor = mentors?.find(m => m.id === a.mentor_id);
              return mentor && mentor.school_id && assignedSchoolIds.includes(mentor.school_id);
            });

            totalAssigned = filteredTeacherAssignments.length + filteredMentorAssignments.length;
          }

          programMap.set(programId, {
            attendance_date: selectedDate,
            training_program_id: programId,
            training_program_name: programName,
            total_assigned: totalAssigned,
            present: 0,
            absent: 0,
            late: 0,
            excused: 0,
            attendance_percentage: 0,
          });
        }

        const report = programMap.get(programId)!;

        switch (record.status) {
          case 'present':
            report.present++;
            break;
          case 'absent':
            report.absent++;
            break;
          case 'late':
            report.late++;
            break;
          case 'excused':
            report.excused++;
            break;
        }
      }

      programMap.forEach((report) => {
        report.attendance_percentage = report.total_assigned > 0
          ? Math.round((report.present / report.total_assigned) * 100)
          : 0;
      });

      setDailyReports(Array.from(programMap.values()));

      // Prepare details for the table
      const details: AttendanceDetail[] = filteredAttendance.map((record) => {
        let name = 'Unknown';
        let email = '';
        let schoolName = 'Unknown';
        let role: 'Teacher' | 'Mentor' = 'Teacher';

        if (record.type === 'teacher') {
          const teacher = teachers?.find(t => t.id === (record as any).teacher_id);
          const school = teacher ? schools?.find(s => s.id === teacher.school_id) : undefined;
          name = teacher ? `${teacher.first_name} ${teacher.last_name}` : 'Unknown Teacher';
          email = teacher?.email || '';
          schoolName = school?.name || 'Unknown School';
          role = 'Teacher';
        } else {
          const mentor = mentors?.find(m => m.id === (record as any).mentor_id);
          const school = mentor ? schools?.find(s => s.id === mentor.school_id) : undefined; // Mentors have school_id
          name = mentor ? `${mentor.first_name} ${mentor.last_name}` : 'Unknown Mentor';
          email = mentor?.email || '';
          schoolName = school?.name || 'Unknown School';
          role = 'Mentor';
        }

        const recordedByUser = users?.find(u => u.id === record.recorded_by);
        const recordedByName = recordedByUser ? recordedByUser.full_name : 'Unknown';

        return {
          id: record.id || `${record.type}-${(record as any).teacher_id || (record as any).mentor_id}-${record.attendance_date}`,
          name,
          email,
          school_name: schoolName,
          role,
          status: record.status,
          notes: record.notes || '',
          recorded_by_name: recordedByName
        };
      });

      setAttendanceDetails(details);

    } catch (error) {
      console.error('Error loading daily report:', error);
    } finally {
      setLoading(false);
    }
  };

  const loadConsolidatedReport = async () => {
    if (selectedProgram === 'all') return;
    setLoading(true);

    try {
      const [teacherAssignments, mentorAssignments, teacherAttendance, mentorAttendance, teachers, mentors, schools] = await Promise.all([
        db.find<TrainingAssignment>(Collections.TRAINING_ASSIGNMENTS, { training_program_id: selectedProgram }),
        db.find<MentorTrainingAssignment>(Collections.MENTOR_TRAINING_ASSIGNMENTS, { training_program_id: selectedProgram }),
        db.find<TrainingAttendance>(Collections.TRAINING_ATTENDANCE, { training_program_id: selectedProgram }),
        db.find<MentorTrainingAttendance>(Collections.MENTOR_TRAINING_ATTENDANCE, { training_program_id: selectedProgram }),
        db.find<Teacher>(Collections.TEACHERS, {}),
        db.find<Mentor>(Collections.MENTORS, {}),
        db.find<School>(Collections.SCHOOLS, {})
      ]);

      const allAttendance = [
        ...(teacherAttendance || []).map(a => ({ ...a, type: 'teacher' as const })),
        ...(mentorAttendance || []).map(a => ({ ...a, type: 'mentor' as const }))
      ];

      // Calculate total sessions for this program (unique dates in attendance)
      const selectedProgramObj = programs.find(p => p.id === selectedProgram);
      const isC10 = selectedProgramObj && (
        (selectedProgramObj.title || '').toLowerCase().includes('c10') ||
        (selectedProgramObj.title || '').toLowerCase().includes('c.10')
      );

      const uniqueDates = new Set(allAttendance.map(a => a.attendance_date));
      const totalSessions = isC10 ? 16 : uniqueDates.size;

      const teacherConsolidated: ConsolidatedAttendance[] = (teacherAssignments || []).map(assignment => {
        const teacher = teachers?.find(t => t.id === assignment.teacher_id);
        const school = teacher ? schools?.find(s => s.id === teacher.school_id) : null;
        const traineeAttendance = (teacherAttendance || []).filter(a => a.teacher_id === assignment.teacher_id);
        const presentCount = traineeAttendance.filter(a => a.status === 'present').length;

        return {
          trainee_id: assignment.teacher_id,
          name: teacher ? `${teacher.first_name} ${teacher.last_name}` : 'Unknown Teacher',
          role: 'Teacher',
          school_name: school?.name || 'Unknown School',
          total_sessions: totalSessions,
          present_count: presentCount,
          attendance_percentage: totalSessions > 0 ? Math.round((presentCount / totalSessions) * 100) : 0,
          marks: assignment.score || null,
          status: assignment.status
        };
      });

      const mentorConsolidated: ConsolidatedAttendance[] = (mentorAssignments || []).map(assignment => {
        const mentor = mentors?.find(m => m.id === assignment.mentor_id);
        const school = mentor ? schools?.find(s => s.id === mentor.school_id) : null;
        const traineeAttendance = (mentorAttendance || []).filter(a => a.mentor_id === assignment.mentor_id);
        const presentCount = traineeAttendance.filter(a => a.status === 'present').length;

        return {
          trainee_id: assignment.mentor_id,
          name: mentor ? `${mentor.first_name} ${mentor.last_name}` : 'Unknown Mentor',
          role: 'Mentor',
          school_name: school?.name || 'Unknown School',
          total_sessions: totalSessions,
          present_count: presentCount,
          attendance_percentage: totalSessions > 0 ? Math.round((presentCount / totalSessions) * 100) : 0,
          marks: assignment.score || null,
          status: assignment.status
        };
      });

      setConsolidatedReports([...teacherConsolidated, ...mentorConsolidated]);
    } catch (error) {
      console.error('Error loading consolidated report:', error);
    } finally {
      setLoading(false);
    }
