                    </label>
                    <input
                      type="time"
                      required
                      value={formData.end_time}
                      onChange={(e) => {
                        const endTime = e.target.value;
                        const [startH, startM] = formData.start_time.split(':').map(Number);
                        const [endH, endM] = endTime.split(':').map(Number);
                        const startMinutes = startH * 60 + startM;
                        const endMinutes = endH * 60 + endM;
                        const duration = Math.max(0, endMinutes - startMinutes);
                        setFormData({ ...formData, end_time: endTime, time_spent: duration });
                      }}
                      className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    />
                  </div>
                </div>

                <div className="bg-blue-50 p-3 rounded-lg">
                  <p className="text-sm text-blue-700">
                    <span className="font-medium">Duration:</span>{' '}
                    <span className="font-bold">{formatDuration(formData.time_spent)}</span>
                  </p>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Status
                  </label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value as 'pending' | 'in_progress' | 'completed' })}
                    className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                  >
                    <option value="pending">Pending</option>
                    <option value="in_progress">In Progress</option>
                    <option value="completed">Completed</option>
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">
                    Notes (optional)
                  </label>
                  <div className="flex gap-2">
                    <textarea
                      value={formData.notes}
                      onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                      rows={3}
                      className="flex-1 px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                      placeholder={isListening && voiceField === 'notes' ? '≡ƒÄñ Listening...' : 'Additional notes about this task'}
                    />
                    {voiceSupported && (
                      <button
                        type="button"
                        onClick={() => startVoiceInput('notes')}
                        disabled={isListening}
                        className={`px-3 self-start py-2 rounded-lg transition-all ${isListening && voiceField === 'notes'
                          ? 'bg-red-500 text-white animate-pulse'
                          : 'bg-blue-100 text-blue-600 hover:bg-blue-200'
                          }`}
                        title="Speak to add notes"
                      >
                        {isListening && voiceField === 'notes' ? <MicOff size={20} /> : <Mic size={20} />}
                      </button>
                    )}
                  </div>
                </div>

                <div className="flex gap-3 pt-4">
                  <button
                    type="button"
                    onClick={resetForm}
                    className="flex-1 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    className="flex-1 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700"
                  >
                    {editingTask ? 'Update Task' : 'Create Task'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        )
      }

      {
        notification && (
          <Notification
            isOpen={notification.isOpen}
            type={notification.type}
            title={notification.title}
            message={notification.message}
            onClose={() => setNotification(null)}
          />
        )
      }

      {
        confirmDialog && (
          <ConfirmDialog
            isOpen={confirmDialog.isOpen}
            title={confirmDialog.title}
            message={confirmDialog.message}
            onConfirm={confirmDialog.onConfirm}
            onCancel={() => setConfirmDialog(null)}
          />
        )
      }
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import {
    Calendar as CalendarIcon,
    ChevronLeft,
    ChevronRight,
    Plus,
    Clock,
    AlertCircle,
    CheckCircle2,
    X,
    Trash2,
    Edit2
} from 'lucide-react';
import { User, CalendarEvent } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';

interface Props {
    currentUser: User;
}

type CalendarView = 'month' | 'week' | 'day';

export default function EventCalendar({ currentUser }: Props) {
    const [view, setView] = useState<CalendarView>('month');
    const [currentDate, setCurrentDate] = useState(new Date());
    const [events, setEvents] = useState<CalendarEvent[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);
    const [editingEvent, setEditingEvent] = useState<CalendarEvent | null>(null);
    const [formData, setFormData] = useState({
        title: '',
        description: '',
        type: 'event' as CalendarEvent['type'],
        start_date: '',
        start_time: '09:00',
        end_date: '',
        end_time: '10:00',
        is_all_day: false,
        reminder_at: '',
        status: 'pending' as CalendarEvent['status']
    });

    useEffect(() => {
        loadEvents();
    }, [currentUser.id]);

    const loadEvents = async () => {
        setLoading(true);
        try {
            const data = await db.find<CalendarEvent>(Collections.EVENTS, { user_id: currentUser.id });
            setEvents(data || []);
        } catch (error) {
            console.error('Error loading events:', error);
        }
        setLoading(false);
    };

    const handleSaveEvent = async (e: React.FormEvent) => {
        e.preventDefault();

        const start = new Date(`${formData.start_date}T${formData.start_time}`);
        const end = new Date(`${formData.end_date || formData.start_date}T${formData.end_time}`);

        const eventData: any = {
            user_id: currentUser.id!,
            title: formData.title,
            description: formData.description,
            type: formData.type,
            start_date: start.toISOString(),
            is_all_day: formData.is_all_day,
            status: formData.status,
            updated_at: new Date().toISOString()
        };

        if (formData.end_date) {
            eventData.end_date = end.toISOString();
        }

        if (formData.reminder_at) {
            eventData.reminder_at = new Date(formData.reminder_at).toISOString();
        }

        try {
            if (editingEvent?.id) {
                await db.updateById(Collections.EVENTS, editingEvent.id, eventData);
            } else {
                await db.insertOne(Collections.EVENTS, {
                    ...eventData,
                    created_at: new Date().toISOString()
                } as CalendarEvent);
            }
            setShowModal(false);
            setEditingEvent(null);
            resetForm();
            loadEvents();
        } catch (error) {
            console.error('Error saving event:', error);
        }
    };

    const handleDeleteEvent = async (id: string) => {
        if (!window.confirm('Are you sure you want to delete this event?')) return;
        try {
            await db.deleteById(Collections.EVENTS, id);
            loadEvents();
        } catch (error) {
            console.error('Error deleting event:', error);
        }
    };

    const resetForm = () => {
        const today = new Date().toISOString().split('T')[0];
        setFormData({
            title: '',
            description: '',
            type: 'event',
            start_date: today,
            start_time: '09:00',
            end_date: today,
            end_time: '10:00',
            is_all_day: false,
            reminder_at: '',
            status: 'pending'
        });
    };

    const openAddModal = (date?: Date) => {
        resetForm();
        if (date) {
            const dateStr = date.toISOString().split('T')[0];
            setFormData(prev => ({ ...prev, start_date: dateStr, end_date: dateStr }));
        }
        setEditingEvent(null);
        setShowModal(true);
    };

    const openEditModal = (event: CalendarEvent) => {
        const start = new Date(event.start_date);
        const end = event.end_date ? new Date(event.end_date) : start;

        setFormData({
            title: event.title,
            description: event.description || '',
            type: event.type,
            start_date: start.toISOString().split('T')[0],
            start_time: start.toTimeString().slice(0, 5),
            end_date: end.toISOString().split('T')[0],
            end_time: end.toTimeString().slice(0, 5),
            is_all_day: event.is_all_day,
            reminder_at: event.reminder_at ? event.reminder_at.slice(0, 16) : '',
            status: event.status
        });
        setEditingEvent(event);
        setShowModal(true);
    };

    // Calendar Logic
    const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
    const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

    const navigateMonth = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentDate);
        if (direction === 'prev') newDate.setMonth(newDate.getMonth() - 1);
        else newDate.setMonth(newDate.getMonth() + 1);
        setCurrentDate(newDate);
    };

    const getDayEvents = (date: Date) => {
        const dateStr = date.toLocaleDateString('en-CA'); // YYYY-MM-DD in local time
        return events.filter(e => e.start_date.startsWith(dateStr));
    };

    const renderMonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const totalDays = daysInMonth(year, month);
        const firstDay = firstDayOfMonth(year, month);
        const days = [];

        // Padding for first day
        for (let i = 0; i < firstDay; i++) {
            days.push(<div key={`pad-${i}`} className="h-32 bg-gray-50 border border-gray-100"></div>);
        }

        for (let i = 1; i <= totalDays; i++) {
            const date = new Date(year, month, i);
            const dayEvents = getDayEvents(date);
            const isToday = new Date().toDateString() === date.toDateString();

            days.push(
                <div
                    key={i}
                    className={`h-32 border border-gray-100 p-2 transition-colors hover:bg-gray-50 relative group ${isToday ? 'bg-blue-50' : 'bg-white'}`}
                    onClick={() => openAddModal(date)}
                >
                    <div className="flex justify-between items-center mb-1">
                        <span className={`text-sm font-semibold ${isToday ? 'text-blue-600 bg-blue-100 w-6 h-6 flex items-center justify-center rounded-full' : 'text-gray-700'}`}>
                            {i}
                        </span>
                        <button
                            className="opacity-0 group-hover:opacity-100 p-1 hover:bg-gray-200 rounded text-gray-500"
                            onClick={(e) => { e.stopPropagation(); openAddModal(date); }}
                        >
                            <Plus size={14} />
                        </button>
                    </div>
                    <div className="space-y-1 overflow-y-auto max-h-20 scrollbar-hide">
                        {dayEvents.map(event => (
                            <div
                                key={event.id}
                                className={`text-[10px] px-1.5 py-0.5 rounded truncate cursor-pointer shadow-sm border ${event.type === 'task' ? 'bg-green-100 text-green-700 border-green-200' :
                                    event.type === 'note' ? 'bg-yellow-100 text-yellow-700 border-yellow-200' :
                                        'bg-blue-100 text-blue-700 border-blue-200'
                                    }`}
                                onClick={(e) => { e.stopPropagation(); openEditModal(event); }}
                            >
                                {event.title}
                            </div>
                        ))}
                    </div>
                </div>
            );
        }

        return (
            <div className="grid grid-cols-7 border-collapse">
                {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                    <div key={day} className="text-center py-2 text-sm font-bold text-gray-500 border-b border-gray-200 bg-gray-50 uppercase tracking-wider">
                        {day}
                    </div>
                ))}
                {days}
            </div>
        );
    };

    const renderListView = (days: number) => {
        const listDays = [];
        const baseDate = new Date(currentDate);

        if (view === 'week') {
            const day = baseDate.getDay();
            baseDate.setDate(baseDate.getDate() - day);
        }

        for (let i = 0; i < days; i++) {
            const date = new Date(baseDate);
            date.setDate(date.getDate() + i);
            const dayEvents = getDayEvents(date);
            const isToday = new Date().toDateString() === date.toDateString();

            listDays.push(
                <div key={i} className={`p-4 border-b border-gray-100 ${isToday ? 'bg-blue-50/50' : ''}`}>
                    <div className="flex items-center gap-4 mb-4">
                        <div className={`flex flex-col items-center justify-center w-14 h-14 rounded-xl border-2 ${isToday ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-200 bg-white text-gray-900'}`}>
                            <span className="text-xs font-bold uppercase">{date.toLocaleDateString('en-US', { weekday: 'short' })}</span>
                            <span className="text-xl font-bold">{date.getDate()}</span>
                        </div>
                        <div>
                            <h4 className="font-bold text-gray-900">{date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}</h4>
                            {isToday && <span className="text-xs font-medium text-blue-600 uppercase tracking-wider">Today</span>}
                        </div>
                        <button
                            onClick={() => openAddModal(date)}
                            className="ml-auto p-2 bg-white border border-gray-200 rounded-lg text-gray-600 hover:bg-gray-50 shadow-sm transition-all"
                        >
                            <Plus size={20} />
                        </button>
                    </div>

                    <div className="ml-0 md:ml-18 space-y-3">
                        {dayEvents.length > 0 ? dayEvents.map(event => (
                            <div
                                key={event.id}
                                onClick={() => openEditModal(event)}
                                className={`group flex items-center gap-4 p-3 rounded-xl border-l-4 cursor-pointer transition-all hover:shadow-md ${event.type === 'task' ? 'bg-green-50 border-green-500 hover:bg-green-100' :
                                    event.type === 'note' ? 'bg-yellow-50 border-yellow-500 hover:bg-yellow-100' :
                                        'bg-blue-50 border-blue-500 hover:bg-blue-100'
                                    }`}
                            >
                                <div className={`p-2 rounded-lg ${event.type === 'task' ? 'bg-green-100 text-green-600' :
                                    event.type === 'note' ? 'bg-yellow-100 text-yellow-600' :
                                        'bg-blue-100 text-blue-600'
                                    }`}>
                                    {event.type === 'task' ? <CheckCircle2 size={18} /> :
                                        event.type === 'note' ? <AlertCircle size={18} /> :
                                            <Clock size={18} />}
                                </div>
                                <div className="flex-1">
                                    <h5 className="font-bold text-gray-900">{event.title}</h5>
                                    <p className="text-sm text-gray-600 line-clamp-1">{event.description || 'No description'}</p>
                                    <div className="flex items-center gap-2 mt-1 text-xs text-gray-500">
                                        <Clock size={12} />
                                        <span>{new Date(event.start_date).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                                        {event.is_all_day && <span className="bg-gray-200 px-1.5 py-0.5 rounded ml-2">All Day</span>}
                                    </div>
                                </div>
                                <div className="opacity-0 group-hover:opacity-100 flex items-center gap-1">
                                    <button
                                        onClick={(e) => { e.stopPropagation(); openEditModal(event); }}
                                        className="p-1.5 hover:bg-white rounded-lg text-gray-500 transition-colors"
                                    >
                                        <Edit2 size={16} />
                                    </button>
                                    <button
                                        onClick={(e) => { e.stopPropagation(); handleDeleteEvent(event.id!); }}
                                        className="p-1.5 hover:bg-red-50 text-red-500 rounded-lg transition-colors"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        )) : (
                            <p className="text-sm text-gray-400 italic py-2 pl-4">No events scheduled</p>
                        )}
                    </div>
                </div>
            );
        }

        return <div className="divide-y divide-gray-100">{listDays}</div>;
    };

    return (
        <div className="space-y-6 max-w-7xl mx-auto">
            {/* Header section */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-6">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                    <div className="flex items-center gap-4">
                        <div className="bg-blue-600 p-3 rounded-xl text-white shadow-lg shadow-blue-200">
                            <CalendarIcon size={24} />
                        </div>
                        <div>
                            <h2 className="text-2xl font-bold text-gray-900">Event Calendar</h2>
                            <p className="text-sm text-gray-500 mt-0.5">Manage your tasks, events and reminders</p>
                        </div>
                    </div>

                    <div className="flex items-center gap-2">
                        <div className="flex bg-gray-100 p-1 rounded-xl">
                            {(['month', 'week', 'day'] as CalendarView[]).map(v => (
                                <button
                                    key={v}
                                    onClick={() => setView(v)}
                                    className={`px-4 py-1.5 text-sm font-semibold rounded-lg transition-all ${view === v ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
                                        }`}
                                >
                                    {v.charAt(0).toUpperCase() + v.slice(1)}
                                </button>
                            ))}
                        </div>
                        <button
                            onClick={() => openAddModal()}
                            className="flex items-center gap-2 px-4 py-2 bg-blue-600 text-white rounded-xl font-bold shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95"
                        >
                            <Plus size={20} />
                            <span>Add Event</span>
                        </button>
                    </div>
                </div>

                <div className="flex items-center justify-between mt-8">
                    <div className="flex items-center gap-4">
                        <h3 className="text-xl font-bold text-gray-900">
                            {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                        </h3>
                        <div className="flex gap-1">
                            <button onClick={() => navigateMonth('prev')} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600"><ChevronLeft size={20} /></button>
                            <button onClick={() => navigateMonth('next')} className="p-2 hover:bg-gray-100 rounded-lg text-gray-600"><ChevronRight size={20} /></button>
                        </div>
                        <button
                            onClick={() => setCurrentDate(new Date())}
                            className="px-3 py-1.5 text-sm font-medium text-blue-600 hover:bg-blue-50 rounded-lg transition-colors"
                        >
                            Today
                        </button>
                    </div>
                </div>
            </div>

            {/* Main Content Area */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden min-h-[600px]">
                {loading ? (
                    <div className="h-64 flex items-center justify-center">
                        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600"></div>
                    </div>
                ) : (
                    view === 'month' ? renderMonthView() :
                        view === 'week' ? renderListView(7) :
                            renderListView(1)
                )}
            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
                    <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl overflow-hidden">
                        <div className="flex items-center justify-between p-6 border-b border-gray-100">
                            <h3 className="text-xl font-bold text-gray-900">{editingEvent ? 'Edit Event' : 'Add New Event'}</h3>
                            <button onClick={() => setShowModal(false)} className="text-gray-400 hover:text-gray-600 transition-colors p-2 hover:bg-gray-100 rounded-xl">
                                <X size={20} />
                            </button>
                        </div>

                        <form onSubmit={handleSaveEvent} className="p-6 space-y-4">
                            <div>
                                <label className="block text-sm font-bold text-gray-700 mb-1.5 text-left">Title</label>
                                <input
                                    required
                                    type="text"
                                    placeholder="What is happening?"
                                    value={formData.title}
                                    onChange={e => setFormData(prev => ({ ...prev, title: e.target.value }))}
                                    className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all"
                                />
                            </div>

                            <div className="grid grid-cols-3 gap-2">
                                {(['event', 'task', 'note'] as CalendarEvent['type'][]).map(t => (
                                    <button
                                        key={t}
                                        type="button"
                                        onClick={() => setFormData(prev => ({ ...prev, type: t }))}
                                        className={`py-2 px-3 rounded-xl border-2 font-bold text-xs uppercase tracking-wider transition-all ${formData.type === t
                                            ? (t === 'event' ? 'bg-blue-50 border-blue-500 text-blue-700' :
                                                t === 'task' ? 'bg-green-50 border-green-500 text-green-700' :
                                                    'bg-yellow-50 border-yellow-500 text-yellow-700')
                                            : 'bg-white border-gray-100 text-gray-400 hover:border-gray-200'
                                            }`}
                                    >
                                        {t}
                                    </button>
                                ))}
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-bold text-gray-700 mb-1.5 text-left">Date</label>
                                    <input
                                        required
                                        type="date"
                                        value={formData.start_date}
                                        onChange={e => setFormData(prev => ({ ...prev, start_date: e.target.value, end_date: e.target.value }))}
                                        className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm font-medium"
                                    />
                                </div>
                                {!formData.is_all_day && (
                                    <div>
                                        <label className="block text-sm font-bold text-gray-700 mb-1.5 text-left">Time</label>
                                        <input
                                            required
                                            type="time"
                                            value={formData.start_time}
                                            onChange={e => setFormData(prev => ({ ...prev, start_time: e.target.value }))}
                                            className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-sm font-medium"
                                        />
                                    </div>
                                )}
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-gray-700 mb-1.5 text-left">Description (Optional)</label>
                                <textarea
                                    rows={3}
                                    placeholder="More details..."
                                    value={formData.description}
                                    onChange={e => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                    className="w-full px-4 py-2.5 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all resize-none text-sm"
                                />
                            </div>

                            <div className="flex items-center gap-3 p-3 bg-blue-50 rounded-xl">
                                <input
                                    type="checkbox"
                                    id="is_all_day"
                                    checked={formData.is_all_day}
                                    onChange={e => setFormData(prev => ({ ...prev, is_all_day: e.target.checked }))}
                                    className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                />
                                <label htmlFor="is_all_day" className="text-sm font-bold text-blue-900 cursor-pointer select-none">All Day Event</label>
                            </div>

                            <div className="mt-8 flex gap-3 pt-4 border-t border-gray-100">
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    className="flex-1 px-4 py-3 border border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 transition-all"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-2 px-8 py-3 bg-blue-600 text-white font-bold rounded-xl shadow-lg shadow-blue-200 hover:bg-blue-700 transition-all active:scale-95"
                                >
                                    {editingEvent ? 'Save Changes' : 'Create Event'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { User, School } from '../lib/models';
import { BarChart3 } from 'lucide-react';

interface Props {
    currentUser: User;
    onNavigate?: (view: string, subTab?: string, targetId?: string) => void;
}

export default function ImplementationAnalytics({ currentUser, onNavigate }: Props) {
    const [schools, setSchools] = useState<School[]>([]);
    const [checklists, setChecklists] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const [schoolsData, checklistData] = await Promise.all([
                db.find<School>(Collections.SCHOOLS, {}),
                db.find<any>('implementation_checklists', {})
            ]);
            setSchools(schoolsData);
            setChecklists(checklistData);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const getSchoolProgress = (schoolId: string) => {
        const checklist = checklists.find(c => c.school_id === schoolId);
        if (!checklist?.items) return 0;
        const total = 9; // total checklist items
        const completed = Object.values(checklist.items).filter(Boolean).length;
        return Math.round((completed / total) * 100);
    };

    const schoolsWithProgress = schools.map(s => ({
        ...s,
        progress: getSchoolProgress(s.id!)
    })).sort((a, b) => b.progress - a.progress);

    const avgProgress = schoolsWithProgress.length > 0
        ? Math.round(schoolsWithProgress.reduce((sum, s) => sum + s.progress, 0) / schoolsWithProgress.length)
        : 0;

    const completed = schoolsWithProgress.filter(s => s.progress === 100).length;
    const inProgress = schoolsWithProgress.filter(s => s.progress > 0 && s.progress < 100).length;
    const notStarted = schoolsWithProgress.filter(s => s.progress === 0).length;

    return (
        <div className="p-6">
            <div className="flex items-center gap-3 mb-6">
                <BarChart3 className="text-blue-600" size={28} />
                <h2 className="text-2xl font-bold text-gray-800">Implementation Analytics</h2>
            </div>

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <>
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-6">
                        <div className="bg-white rounded-xl shadow-sm border p-5">
                            <p className="text-sm text-gray-500">Average Progress</p>
                            <p className="text-3xl font-bold text-blue-600">{avgProgress}%</p>
                        </div>
                        <div className="bg-white rounded-xl shadow-sm border p-5">
                            <p className="text-sm text-gray-500">Completed</p>
                            <p className="text-3xl font-bold text-green-600">{completed}</p>
                        </div>
                        <div className="bg-white rounded-xl shadow-sm border p-5">
                            <p className="text-sm text-gray-500">In Progress</p>
                            <p className="text-3xl font-bold text-yellow-600">{inProgress}</p>
                        </div>
                        <div className="bg-white rounded-xl shadow-sm border p-5">
                            <p className="text-sm text-gray-500">Not Started</p>
                            <p className="text-3xl font-bold text-red-600">{notStarted}</p>
                        </div>
                    </div>

                    <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                        <table className="w-full">
                            <thead className="bg-gray-50">
                                <tr>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">School</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Progress</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Status</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Action</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {schoolsWithProgress.map(school => (
                                    <tr key={school.id} className="hover:bg-gray-50">
                                        <td className="px-4 py-3 text-sm font-medium text-gray-800">{school.name}</td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-2">
                                                <div className="w-24 bg-gray-200 rounded-full h-2">
                                                    <div className={`h-2 rounded-full ${school.progress === 100 ? 'bg-green-500' : school.progress > 0 ? 'bg-blue-500' : 'bg-gray-300'}`} style={{ width: `${school.progress}%` }}></div>
                                                </div>
                                                <span className="text-xs text-gray-500">{school.progress}%</span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className={`px-2 py-1 rounded-full text-xs ${school.progress === 100 ? 'bg-green-100 text-green-700' : school.progress > 0 ? 'bg-yellow-100 text-yellow-700' : 'bg-red-100 text-red-700'}`}>
                                                {school.progress === 100 ? 'Completed' : school.progress > 0 ? 'In Progress' : 'Not Started'}
                                            </span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <button onClick={() => onNavigate?.('implementation-checklist', undefined, school.id)} className="text-sm text-blue-600 hover:underline">View Checklist</button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { User, EmployeeTask } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Train } from 'lucide-react';

interface StationRecord {
    employeeId: string;
    employeeName: string;
    progress: number;
    tasksCount: number;
    status: 'on_time' | 'behind' | 'arrived' | 'stalled';
}

export default function LiveStationBoard() {
    const [records, setRecords] = useState<StationRecord[]>([]);
    const [loading, setLoading] = useState(true);

    const calculateStatus = (progress: number): StationRecord['status'] => {
        if (progress >= 100) return 'arrived';
        const now = new Date();
        const currentHour = now.getHours();
        const dayStart = 9 * 60;
        const dayEnd = 17 * 60;
        const totalWorkMinutes = dayEnd - dayStart;
        const currentWorkMinutes = Math.min(Math.max((currentHour * 60 + now.getMinutes()) - dayStart, 0), totalWorkMinutes);
        const expectedProgress = (currentWorkMinutes / totalWorkMinutes) * 100;

        if (progress < expectedProgress - 15) return 'behind';
        if (progress === 0 && currentHour >= 10) return 'stalled';
        return 'on_time';
    };

    const loadGlobalData = async () => {
        const today = new Date().toISOString().split('T')[0];
        const employees = await db.find<User>(Collections.USERS, { role: 'employee', is_active: true });
        if (!employees) return;

        const allTasks = await db.find<EmployeeTask>(Collections.EMPLOYEE_TASKS, { date: today });

        const newRecords: StationRecord[] = employees.map(emp => {
            const empTasks = allTasks.filter(t => t.employee_id === emp.id);
            const completedTasks = empTasks.filter(t => t.status === 'completed');
            const progress = empTasks.length > 0 ? (completedTasks.length / empTasks.length) * 100 : 0;

            return {
                employeeId: emp.id!,
                employeeName: emp.full_name.split(' ')[0], // Compact name
                progress: Math.round(progress),
                tasksCount: empTasks.length,
                status: calculateStatus(progress)
            };
        });

        setRecords(newRecords.sort((a, b) => b.progress - a.progress));
        setLoading(false);
    };

    useEffect(() => {
        loadGlobalData();
        const interval = setInterval(loadGlobalData, 120000);
        return () => clearInterval(interval);
    }, []);

    if (loading || records.length === 0) return null;

    return (
        <div className="bg-[#0f172a]/95 backdrop-blur-sm rounded-lg border border-amber-500/30 shadow-2xl overflow-hidden mb-6 animate-fade-in w-full max-w-2xl self-start">
            <div className="flex bg-black/40 px-3 py-1.5 items-center gap-3">
                <div className="flex items-center gap-2 border-r border-white/10 pr-3">
                    <Train className="text-amber-500" size={12} />
                    <span className="text-amber-500 font-black text-[9px] uppercase tracking-[0.2em] whitespace-nowrap">Live Signal</span>
                </div>

                {/* Horizontal Scrolling Ticker */}
                <div className="flex-1 overflow-hidden relative">
                    <div className="flex items-center gap-4 animate-ticker whitespace-nowrap py-0.5">
                        {records.map((record) => (
                            <div key={record.employeeId} className="flex items-center gap-2 group cursor-help">
                                <div className={`w-1.5 h-1.5 rounded-full ${record.status === 'arrived' ? 'bg-green-500' :
                                        record.status === 'behind' ? 'bg-red-500' :
                                            'bg-amber-500'
                                    } shadow-[0_0_5px_currentColor]`}></div>

                                <span className="text-white font-bold text-[10px] tracking-tight">{record.employeeName}</span>

                                <span className={`text-[9px] font-mono ${record.status === 'arrived' ? 'text-green-400' :
                                        record.status === 'behind' ? 'text-red-400' :
                                            'text-amber-400'
                                    }`}>{record.progress}%</span>

                                <div className="w-8 h-0.5 bg-white/5 rounded-full overflow-hidden">
                                    <div
                                        className={`h-full ${record.status === 'arrived' ? 'bg-green-500' :
                                                record.status === 'behind' ? 'bg-red-500' :
                                                    'bg-amber-500'
                                            }`}
                                        style={{ width: `${record.progress}%` }}
                                    />
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                <div className="text-amber-500 font-mono text-[9px] font-black tracking-tighter tabular-nums pl-3 border-l border-white/10">
                    {new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
            </div>

            <style>{`
                @keyframes ticker {
                    0% { transform: translateX(10%); }
                    100% { transform: translateX(-100%); }
                }
                .animate-ticker {
                    animation: ticker 25s linear infinite;
                    display: inline-flex;
                }
                .animate-ticker:hover {
                    animation-play-state: paused;
                }
            `}</style>
        </div>
    );
}

import { useState } from 'react';
import { login } from '../lib/auth';
import { User, Permission, Teacher, Mentor, Management } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Lock, LogIn, Phone, GraduationCap, Users, BookOpen, Award, Sparkles } from 'lucide-react';

interface Props {
  onLogin: (user: User, permissions: Permission) => void;
  onTeacherLogin: (teacher: Teacher) => void;
  onMentorLogin: (mentor: Mentor) => void;
  onManagementLogin: (management: Management) => void;
  onParentAccess: () => void;
}

export default function Login({ onLogin, onTeacherLogin, onMentorLogin, onManagementLogin, onParentAccess }: Props) {
  const [showStaffLogin, setShowStaffLogin] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleAdminLogin = async () => {
    const adminResult = await login(username, password);
    if (adminResult) {
      if (adminResult.error) {
        setError(adminResult.error);
        return false;
      }
      onLogin(adminResult.user, adminResult.permissions);
      return true;
    }
    return false;
  };

  // Helper function to normalize phone numbers by removing all whitespace
  const normalizePhone = (phone: string | undefined): string => {
    if (!phone) return '';
    // Remove all whitespace characters including spaces, tabs, newlines, etc.
    return phone.replace(/\s+/g, '');
  };

  const checkTeacherAsMentor = async (teacher: Teacher) => {
    if (!teacher || !teacher.id) return null;

    // Check if this teacher has any mentor training assignments
    const mentorAssignments = await db.find(Collections.MENTOR_TRAINING_ASSIGNMENTS, { mentor_id: teacher.id });

    if (mentorAssignments && mentorAssignments.length > 0) {
      // Create a virtual mentor object from the teacher data
      return {
        id: teacher.id,
        _id: teacher._id,
        first_name: teacher.first_name,
        last_name: teacher.last_name,
        email: teacher.email || '',
        phone: teacher.phone,
        school_id: teacher.school_id,
        specialization: teacher.subject_specialization || 'General',
        years_of_experience: 1,
        status: 'active' as const,
        created_at: teacher.created_at,
        updated_at: teacher.updated_at,
      };
    } else {
      // Check for standard training assignments that might be mentor training
      const trainingAssignments = await db.find(Collections.TRAINING_ASSIGNMENTS, { teacher_id: teacher.id });

      if (trainingAssignments && trainingAssignments.length > 0) {
        // Check if any of these assignments are for mentor training programs
        const allPrograms = await db.find<any>(Collections.TRAINING_PROGRAMS, {});

        const hasMentorTraining = trainingAssignments.some((assignment: any) => {
          const program = allPrograms.find((p: any) => p.id === assignment.training_program_id);
          if (!program) return false;

          const title = (program.title || '').toLowerCase();
          return title.includes('mentor') || title.includes('b4') || title.includes('c10') || title.includes('c.10');
        });

        if (hasMentorTraining) {
          return {
            id: teacher.id,
            _id: teacher._id,
            first_name: teacher.first_name,
            last_name: teacher.last_name,
            email: teacher.email || '',
            phone: teacher.phone,
            school_id: teacher.school_id,
            specialization: teacher.subject_specialization || 'General',
            years_of_experience: 1,
            status: 'active' as const,
            created_at: teacher.created_at,
            updated_at: teacher.updated_at,
          };
        }
      }
    }
    return null;
  };

  const handleUnifiedLogin = async () => {
    const normalizedInput = normalizePhone(phoneNumber);

    // 1. Try finding a Mentor first
    let mentor = null;
    const mentors = await db.find<Mentor>(Collections.MENTORS, { phone: phoneNumber.trim() });
    if (mentors && mentors.length > 0) {
      mentor = mentors.find(m => m.status === 'active') || mentors[0];
    } else {
      const allMentors = await db.find<Mentor>(Collections.MENTORS, {});
      const matches = allMentors?.filter(m => normalizePhone(m.phone) === normalizedInput) || [];
      mentor = matches.find(m => m.status === 'active') || matches[0] || null;
    }

    if (mentor) {
      localStorage.setItem('currentMentor', JSON.stringify(mentor));
      onMentorLogin(mentor);
      return true;
    }

    // 2. Try finding a Teacher
    let teacher = null;
    const teachers = await db.find<Teacher>(Collections.TEACHERS, { phone: phoneNumber.trim() });
    if (teachers && teachers.length > 0) {
      teacher = teachers.find(t => t.school_id !== null) || teachers[0];
    } else {
      const allTeachers = await db.find<Teacher>(Collections.TEACHERS, {});
      const matches = allTeachers?.filter(t => normalizePhone(t.phone) === normalizedInput) || [];
      teacher = matches.find(t => t.school_id !== null) || matches[0] || null;
    }

    if (teacher) {
      // Check if this teacher is effectively a mentor (Virtual Mentor)
      const virtualMentor = await checkTeacherAsMentor(teacher);
      if (virtualMentor) {
        localStorage.setItem('currentMentor', JSON.stringify(virtualMentor));
        onMentorLogin(virtualMentor);
        return true;
      }

      localStorage.setItem('currentTeacher', JSON.stringify(teacher));
      onTeacherLogin(teacher);
      return true;
    }

    // 3. Try finding Management
    const managements = await db.find<Management>(Collections.MANAGEMENT, { phone: phoneNumber.trim() });
    if (managements && managements.length > 0) {
      const management = managements.find(m => m.status === 'active') || managements[0];
      localStorage.setItem('currentManagement', JSON.stringify(management));
      onManagementLogin(management);
      return true;
    }

    return false;
  };

  const handlePhoneSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const success = await handleUnifiedLogin();

      if (!success) {
        setError('Phone number not found. Please contact your administrator.');
      }
    } catch (err) {
      setError('An error occurred during login');
    } finally {
      setLoading(false);
    }
  };

  const handleStaffSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const success = await handleAdminLogin();
      if (!success) {
        setError('Invalid username or password');
      }
    } catch (err) {
      setError('An error occurred during login');
    } finally {
      setLoading(false);
    }
  };

  if (showStaffLogin) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center p-4">
        <div className="bg-white rounded-[20px] shadow-[0_14px_28px_rgba(0,0,0,0.25),0_10px_10px_rgba(0,0,0,0.22)] overflow-hidden w-full max-w-4xl flex flex-col md:flex-row min-h-[500px]">

          {/* Left Side - Welcome / Switch */}
          <div className="w-full md:w-2/5 bg-gradient-to-br from-indigo-600 via-purple-600 to-pink-600 p-12 text-white flex flex-col items-center justify-center text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full">
              <div className="absolute w-60 h-60 bg-white/10 rounded-full -top-10 -right-10"></div>
              <div className="absolute w-40 h-40 bg-white/10 rounded-full bottom-10 -left-10"></div>
            </div>

            <div className="relative z-10">
              <h2 className="text-3xl font-bold mb-4">Welcome Back!</h2>
              <p className="text-blue-100 mb-8 font-medium leading-relaxed">
                To keep connected with us please login with your personal info.
              </p>
              <p className="text-white/80 text-sm mb-6">Are you a Participant?</p>
              <button
                onClick={() => {
                  setShowStaffLogin(false);
                  setError('');
                  setUsername('');
                  setPassword('');
                }}
                className="border-2 border-white text-white rounded-full px-12 py-3 font-bold uppercase text-xs tracking-wider hover:bg-white hover:text-indigo-600 transition-all duration-300 shadow-lg"
              >
                Sign In as Participant
              </button>
            </div>
          </div>

          {/* Right Side - Login Form */}
          <div className="w-full md:w-3/5 p-12 bg-white flex flex-col justify-center items-center">
            <div className="w-full max-w-sm">
              <div className="text-center mb-8">
                <h1 className="text-3xl font-bold text-indigo-600 mb-2">Employee Login</h1>
                <div className="flex justify-center gap-4 mt-4">
                  <div className="w-10 h-10 rounded-full border border-gray-200 flex items-center justify-center text-gray-400 hover:border-indigo-500 hover:text-indigo-500 transition-colors cursor-pointer">
                    <Users size={18} />
                  </div>
                  <div className="w-10 h-10 rounded-full border border-gray-200 flex items-center justify-center text-gray-400 hover:border-indigo-500 hover:text-indigo-500 transition-colors cursor-pointer">
                    <BookOpen size={18} />
                  </div>
                  <div className="w-10 h-10 rounded-full border border-gray-200 flex items-center justify-center text-gray-400 hover:border-indigo-500 hover:text-indigo-500 transition-colors cursor-pointer">
                    <Sparkles size={18} />
                  </div>
                </div>
                <p className="text-gray-400 text-xs mt-4">or use your admin account</p>
              </div>

              <form onSubmit={handleStaffSubmit} className="space-y-4">
                <div className="bg-gray-100 rounded-lg flex items-center px-4 py-3">
                  <Users size={18} className="text-gray-400 mr-3" />
                  <input
                    type="text"
                    required
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    className="bg-transparent border-none outline-none w-full text-sm font-medium text-gray-700 placeholder-gray-400"
                    placeholder="Username"
                    autoFocus
                  />
                </div>

                <div className="bg-gray-100 rounded-lg flex items-center px-4 py-3">
                  <Lock size={18} className="text-gray-400 mr-3" />
                  <input
                    type="password"
                    required
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="bg-transparent border-none outline-none w-full text-sm font-medium text-gray-700 placeholder-gray-400"
                    placeholder="Password"
                  />
                </div>

                {error && (
                  <div className="text-red-500 text-xs text-center font-medium mt-2 bg-red-50 py-2 rounded">
                    {error}
                  </div>
                )}

                <div className="text-center mt-4 mb-6">
                  <a href="#" className="text-gray-400 text-xs border-b border-gray-300 hover:text-indigo-600 hover:border-indigo-600 transition-colors">
                    Forgot your password?
                  </a>
                </div>

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full bg-indigo-600 text-white rounded-full py-3.5 font-bold uppercase text-xs tracking-wider shadow-md hover:bg-indigo-700 hover:shadow-lg transition-all duration-300 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loading ? (
                    <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                  ) : null}
                  {loading ? 'SIGNING IN...' : 'SIGN IN'}
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center p-4">
      <div className="bg-white rounded-[20px] shadow-[0_14px_28px_rgba(0,0,0,0.25),0_10px_10px_rgba(0,0,0,0.22)] overflow-hidden w-full max-w-4xl flex flex-col md:flex-row min-h-[500px]">

        {/* Left Side - Branding / Switch */}
        <div className="w-full md:w-2/5 p-12 text-white flex flex-col items-center justify-center text-center relative overflow-hidden transition-colors duration-500 bg-gradient-to-br from-blue-600 via-indigo-600 to-purple-600">
          <div className="absolute top-0 left-0 w-full h-full">
            <div className="absolute w-60 h-60 bg-white/10 rounded-full -top-10 -right-10"></div>
            <div className="absolute w-40 h-40 bg-white/10 rounded-full bottom-10 -left-10"></div>
          </div>

          <div className="relative z-10">
            <h2 className="text-3xl font-bold mb-4">Hello, Participant!</h2>
            <p className="text-blue-100 mb-8 font-medium leading-relaxed">
              Enter your registered phone number to start your learning journey.
            </p>
            <p className="text-white/80 text-sm mb-6">Are you an Admin or Employee?</p>
            <button
              onClick={() => {
                setShowStaffLogin(true);
                setError('');
              }}
              className="border-2 border-white text-white rounded-full px-12 py-3 font-bold uppercase text-xs tracking-wider hover:bg-white hover:text-indigo-600 transition-all duration-300 shadow-lg mb-4 w-full"
            >
              Sign In as Staff
            </button>
            <button
              onClick={onParentAccess}
              className="text-white/80 hover:text-white text-sm font-medium underline underline-offset-4"
            >
              Parent Portal Access
            </button>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div className="w-full md:w-3/5 p-12 bg-white flex flex-col justify-center items-center">
          <div className="w-full max-w-sm">
            <div className="text-center mb-8">
              <h1 className="text-3xl font-bold mb-2 transition-colors duration-300 text-indigo-600">
                Participant Login
              </h1>

              <div className="flex justify-center gap-4 mt-6 text-indigo-100">
                <Users size={48} className="text-indigo-200" />
              </div>

              <p className="text-gray-400 text-xs mt-4">Teachers & Mentors</p>
            </div>

            <form onSubmit={handlePhoneSubmit} className="space-y-6">
              <div className="bg-gray-100 rounded-lg flex items-center px-4 py-3">
                <Phone size={18} className="text-gray-400 mr-3" />
                <input
                  type="tel"
                  required
                  value={phoneNumber}
                  onChange={(e) => setPhoneNumber(e.target.value)}
                  className="bg-transparent border-none outline-none w-full text-sm font-medium text-gray-700 placeholder-gray-400"
                  placeholder="Phone Number"
                  autoFocus
                />
              </div>

              {/* Hint */}
              <div className="text-xs text-center text-gray-400 bg-gray-50 py-2 rounded">
                Use your registered phone number to sign in
              </div>

              {error && (
                <div className="text-red-500 text-xs text-center font-medium mt-2 bg-red-50 py-2 rounded">
                  {error}
                </div>
              )}

              <button
                type="submit"
                disabled={loading}
                className="w-full text-white rounded-full py-3.5 font-bold uppercase text-xs tracking-wider shadow-md hover:shadow-lg transition-all duration-300 flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed bg-indigo-600 hover:bg-indigo-700"
              >
                {loading ? (
                  <span className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                ) : null}
                {loading ? 'SIGNING IN...' : 'SIGN IN'}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { BarChart3, Download, Calendar, User, Smartphone, Monitor, Tablet, Filter } from 'lucide-react';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';

interface LoginRecord {
    id: string;
    user_id: string;
    device_id: string;
    device_type: string;
    browser: string;
    os: string;
    last_login: string;
    login_count: number;
    created_at: string;
    user?: {
        full_name: string;
        username: string;
        role: string;
    };
}

const COLORS = ['#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];

export default function LoginStatistics() {
    const [loginRecords, setLoginRecords] = useState<LoginRecord[]>([]);
    const [filteredRecords, setFilteredRecords] = useState<LoginRecord[]>([]);
    const [loading, setLoading] = useState(true);
    const [users, setUsers] = useState<any[]>([]);
    const [dateFrom, setDateFrom] = useState('');
    const [dateTo, setDateTo] = useState('');
    const [selectedUser, setSelectedUser] = useState('all');
    const [selectedDeviceType, setSelectedDeviceType] = useState('all');
    const [stats, setStats] = useState({
        totalLogins: 0,
        uniqueDevices: 0,
        uniqueUsers: 0,
        deviceTypeBreakdown: [] as { name: string; value: number }[],
    });

    useEffect(() => {
        loadUsers();
        loadLoginData();
    }, []);

    useEffect(() => {
        applyFilters();
    }, [dateFrom, dateTo, selectedUser, selectedDeviceType, loginRecords]);

    const loadUsers = async () => {
        const data = await db.find(Collections.USERS, {}, { sort: { full_name: 1 } });
        setUsers(data);
    };

    const loadLoginData = async () => {
        setLoading(true);
        try {
            const devices = await db.find(Collections.USER_DEVICES, {}, { sort: { last_login: -1 } });
            const allUsers = await db.find(Collections.USERS, {});

            const recordsWithUser = devices.map((device: any) => ({
                ...device,
                user: allUsers.find(u => u.id === device.user_id)
            }));

            setLoginRecords(recordsWithUser);
        } catch (error) {
            console.error('Error loading login data:', error);
        }
        setLoading(false);
    };

    const applyFilters = () => {
        let filtered = [...loginRecords];

        // Filter by date range
        if (dateFrom) {
            const fromDate = new Date(dateFrom);
            filtered = filtered.filter(record => new Date(record.last_login) >= fromDate);
        }
        if (dateTo) {
            const toDate = new Date(dateTo);
            toDate.setHours(23, 59, 59, 999);
            filtered = filtered.filter(record => new Date(record.last_login) <= toDate);
        }

        // Filter by user
        if (selectedUser !== 'all') {
            filtered = filtered.filter(record => record.user_id === selectedUser);
        }

        // Filter by device type
        if (selectedDeviceType !== 'all') {
            filtered = filtered.filter(record => record.device_type.toLowerCase() === selectedDeviceType);
        }

        setFilteredRecords(filtered);
        calculateStats(filtered);
    };

    const calculateStats = (records: LoginRecord[]) => {
        const uniqueDevices = new Set(records.map(r => r.device_id)).size;
        const uniqueUsers = new Set(records.map(r => r.user_id)).size;
        const totalLogins = records.reduce((sum, r) => sum + (r.login_count || 0), 0);

        // Device type breakdown
        const deviceCounts: { [key: string]: number } = {};
        records.forEach(record => {
            const type = record.device_type || 'unknown';
            deviceCounts[type] = (deviceCounts[type] || 0) + 1;
        });

        const deviceTypeBreakdown = Object.entries(deviceCounts).map(([name, value]) => ({
            name: name.charAt(0).toUpperCase() + name.slice(1),
            value
        }));

        setStats({
            totalLogins,
            uniqueDevices,
            uniqueUsers,
            deviceTypeBreakdown,
        });
    };

    const exportToCSV = () => {
        const headers = ['Date', 'Employee Name', 'Username', 'Role', 'Device Type', 'OS', 'Browser', 'Login Count', 'First Login', 'Last Login'];
        const rows = filteredRecords.map(record => [
            new Date(record.last_login).toLocaleDateString(),
            record.user?.full_name || 'Unknown',
            record.user?.username || 'N/A',
            record.user?.role || 'N/A',
            record.device_type,
            record.os,
            record.browser,
            record.login_count,
            new Date(record.created_at).toLocaleString(),
            new Date(record.last_login).toLocaleString(),
        ]);

        const csvContent = [headers, ...rows].map(row => row.join(',')).join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv' });
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `login-statistics-${new Date().toISOString().split('T')[0]}.csv`;
        a.click();
        window.URL.revokeObjectURL(url);
    };

    const formatDate = (dateString: string) => {
        return new Date(dateString).toLocaleString('en-US', {
            month: 'short',
            day: 'numeric',
            year: 'numeric',
            hour: '2-digit',
            minute: '2-digit',
        });
    };

    const getDeviceIcon = (type: string) => {
        switch (type?.toLowerCase()) {
            case 'mobile':
                return <Smartphone className="text-blue-600" size={16} />;
            case 'tablet':
                return <Tablet className="text-green-600" size={16} />;
            default:
                return <Monitor className="text-gray-600" size={16} />;
        }
    };

    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="bg-white rounded-lg shadow-md p-6">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                        <div className="bg-blue-100 p-3 rounded-lg">
                            <BarChart3 className="text-blue-600" size={24} />
                        </div>
                        <div>
                            <h3 className="text-lg font-bold text-gray-900">Login Statistics</h3>
                            <p className="text-sm text-gray-600">View and analyze employee device login activity</p>
                        </div>
                    </div>

                    <button
                        onClick={exportToCSV}
                        className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
                    >
                        <Download size={18} />
                        Export CSV
                    </button>
                </div>
            </div>

            {/* Filters */}
            <div className="bg-white rounded-lg shadow-md p-6">
                <div className="flex items-center gap-2 mb-4">
                    <Filter size={20} className="text-gray-600" />
                    <h4 className="font-semibold text-gray-900">Filters</h4>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            <Calendar size={16} className="inline mr-1" />
                            From Date
                        </label>
                        <input
                            type="date"
                            value={dateFrom}
                            onChange={(e) => setDateFrom(e.target.value)}
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            <Calendar size={16} className="inline mr-1" />
                            To Date
                        </label>
                        <input
                            type="date"
                            value={dateTo}
                            onChange={(e) => setDateTo(e.target.value)}
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            <User size={16} className="inline mr-1" />
                            Employee
                        </label>
                        <select
                            value={selectedUser}
                            onChange={(e) => setSelectedUser(e.target.value)}
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="all">All Employees</option>
                            {users.map((user) => (
                                <option key={user.id} value={user.id}>
                                    {user.full_name}
                                </option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-2">
                            <Smartphone size={16} className="inline mr-1" />
                            Device Type
                        </label>
                        <select
                            value={selectedDeviceType}
                            onChange={(e) => setSelectedDeviceType(e.target.value)}
                            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
                        >
                            <option value="all">All Types</option>
                            <option value="mobile">Mobile</option>
                            <option value="tablet">Tablet</option>
                            <option value="desktop">Desktop</option>
                        </select>
                    </div>
                </div>
            </div>

            {/* Statistics Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Total Logins</p>
                            <p className="text-3xl font-bold text-blue-600">{stats.totalLogins}</p>
                        </div>
                        <BarChart3 className="text-blue-400" size={40} />
                    </div>
                </div>

                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Unique Devices</p>
                            <p className="text-3xl font-bold text-green-600">{stats.uniqueDevices}</p>
                        </div>
                        <Smartphone className="text-green-400" size={40} />
                    </div>
                </div>

                <div className="bg-white rounded-lg shadow-md p-6">
                    <div className="flex items-center justify-between">
                        <div>
                            <p className="text-sm text-gray-600">Unique Users</p>
                            <p className="text-3xl font-bold text-purple-600">{stats.uniqueUsers}</p>
                        </div>
                        <User className="text-purple-400" size={40} />
                    </div>
                </div>
            </div>

            {/* Device Type Breakdown Chart */}
            {stats.deviceTypeBreakdown.length > 0 && (
                <div className="bg-white rounded-lg shadow-md p-6">
                    <h4 className="font-semibold text-gray-900 mb-4">Device Type Distribution</h4>
                    <ResponsiveContainer width="100%" height={300}>
                        <PieChart>
                            <Pie
                                data={stats.deviceTypeBreakdown}
                                cx="50%"
                                cy="50%"
                                labelLine={false}
                                label={({ name, percent }) => `${name}: ${percent ? (percent * 100).toFixed(0) : 0}%`}
                                outerRadius={80}
                                fill="#8884d8"
                                dataKey="value"
                            >
                                {stats.deviceTypeBreakdown.map((_, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            )}

            {/* Login Records Table */}
            <div className="bg-white rounded-lg shadow-md p-6">
                <h4 className="font-semibold text-gray-900 mb-4">Login Details</h4>

                {loading ? (
                    <div className="text-center py-12">
                        <div className="text-gray-500">Loading login data...</div>
                    </div>
                ) : filteredRecords.length === 0 ? (
                    <div className="text-center py-12 text-gray-500">
                        <BarChart3 size={48} className="mx-auto mb-4 opacity-50" />
                        <p>No login records found for the selected filters</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-gray-50 border-b border-gray-200">
                                <tr>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Employee</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Device</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Browser/OS</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">First Login</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Last Login</th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Login Count</th>
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-gray-200">
                                {filteredRecords.map((record) => (
                                    <tr key={record.id}>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div>
                                                <div className="text-sm font-medium text-gray-900">{record.user?.full_name || 'Unknown'}</div>
                                                <div className="text-xs text-gray-500">{record.user?.username}</div>
                                                <div className="text-xs text-gray-400 capitalize">{record.user?.role}</div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="flex items-center gap-2">
                                                {getDeviceIcon(record.device_type)}
                                                <span className="text-sm text-gray-900 capitalize">{record.device_type}</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-900">{record.browser}</div>
                                            <div className="text-xs text-gray-500">{record.os}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-600">{formatDate(record.created_at)}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm text-gray-600">{formatDate(record.last_login)}</div>
                                        </td>
                                        <td className="px-6 py-4 whitespace-nowrap">
                                            <div className="text-sm font-semibold text-blue-600">{record.login_count}</div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { User, Permission, Management } from '../lib/models';
import { Shield, Plus, Search, Edit, Trash2, X } from 'lucide-react';

interface Props {
    currentUser: User;
    currentPermissions: Permission;
}

export default function ManagementManagement({ currentUser, currentPermissions }: Props) {
    const [members, setMembers] = useState<Management[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showForm, setShowForm] = useState(false);
    const [editingMember, setEditingMember] = useState<Management | null>(null);
    const [formData, setFormData] = useState({
        first_name: '', last_name: '', email: '', phone: '',
        position: '', department: '', hire_date: '', status: 'active' as const
    });

    useEffect(() => { loadMembers(); }, []);

    const loadMembers = async () => {
        try {
            setLoading(true);
            const data = await db.find<Management>('management_members', {});
            setMembers(data);
        } catch (error) {
            console.error('Error loading management:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        try {
            const now = new Date().toISOString();
            if (editingMember) {
                await db.update('management_members', editingMember.id!, { ...formData, updated_at: now });
            } else {
                await db.create('management_members', { ...formData, created_at: now, updated_at: now });
            }
            setShowForm(false);
            setEditingMember(null);
            setFormData({ first_name: '', last_name: '', email: '', phone: '', position: '', department: '', hire_date: '', status: 'active' });
            loadMembers();
        } catch (error) {
            console.error('Error saving:', error);
        }
    };

    const handleEdit = (member: Management) => {
        setEditingMember(member);
        setFormData({
            first_name: member.first_name, last_name: member.last_name,
            email: member.email, phone: member.phone,
            position: member.position, department: member.department,
            hire_date: member.hire_date || '', status: member.status
        });
        setShowForm(true);
    };

    const handleDelete = async (id: string) => {
        if (confirm('Are you sure you want to delete this member?')) {
            await db.delete('management_members', id);
            loadMembers();
        }
    };

    const filtered = members.filter(m =>
        `${m.first_name} ${m.last_name}`.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="p-6">
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-3">
                    <Shield className="text-blue-600" size={28} />
                    <h2 className="text-2xl font-bold text-gray-800">Management Members</h2>
                </div>
                <button onClick={() => { setShowForm(true); setEditingMember(null); setFormData({ first_name: '', last_name: '', email: '', phone: '', position: '', department: '', hire_date: '', status: 'active' }); }} className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">
                    <Plus size={18} /> Add Member
                </button>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6">
                <div className="relative">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
            </div>

            {showForm && (
                <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-xl shadow-xl w-full max-w-lg p-6">
                        <div className="flex items-center justify-between mb-4">
                            <h3 className="text-lg font-bold">{editingMember ? 'Edit' : 'Add'} Management Member</h3>
                            <button onClick={() => setShowForm(false)}><X size={20} /></button>
                        </div>
                        <div className="space-y-3">
                            <div className="grid grid-cols-2 gap-3">
                                <input placeholder="First Name" value={formData.first_name} onChange={e => setFormData({ ...formData, first_name: e.target.value })} className="px-3 py-2 border rounded-lg" />
                                <input placeholder="Last Name" value={formData.last_name} onChange={e => setFormData({ ...formData, last_name: e.target.value })} className="px-3 py-2 border rounded-lg" />
                            </div>
                            <input placeholder="Email" value={formData.email} onChange={e => setFormData({ ...formData, email: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <input placeholder="Phone" value={formData.phone} onChange={e => setFormData({ ...formData, phone: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <input placeholder="Position" value={formData.position} onChange={e => setFormData({ ...formData, position: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <input placeholder="Department" value={formData.department} onChange={e => setFormData({ ...formData, department: e.target.value })} className="w-full px-3 py-2 border rounded-lg" />
                            <button onClick={handleSave} className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700">Save</button>
                        </div>
                    </div>
                </div>
            )}

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {filtered.map(member => (
                        <div key={member.id} className="bg-white rounded-xl shadow-sm border p-5 hover:shadow-md transition-shadow">
                            <div className="flex items-start justify-between">
                                <div>
                                    <h3 className="font-bold text-gray-800">{member.first_name} {member.last_name}</h3>
                                    <p className="text-sm text-gray-500">{member.position}</p>
                                    <p className="text-sm text-gray-400">{member.department}</p>
                                </div>
                                <span className={`px-2 py-1 rounded-full text-xs ${member.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>{member.status}</span>
                            </div>
                            <div className="mt-3 text-sm text-gray-500">
                                <p>{member.email}</p>
                                <p>{member.phone}</p>
                            </div>
                            <div className="flex gap-2 mt-4">
                                <button onClick={() => handleEdit(member)} className="flex-1 flex items-center justify-center gap-1 px-3 py-1.5 border rounded-lg text-sm hover:bg-gray-50"><Edit size={14} /> Edit</button>
                                <button onClick={() => handleDelete(member.id!)} className="flex items-center justify-center gap-1 px-3 py-1.5 border border-red-200 text-red-600 rounded-lg text-sm hover:bg-red-50"><Trash2 size={14} /></button>
                            </div>
                        </div>
                    ))}
                    {filtered.length === 0 && <p className="text-gray-500 col-span-full text-center py-8">No management members found</p>}
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
