    loadData();
  }, []);

  useEffect(() => {
    let filtered: MentorWithSchool[];

    if (phoneSearch.trim()) {
      const searchTerm = phoneSearch.trim().replace(/\s+/g, '');
      filtered = mentors.filter(m =>
        m.phone?.replace(/\s+/g, '').includes(searchTerm)
      );
    } else {
      filtered = mentors;
    }

    if (selectedSchoolFilter && !phoneSearch.trim()) {
      filtered = filtered.filter(m => m.school_id === selectedSchoolFilter);
    }

    setFilteredMentors(filtered);
  }, [selectedSchoolFilter, phoneSearch, mentors]);

  const loadData = async () => {
    setLoading(true);

    try {
      let assignedSchoolIds: string[] = [];

      if (currentUser.role !== 'admin' && currentUser.id) {
        const userAssignments = await db.find(Collections.SCHOOL_ASSIGNMENTS, { employee_id: currentUser.id });
        assignedSchoolIds = userAssignments?.map((a: any) => a.school_id) || [];
      }

      // Load schools
      let schoolsData: School[] = [];
      if (currentUser.role !== 'admin' && assignedSchoolIds.length > 0) {
        const allSchools = await db.find<School>(Collections.SCHOOLS, {}, { sort: { name: 1 } });
        schoolsData = allSchools.filter(s => s.id && assignedSchoolIds.includes(s.id));
      } else if (currentUser.role === 'admin') {
        schoolsData = await db.find<School>(Collections.SCHOOLS, {}, { sort: { name: 1 } });
      }

      setSchools(schoolsData);

      // Load all mentors
      const allMentors = await db.find<Mentor>(Collections.MENTORS, {}, { sort: { last_name: 1 } });

      // Filter mentors based on permissions
      let mentorsData: Mentor[] = [];
      if (currentUser.role !== 'admin' && assignedSchoolIds.length > 0) {
        mentorsData = allMentors.filter(m => m.school_id && assignedSchoolIds.includes(m.school_id));
      } else if (currentUser.role === 'admin') {
        mentorsData = allMentors;
      }

      // Map mentors with schools
      const mapped = mentorsData.map(m => ({
        ...m,
        school: schoolsData.find(s => s.id === m.school_id)
      }));

      setMentors(mapped);
      setFilteredMentors(mapped);

      // Load B4 Program and Assignments for Badge
      // Load B4 Program and Assignments for Badge
      try {
        console.log('Loading B4 data for badge logic...');
        // Fetch all programs
        const allPrograms = await db.find<TrainingProgram>(Collections.TRAINING_PROGRAMS, {}, {});

        // Find B4 program
        const b4Program = allPrograms.find(p =>
          p.title && (p.title.toLowerCase().includes('b4') || p.title.toLowerCase().includes("mentors' training"))
        );

        const b4Ids = new Set<string>();

        if (b4Program && b4Program.id) {
          console.log('Found B4 Program:', b4Program.title, b4Program.id);
          const b4Assignments = await db.find(Collections.MENTOR_TRAINING_ASSIGNMENTS, {
            training_program_id: b4Program.id
          });

          if (b4Assignments) {
            console.log(`Found ${b4Assignments.length} assignments for B4 program`);
            b4Assignments.forEach((a: any) => {
              if (a.mentor_id) b4Ids.add(a.mentor_id);
            });
          }
        } else {
          console.warn('Could not find B4 program in loaded programs list');
        }
        setB4MentorIds(b4Ids);

        // Load programs for assignment dialog (show all, regardless of status)
        setPrograms(allPrograms.sort((a, b) => a.title.localeCompare(b.title)));
      } catch (err) {
        console.error('Error loading B4 data:', err);
      }
    } catch (error) {
      console.error('Error loading mentor data:', error);
    }

    setLoading(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const data = {
      ...formData,
      school_id: formData.school_id || null,
    };

    try {
      if (editingMentor && editingMentor.id) {
