import { useState } from 'react';
import { Teacher, Management, User, Mentor } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Shield, Key, Eye, EyeOff, Save, CheckCircle2 } from 'lucide-react';

interface Props {
    teacher?: Teacher;
    management?: Management;
    user?: User;
    mentor?: Mentor;
}

export default function PasscodeSettings({ teacher, management, user, mentor }: Props) {
    const [newPasscode, setNewPasscode] = useState('');
    const [confirmPasscode, setConfirmPasscode] = useState('');
    const [showPasscodes, setShowPasscodes] = useState(false);
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const currentUser = teacher || management || user || mentor;
    if (!currentUser) return null;

    const handleUpdatePasscode = async (e: React.FormEvent) => {
        e.preventDefault();
        setError(null);
        setSuccess(false);

        if (newPasscode !== confirmPasscode) {
            setError('New passcodes do not match');
            return;
        }

        if (newPasscode.length < 4) {
            setError('Passcode must be at least 4 characters');
            return;
        }

        setLoading(true);
        try {
            let collectionName = '';
            if (teacher) collectionName = Collections.TEACHERS;
            else if (management) collectionName = 'management';
            else if (user) collectionName = Collections.USERS;
            else if (mentor) collectionName = Collections.MENTORS;

            if (!collectionName || !currentUser.id) {
                throw new Error('Invalid user context');
            }

            const updateData: any = {
                passcode: newPasscode,
                updated_at: new Date().toISOString()
            };

            // Also update plain_passcode for teachers and mentors as it's used for display
            if (teacher || mentor) {
                updateData.plain_passcode = newPasscode;
            }

            await db.updateById(collectionName, currentUser.id, updateData);

            setSuccess(true);
            setNewPasscode('');
            setConfirmPasscode('');
        } catch (err: any) {
            setError(err.message || 'Failed to update passcode');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm max-w-md mx-auto">
            <div className="flex items-center gap-3 mb-6">
                <div className="bg-blue-100 p-2 rounded-lg">
                    <Shield className="text-blue-600" size={20} />
                </div>
                <div>
                    <h3 className="text-lg font-bold text-gray-900">Security Settings</h3>
                    <p className="text-sm text-gray-500">Update your access passcode</p>
                </div>
            </div>

            {success && (
                <div className="mb-6 p-4 bg-green-50 border border-green-100 rounded-xl flex items-center gap-3 text-green-700">
                    <CheckCircle2 size={20} />
                    <p className="text-sm font-medium">Passcode updated successfully!</p>
                </div>
            )}

            {error && (
                <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl text-red-600 text-sm font-medium">
                    {error}
                </div>
            )}

            <form onSubmit={handleUpdatePasscode} className="space-y-4">
                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">New Passcode</label>
                    <div className="relative">
                        <input
                            type={showPasscodes ? 'text' : 'password'}
                            value={newPasscode}
                            onChange={(e) => setNewPasscode(e.target.value)}
                            className="w-full pl-10 pr-12 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 font-bold"
                            placeholder="Enter new passcode"
                            disabled={loading}
                        />
                        <Key className="absolute left-3.5 top-3.5 text-gray-400" size={18} />
                        <button
                            type="button"
                            onClick={() => setShowPasscodes(!showPasscodes)}
                            className="absolute right-3.5 top-3.5 text-gray-400 hover:text-gray-600"
                        >
                            {showPasscodes ? <EyeOff size={18} /> : <Eye size={18} />}
                        </button>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold text-gray-500 uppercase mb-1.5 ml-1">Confirm New Passcode</label>
                    <div className="relative">
                        <input
                            type={showPasscodes ? 'text' : 'password'}
                            value={confirmPasscode}
                            onChange={(e) => setConfirmPasscode(e.target.value)}
                            className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 font-bold"
                            placeholder="Confirm new passcode"
                            disabled={loading}
                        />
                        <Key className="absolute left-3.5 top-3.5 text-gray-400" size={18} />
                    </div>
                </div>

                <button
                    type="submit"
                    disabled={loading || !newPasscode || !confirmPasscode}
                    className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 transition-all disabled:opacity-50 mt-2"
                >
                    {loading ? 'Updating...' : (
                        <>
                            <Save size={18} />
                            Update Passcode
                        </>
                    )}
                </button>
            </form>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { User, Permission } from '../lib/models';
import { Lock, Save, Search } from 'lucide-react';

const PERMISSION_FIELDS = [
    { key: 'can_delete_schools', label: 'Delete Schools' },
    { key: 'can_manage_users', label: 'Manage Users' },
    { key: 'can_assign_training', label: 'Assign Training' },
    { key: 'can_view_reports', label: 'View Reports' },
    { key: 'can_manage_schools', label: 'Manage Schools' },
    { key: 'can_manage_teachers', label: 'Manage Teachers' },
    { key: 'can_manage_mentors', label: 'Manage Mentors' },
    { key: 'can_manage_admin_personnel', label: 'Manage Admin Personnel' },
    { key: 'can_manage_training_programs', label: 'Manage Training Programs' },
];

export function PermissionsManagement() {
    const [users, setUsers] = useState<User[]>([]);
    const [permissions, setPermissions] = useState<Permission[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [saving, setSaving] = useState<string | null>(null);

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const [usersData, permsData] = await Promise.all([
                db.find<User>(Collections.USERS, {}),
                db.find<Permission>(Collections.PERMISSIONS, {})
            ]);
            setUsers(usersData.filter(u => u.is_active));
            setPermissions(permsData);
        } catch (error) {
            console.error('Error loading data:', error);
        } finally {
            setLoading(false);
        }
    };

    const getPermission = (userId: string) => permissions.find(p => p.user_id === userId);

    const togglePermission = async (userId: string, field: string) => {
        setSaving(userId);
        try {
            const existing = permissions.find(p => p.user_id === userId);
            if (existing) {
                const updated = { ...existing, [field]: !(existing as any)[field] };
                await db.update(Collections.PERMISSIONS, existing.id!, updated);
            } else {
                const newPerm: any = { user_id: userId };
                PERMISSION_FIELDS.forEach(f => { newPerm[f.key] = f.key === field; });
                await db.create(Collections.PERMISSIONS, newPerm);
            }
            loadData();
        } catch (error) {
            console.error('Error updating permission:', error);
        } finally {
            setSaving(null);
        }
    };

    const filtered = users.filter(u => u.full_name.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
        <div className="p-6">
            <div className="flex items-center gap-3 mb-6">
                <Lock className="text-blue-600" size={28} />
                <h2 className="text-2xl font-bold text-gray-800">Permissions Management</h2>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6">
                <div className="relative">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search users..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
            </div>

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full">
                            <thead className="bg-gray-50">
                                <tr>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase sticky left-0 bg-gray-50">User</th>
                                    <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Role</th>
                                    {PERMISSION_FIELDS.map(f => (
                                        <th key={f.key} className="px-3 py-3 text-center text-xs font-semibold text-gray-600 uppercase whitespace-nowrap">{f.label}</th>
                                    ))}
                                </tr>
                            </thead>
                            <tbody className="divide-y">
                                {filtered.map(user => {
                                    const perm = getPermission(user.id!);
                                    return (
                                        <tr key={user.id} className="hover:bg-gray-50">
                                            <td className="px-4 py-3 text-sm font-medium text-gray-800 sticky left-0 bg-white">{user.full_name}</td>
                                            <td className="px-4 py-3"><span className="px-2 py-1 bg-blue-100 text-blue-700 rounded-full text-xs capitalize">{user.role}</span></td>
                                            {PERMISSION_FIELDS.map(f => (
                                                <td key={f.key} className="px-3 py-3 text-center">
                                                    <input
                                                        type="checkbox"
                                                        checked={(perm as any)?.[f.key] || false}
                                                        onChange={() => togglePermission(user.id!, f.key)}
                                                        disabled={saving === user.id}
                                                        className="w-4 h-4 text-blue-600 rounded cursor-pointer"
                                                    />
                                                </td>
                                            ))}
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect, Fragment } from 'react';
import { User, Permission, SchoolQuery, School } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Plus, Search, X, Edit2, Trash2, Building2, MessageSquare, History, Users, Briefcase, Clock } from 'lucide-react';
import LoadingSpinner from './LoadingSpinner';

interface Props {
    currentUser: User;
    currentPermissions: Permission;
}

type SchoolWithQuery = School & {
    latestQuery?: SchoolQuery;
    hasPendingQuery: boolean;
};

const getLocalDate = () => {
    const now = new Date();
    const year = now.getFullYear();
    const month = String(now.getMonth() + 1).padStart(2, '0');
    const day = String(now.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
};

export default function QueryTracker({ currentUser }: Props) {
    const [schools, setSchools] = useState<SchoolWithQuery[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedSchool, setSelectedSchool] = useState<School | null>(null);
    const [showAddModal, setShowAddModal] = useState(false);
    const [activeTab, setActiveTab] = useState<'all' | 'today'>('all');
    const [expandedSchoolId, setExpandedSchoolId] = useState<string | null>(null);
    const [schoolQueriesMap, setSchoolQueriesMap] = useState<Map<string, SchoolQuery[]>>(new Map());
    const [loadingHistory, setLoadingHistory] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [employees, setEmployees] = useState<User[]>([]);
    const [selectedEmployeeId, setSelectedEmployeeId] = useState<string>('');

    const [formData, setFormData] = useState<Partial<SchoolQuery>>({
        school_id: '',
        school_name: '',
        person_name: '',
        person_designation: '',
        received_date: getLocalDate(),
        resolved_by: '',
        resolved_date: '',
        source: 'call',
        department: '',
        query: '',
        resolution: '',
        status: 'pending',
    });

    const [editingQuery, setEditingQuery] = useState<SchoolQuery | null>(null);

    const isAdmin = currentUser.role === 'admin';

    useEffect(() => {
        if (isAdmin) {
            loadEmployees();
        }
        loadData();
    }, [currentUser.id, activeTab, selectedEmployeeId]);

    const loadEmployees = async () => {
        const data = await db.find<User>(Collections.USERS, { role: 'employee', is_active: true }, { sort: { full_name: 1 } });
        if (data) {
            setEmployees(data);
        }
    };

    const loadData = async () => {
        setLoading(true);
        setExpandedSchoolId(null);
        setSchoolQueriesMap(new Map());

        const today = getLocalDate();
        let schoolsData: School[] = [];

        if (isAdmin) {
            const allSchools = await db.find<School>(Collections.SCHOOLS, {}, { sort: { name: 1 } });
            if (selectedEmployeeId) {
                const assignments = await db.find<any>(Collections.SCHOOL_ASSIGNMENTS, { employee_id: selectedEmployeeId });
                const assignedSchoolIds = assignments.map(a => a.school_id);
                schoolsData = allSchools.filter(s => assignedSchoolIds.includes(s.id));
            } else {
                schoolsData = allSchools;
            }
        } else {
            const assignments = await db.find<any>(Collections.SCHOOL_ASSIGNMENTS, { employee_id: currentUser.id });
            if (!assignments || assignments.length === 0) {
                setSchools([]);
                setLoading(false);
                return;
            }
            const schoolIds = assignments.map(a => a.school_id);
            const allSchools = await db.find<School>(Collections.SCHOOLS, {}, { sort: { name: 1 } });
            schoolsData = allSchools.filter(s => schoolIds.includes(s.id));
        }

        if (schoolsData.length > 0) {
            const schoolsWithQueries = await Promise.all(
                schoolsData.map(async (school) => {
                    const filter: any = { school_id: school.id };
                    const queryList = await db.find<SchoolQuery>(Collections.SCHOOL_QUERIES, filter);

                    // Sort to find the latest
                    queryList.sort((a, b) => {
                        const dateA = new Date(a.received_date).getTime();
                        const dateB = new Date(b.received_date).getTime();
                        if (dateB !== dateA) return dateB - dateA;
                        const createdA = new Date(a.created_at || 0).getTime();
                        const createdB = new Date(b.created_at || 0).getTime();
                        return createdB - createdA;
                    });

                    const latestQuery = queryList[0];
                    const hasPendingQuery = queryList.some(q => q.status !== 'resolved');

                    return {
                        ...school,
                        latestQuery,
                        hasPendingQuery,
                    };
                })
            );

            let filtered = schoolsWithQueries;
            if (activeTab === 'today') {
                filtered = schoolsWithQueries.filter(s => s.latestQuery?.received_date === today);
            } else if (isAdmin && !selectedEmployeeId) {
                // Admin "All" view: show schools that have at least one query
                filtered = schoolsWithQueries.filter(s => s.latestQuery);
            }

            setSchools(filtered);
        } else {
            setSchools([]);
        }

        setLoading(false);
    };

    const loadSchoolHistory = async (schoolId: string) => {
        if (schoolQueriesMap.has(schoolId)) {
            setExpandedSchoolId(expandedSchoolId === schoolId ? null : schoolId);
            return;
        }

        setLoadingHistory(true);
        const filter: any = { school_id: schoolId };
        const historyData = await db.find<SchoolQuery>(
            Collections.SCHOOL_QUERIES,
            filter,
            { sort: { received_date: -1 } }
        );

        if (historyData) {
            const newMap = new Map(schoolQueriesMap);
            newMap.set(schoolId, historyData);
            setSchoolQueriesMap(newMap);
        }
        setExpandedSchoolId(schoolId);
        setLoadingHistory(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!selectedSchool) return;

        try {
            await db.insertOne(Collections.SCHOOL_QUERIES, {
                ...formData,
                school_id: selectedSchool.id,
                school_name: selectedSchool.name,
                created_at: new Date().toISOString(),
                updated_at: new Date().toISOString(),
            });

            setShowAddModal(false);
            setSelectedSchool(null);
            resetForm();
            loadData();
        } catch (error: any) {
            console.error('Error creating query:', error);
            alert('Failed to create query: ' + error.message);
        }
    };

    const handleEditSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!editingQuery) return;

        try {
            await db.updateById(Collections.SCHOOL_QUERIES, editingQuery.id!, {
                ...formData,
                updated_at: new Date().toISOString(),
            });

            setEditingQuery(null);
            setShowAddModal(false);
            resetForm();
            loadData();
        } catch (error: any) {
            console.error('Error updating query:', error);
            alert('Failed to update query: ' + error.message);
        }
    };

    const handleDelete = async (id: string, schoolId: string) => {
        if (!window.confirm('Are you sure you want to delete this query?')) return;
        try {
            await db.deleteById(Collections.SCHOOL_QUERIES, id);

            // Update local map if expanded
            if (schoolQueriesMap.has(schoolId)) {
                const updated = schoolQueriesMap.get(schoolId)!.filter(q => q.id !== id);
                const newMap = new Map(schoolQueriesMap);
                newMap.set(schoolId, updated);
                setSchoolQueriesMap(newMap);
            }

            loadData();
        } catch (error: any) {
            console.error('Error deleting query:', error);
            alert('Failed to delete query: ' + error.message);
        }
    };

    const resetForm = () => {
        setFormData({
            school_id: '',
            school_name: '',
            person_name: '',
            person_designation: '',
            received_date: getLocalDate(),
            resolved_by: '',
            resolved_date: '',
            source: 'call',
            department: '',
            query: '',
            resolution: '',
            status: 'pending',
        });
    };

    const formatDate = (dateString: string) => {
        if (!dateString) return '-';
        const date = new Date(dateString);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
    };

    const filteredSchools = schools.filter(school =>
        school.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        school.code?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    if (loading) {
        return <LoadingSpinner label="Loading Queries" />;
    }

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h2 className="text-2xl font-bold text-gray-900">Query Tracker</h2>
                    <p className="text-gray-600 mt-1">
