                                        <textarea
                                            value={formData.resolution}
                                            onChange={(e) => setFormData({ ...formData, resolution: e.target.value })}
                                            rows={3}
                                            className="w-full px-3 py-2 border border-gray-300 rounded-lg text-sm bg-white"
