import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { User, Student, School } from '../lib/models';
import { Users, Search } from 'lucide-react';

interface Props {
    currentUser: User;
}

export default function StudentListing({ currentUser }: Props) {
    const [students, setStudents] = useState<Student[]>([]);
    const [schools, setSchools] = useState<School[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [gradeFilter, setGradeFilter] = useState('all');

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        try {
            setLoading(true);
            const [studentsData, schoolsData] = await Promise.all([
                db.find<Student>(Collections.STUDENTS, {}),
                db.find<School>(Collections.SCHOOLS, {})
            ]);
            setStudents(studentsData);
            setSchools(schoolsData);
        } catch (error) {
            console.error('Error loading students:', error);
        } finally {
            setLoading(false);
        }
    };

    const getSchoolName = (id: string) => schools.find(s => s.id === id)?.name || 'Unknown';

    const filtered = students.filter(s => {
        const matchSearch = s.name.toLowerCase().includes(searchTerm.toLowerCase()) || getSchoolName(s.school_id).toLowerCase().includes(searchTerm.toLowerCase());
        const matchGrade = gradeFilter === 'all' || s.grade === gradeFilter;
        return matchSearch && matchGrade;
    });

    return (
        <div className="p-6">
            <div className="flex items-center gap-3 mb-6">
                <Users className="text-blue-600" size={28} />
                <h2 className="text-2xl font-bold text-gray-800">Students</h2>
                <span className="bg-blue-100 text-blue-700 px-2 py-1 rounded-full text-sm">{students.length}</span>
            </div>

            <div className="bg-white rounded-xl shadow-sm border p-4 mb-6 flex gap-3">
                <div className="relative flex-1">
                    <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
                    <input type="text" placeholder="Search students..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-10 pr-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500" />
                </div>
                <select value={gradeFilter} onChange={e => setGradeFilter(e.target.value)} className="px-3 py-2 border rounded-lg">
                    <option value="all">All Grades</option>
                    <option value="H1">H1</option>
                    <option value="H2">H2</option>
                    <option value="H3">H3</option>
                </select>
            </div>

            {loading ? (
                <div className="flex justify-center py-12"><div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div></div>
            ) : (
                <div className="bg-white rounded-xl shadow-sm border overflow-hidden">
                    <table className="w-full">
                        <thead className="bg-gray-50">
                            <tr>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Name</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Phone</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">School</th>
                                <th className="px-4 py-3 text-left text-xs font-semibold text-gray-600 uppercase">Grade</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y">
                            {filtered.length === 0 ? (
                                <tr><td colSpan={4} className="text-center py-8 text-gray-500">No students found</td></tr>
                            ) : filtered.map(student => (
                                <tr key={student.id} className="hover:bg-gray-50">
                                    <td className="px-4 py-3 text-sm font-medium text-gray-800">{student.name}</td>
                                    <td className="px-4 py-3 text-sm text-gray-500">{student.phone}</td>
                                    <td className="px-4 py-3 text-sm text-gray-500">{getSchoolName(student.school_id)}</td>
                                    <td className="px-4 py-3"><span className="px-2 py-1 bg-blue-100 text-blue-700 rounded-full text-xs">{student.grade}</span></td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Student, School } from '../lib/models';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { X, Plus, Edit2, Trash2, Search, UserPlus, Save } from 'lucide-react';
import LoadingSpinner from './LoadingSpinner';

interface Props {
    schoolId: string;
    teacherId?: string;
    onClose: () => void;
}

export default function StudentManager({ schoolId, teacherId, onClose }: Props) {
    const [students, setStudents] = useState<Student[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [filterGrade, setFilterGrade] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingStudent, setEditingStudent] = useState<Student | null>(null);
    const [school, setSchool] = useState<School | null>(null);
    const [formData, setFormData] = useState({
        name: '',
        roll_number: '',
        grade: 'H1' as 'H1' | 'H2' | 'H3',
        parent_name: '',
        parent_phone: '',
        gender: 'male' as 'male' | 'female' | 'other',
        status: 'active' as 'active' | 'inactive' | 'dropped'
    });

    useEffect(() => {
        loadData();
    }, [schoolId]);

    const loadData = async () => {
        setLoading(true);
        try {
            const filter: any = { school_id: schoolId };
            if (teacherId) {
                filter.teacher_id = teacherId;
            }
            const [studentsData, schoolData] = await Promise.all([
                db.find<Student>(Collections.STUDENTS, filter, { sort: { name: 1 } }),
                db.findById<School>(Collections.SCHOOLS, schoolId)
            ]);
            setStudents(studentsData);
            setSchool(schoolData);
        } catch (error) {
            console.error('Error loading data:', error);
        }
        setLoading(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            if (editingStudent && editingStudent.id) {
                await db.updateById(Collections.STUDENTS, editingStudent.id, {
                    ...formData,
                    updated_at: new Date().toISOString()
                });
            } else {
                await db.insertOne(Collections.STUDENTS, {
                    ...formData,
                    school_id: schoolId,
                    teacher_id: teacherId,
                    created_at: new Date().toISOString(),
                    updated_at: new Date().toISOString()
                } as any);
            }
            setShowModal(false);
            setEditingStudent(null);
            resetForm();
            loadData();
        } catch (error) {
            console.error('Error saving student:', error);
        }
    };

    const handleDelete = async (id: string) => {
        if (confirm('Are you sure you want to delete this student?')) {
            try {
                await db.deleteById(Collections.STUDENTS, id);
                loadData();
            } catch (error) {
                console.error('Error deleting student:', error);
            }
        }
    };

    const resetForm = () => {
        setFormData({
            name: '',
            roll_number: '',
            grade: 'H1',
            parent_name: '',
            parent_phone: '',
            gender: 'male',
            status: 'active'
        });
    };

    const openEditModal = (student: Student) => {
        setEditingStudent(student);
        setFormData({
            name: student.name,
            roll_number: student.roll_number || '',
            grade: student.grade,
            parent_name: student.parent_name || '',
            parent_phone: student.parent_phone || '',
            gender: (student as any).gender || 'male',
            status: student.status || 'active'
        });
        setShowModal(true);
    };

    const filteredStudents = students.filter(s =>
        (s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            (s.roll_number && s.roll_number.toLowerCase().includes(searchTerm.toLowerCase()))) &&
        (!filterGrade || s.grade === filterGrade)
    );

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
            <div className="bg-white w-full max-w-4xl max-h-[90vh] rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200">
                <div className="px-6 py-4 bg-blue-600 text-white flex justify-between items-center shadow-lg">
                    <div>
                        <h2 className="text-xl font-bold flex items-center gap-2">
                            <UserPlus size={24} />
                            Student Manager
                        </h2>
                        <p className="text-blue-100 text-sm mt-0.5">{school?.name || 'Loading...'}</p>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-white/20 rounded-full transition-colors">
                        <X size={24} />
                    </button>
                </div>

                <div className="p-6 border-b border-gray-100 bg-gray-50 flex flex-col md:flex-row gap-4 items-center justify-between">
                    <div className="flex flex-1 items-center gap-3 w-full">
                        <div className="relative flex-1 max-w-sm">
                            <input
                                type="text"
                                placeholder="Search students..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                            />
                            <Search className="absolute left-3 top-2.5 text-gray-400" size={18} />
                        </div>
                        <select
                            value={filterGrade}
                            onChange={(e) => setFilterGrade(e.target.value)}
                            className="px-4 py-2 bg-white border border-gray-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 text-sm"
                        >
                            <option value="">All Grades</option>
                            <option value="H1">Grade H1</option>
                            <option value="H2">Grade H2</option>
                            <option value="H3">Grade H3</option>
                        </select>
                    </div>
                    <button
                        onClick={() => { resetForm(); setEditingStudent(null); setShowModal(true); }}
                        className="flex items-center gap-2 bg-blue-600 text-white px-5 py-2 rounded-xl hover:bg-blue-700 transition-all font-bold shadow-md shadow-blue-200 w-full md:w-auto text-sm"
                    >
                        <Plus size={20} />
                        Add Student
                    </button>
                </div>

                <div className="flex-1 overflow-y-auto p-6 bg-white">
                    {loading ? (
                        <div className="flex justify-center items-center h-48">
                            <LoadingSpinner label="Loading students..." />
                        </div>
                    ) : filteredStudents.length === 0 ? (
                        <div className="flex flex-col items-center justify-center py-20 bg-gray-50/50 rounded-3xl border border-dashed border-gray-200">
                            <div className="bg-gray-100 p-4 rounded-full mb-4">
                                <Search size={32} className="text-gray-400" />
                            </div>
                            <p className="text-gray-500 font-medium">No students found</p>
                            <button
                                onClick={() => { resetForm(); setEditingStudent(null); setShowModal(true); }}
                                className="text-blue-600 font-bold mt-2 hover:underline"
                            >
                                Add your first student
                            </button>
                        </div>
                    ) : (
                        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                            {filteredStudents.map(student => (
                                <div key={student.id} className="group bg-white p-4 rounded-2xl border border-gray-100 hover:border-blue-200 hover:shadow-xl hover:shadow-blue-500/5 transition-all relative overflow-hidden">
                                    <div className={`absolute top-0 right-0 w-1 h-full ${student.grade === 'H1' ? 'bg-emerald-400' : student.grade === 'H2' ? 'bg-amber-400' : 'bg-blue-400'}`} />
                                    <div className="flex items-start justify-between mb-3">
                                        <div className="flex items-center gap-3">
                                            <div className="w-10 h-10 bg-gray-50 rounded-xl flex items-center justify-center group-hover:bg-blue-50 transition-colors">
                                                <span className="text-lg font-bold text-gray-700 group-hover:text-blue-600">{student.name.charAt(0)}</span>
                                            </div>
                                            <div>
                                                <h4 className="font-bold text-gray-900 leading-tight">{student.name}</h4>
                                                <p className="text-xs text-gray-400 font-medium">Roll: {student.roll_number || 'N/A'}</p>
                                            </div>
                                        </div>
                                        <div className="flex gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button onClick={() => openEditModal(student)} className="p-1.5 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg"><Edit2 size={16} /></button>
                                            <button onClick={() => student.id && handleDelete(student.id)} className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg"><Trash2 size={16} /></button>
                                        </div>
                                    </div>
                                    <div className="grid grid-cols-2 gap-2 text-xs">
                                        <div className="bg-gray-50 rounded-lg p-2">
                                            <p className="text-gray-400 mb-0.5">Grade</p>
                                            <p className="font-bold text-gray-900 border-l-2 border-current px-2 -ml-1" style={{ color: student.grade === 'H1' ? '#10b981' : student.grade === 'H2' ? '#f59e0b' : '#3b82f6' }}>{student.grade}</p>
                                        </div>
                                        <div className="bg-gray-50 rounded-lg p-2">
                                            <p className="text-gray-400 mb-0.5">Status</p>
                                            <p className={`font-bold capitalize ${student.status === 'active' ? 'text-emerald-600' : student.status === 'dropped' ? 'text-rose-500' : 'text-gray-500'}`}>{student.status}</p>
                                        </div>
                                    </div>
                                    <div className="mt-3 pt-3 border-t border-gray-50">
                                        <div className="flex items-center gap-2 text-xs text-gray-500">
                                            <p className="truncate"><span className="font-medium">Parent:</span> {student.parent_name || 'N/A'}</p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {showModal && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
                    <div className="bg-white w-full max-w-lg rounded-2xl shadow-2xl animate-in fade-in zoom-in-95 duration-200">
                        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50/50 rounded-t-2xl">
                            <div>
                                <h3 className="text-xl font-black text-gray-900">{editingStudent ? 'Edit' : 'Add New'} Student</h3>
                                <p className="text-xs text-gray-500 uppercase tracking-widest font-bold mt-1">Student Particulars</p>
                            </div>
                            <button onClick={() => setShowModal(false)} className="p-2 hover:bg-gray-100 rounded-full"><X size={20} /></button>
                        </div>
                        <form onSubmit={handleSubmit} className="p-6 space-y-5">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="col-span-2">
                                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Full Name</label>
                                    <input
                                        required
                                        type="text"
                                        value={formData.name}
                                        onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                                        placeholder="Enter full name"
                                    />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Roll Number</label>
                                    <input
                                        type="text"
                                        value={formData.roll_number}
                                        onChange={(e) => setFormData({ ...formData, roll_number: e.target.value })}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                                        placeholder="e.g. 001"
                                    />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Grade</label>
                                    <select
                                        value={formData.grade}
                                        onChange={(e) => setFormData({ ...formData, grade: e.target.value as any })}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                                    >
                                        <option value="H1">Grade H1</option>
                                        <option value="H2">Grade H2</option>
                                        <option value="H3">Grade H3</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Parent Name</label>
                                    <input
                                        type="text"
                                        value={formData.parent_name}
                                        onChange={(e) => setFormData({ ...formData, parent_name: e.target.value })}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                                        placeholder="Father/Mother name"
                                    />
                                </div>
                                <div>
                                    <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1.5 ml-1">Parent Phone</label>
                                    <input
                                        type="tel"
                                        value={formData.parent_phone}
                                        onChange={(e) => setFormData({ ...formData, parent_phone: e.target.value })}
                                        className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:outline-none font-bold"
                                        placeholder="10-digit number"
                                    />
                                </div>
                            </div>

                            <div className="flex gap-3 pt-2">
                                <button
                                    type="button"
                                    onClick={() => setShowModal(false)}
                                    className="flex-1 px-6 py-3 border border-gray-200 text-gray-600 rounded-xl font-bold hover:bg-gray-50 transition-colors"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    className="flex-[2] px-6 py-3 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-200 flex items-center justify-center gap-2"
                                >
                                    <Save size={18} />
                                    {editingStudent ? 'Update Student' : 'Save Student'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

import { useState, useEffect } from 'react';
import { db } from '../lib/services/db';
import { Collections } from '../lib/constants';
import { Student, StudentAssessment, School } from '../lib/models';
import { ArrowLeft, User as UserIcon, Calendar, TrendingUp, CheckCircle2, Clock, BookOpen, Building2 } from 'lucide-react';
import { THEMES } from './StudentAssessmentForm';
import LoadingSpinner from './LoadingSpinner';

interface Props {
    student: Student;
    onBack: () => void;
}

export default function StudentProfileView({ student, onBack }: Props) {
    const [assessments, setAssessments] = useState<StudentAssessment[]>([]);
    const [school, setSchool] = useState<School | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadStudentData();
    }, [student]);

    const loadStudentData = async () => {
        setLoading(true);
        try {
            const [assessmentsData, schoolData] = await Promise.all([
                db.find<StudentAssessment>(Collections.STUDENT_ASSESSMENTS, { student_id: student.id }),
                db.findById<School>(Collections.SCHOOLS, student.school_id)
            ]);
            setAssessments(assessmentsData);
            setSchool(schoolData);
        } catch (error) {
            console.error('Error loading student profile data:', error);
        }
        setLoading(false);
    };

    // Calculate some simple stats
    const totalAssessments = assessments.length;
    const lastAssessed = assessments.length > 0
        ? new Date(Math.max(...assessments.map(a => new Date(a.updated_at || a.created_at).getTime()))).toLocaleDateString()
        : 'Never';

    // Basic mastery calculation (average of all skills if present)
    let totalMastery = 0;
    let masteryCount = 0;

    assessments.forEach(ass => {
        if (ass.skills) {
            const skills = Object.values(ass.skills);
            if (skills.length > 0) {
                const canCount = skills.filter(s => s === 'can').length;
                const totalSkills = skills.length;
                totalMastery += (canCount / totalSkills) * 100;
                masteryCount++;
            }
        }
    });

    const averageMastery = masteryCount > 0 ? Math.round(totalMastery / masteryCount) : 0;

    if (loading) return <LoadingSpinner label="Loading student profile..." />;

    return (
        <div className="space-y-6">
            {/* Navigation Header */}
            <button
                onClick={onBack}
                className="flex items-center gap-2 text-blue-600 hover:text-blue-800 font-medium transition-colors"
            >
                <ArrowLeft size={20} />
                Back to Student List
            </button>

            {/* Profile Header Card */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="h-32 bg-gradient-to-r from-blue-600 to-indigo-700"></div>
                <div className="px-6 pb-6">
                    <div className="relative flex flex-col md:flex-row md:items-end gap-6 -mt-12">
                        <div className="w-32 h-32 bg-white rounded-2xl shadow-lg border-4 border-white flex items-center justify-center text-blue-600">
                            <UserIcon size={64} />
                        </div>
                        <div className="flex-1 pb-2">
                            <h1 className="text-3xl font-bold text-gray-900">{student.name}</h1>
                            <div className="flex flex-wrap items-center gap-4 mt-2 text-gray-600">
                                <div className="flex items-center gap-1.5">
                                    <Building2 size={16} />
                                    <span>{school?.name || 'Loading school...'}</span>
                                </div>
                                <div className="flex items-center gap-1.5">
                                    <BookOpen size={16} />
                                    <span>Grade {student.grade} {student.section ? `(${student.section})` : ''}</span>
                                </div>
                                <div className="flex items-center gap-1.5">
                                    <Calendar size={16} />
                                    <span>Added {new Date(student.created_at).toLocaleDateString()}</span>
                                </div>
                            </div>
                        </div>
                        <div className="pb-2">
                            <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-sm font-bold border border-green-200">
                                Active Student
                            </span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                    <div className="flex items-center justify-between mb-4">
                        <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Overall Mastery</p>
                        <TrendingUp className="text-blue-600" size={20} />
                    </div>
                    <div className="flex items-end gap-2">
                        <span className="text-4xl font-bold text-gray-900">{averageMastery}%</span>
                        <div className="mb-2 w-full h-2 bg-gray-100 rounded-full overflow-hidden">
                            <div
                                className="h-full bg-blue-600 transition-all duration-1000"
                                style={{ width: `${averageMastery}%` }}
                            />
                        </div>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                    <div className="flex items-center justify-between mb-4">
                        <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Total Assessments</p>
                        <CheckCircle2 className="text-emerald-600" size={20} />
                    </div>
                    <div className="flex items-baseline gap-2">
                        <span className="text-4xl font-bold text-gray-900">{totalAssessments}</span>
                        <span className="text-gray-500 font-medium">Themes Completed</span>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-200">
                    <div className="flex items-center justify-between mb-4">
                        <p className="text-sm font-medium text-gray-500 uppercase tracking-wider">Last Activity</p>
                        <Clock className="text-orange-600" size={20} />
                    </div>
                    <div className="flex items-baseline gap-2">
                        <span className="text-2xl font-bold text-gray-900">{lastAssessed}</span>
                    </div>
                </div>
            </div>

            {/* Detailed Theme Progress */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="p-6 border-b border-gray-100 bg-gray-50/30">
                    <h3 className="text-lg font-bold text-gray-900">Thematic Progress Breakdown</h3>
                </div>
                <div className="p-6">
                    <div className="space-y-6">
                        {THEMES.map(theme => {
                            const assessment = assessments.find(a => a.theme_number === theme.id);
                            let mastery = 0;
                            if (assessment?.skills) {
                                const skills = Object.values(assessment.skills);
                                const canCount = skills.filter(s => s === 'can').length;
                                mastery = Math.round((canCount / skills.length) * 100);
                            }

                            return (
                                <div key={theme.id} className="group">
                                    <div className="flex items-center justify-between mb-2">
                                        <span className="font-bold text-gray-800 group-hover:text-blue-600 transition-colors uppercase text-sm tracking-wide">
                                            {theme.name.split(':')[0]}
                                        </span>
                                        <span className="text-sm font-bold text-gray-900 bg-gray-100 px-2.5 py-1 rounded-lg">
                                            {assessment ? `${mastery}% Mastery` : 'Not Started'}
                                        </span>
                                    </div>
                                    <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
                                        <div
                                            className={`h-full transition-all duration-1000 ${assessment ? (mastery >= 80 ? 'bg-green-500' : mastery >= 50 ? 'bg-blue-500' : 'bg-orange-500') : 'bg-gray-200'}`}
                                            style={{ width: `${mastery}%` }}
                                        />
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        </div>
    );
}

