    first_name: string;
    last_name: string;
    email: string;
    phone: string;
    position: string;
    department: string;
    hire_date: string | null;
    status: 'active' | 'inactive';
    created_at: string;
    updated_at: string;
};

import {
    collection,
    doc,
    getDoc,
    getDocs,
    addDoc,
    setDoc,
    updateDoc,
    deleteDoc,
    query,
    where,
    limit,
    getCountFromServer,
    DocumentData,
    QueryConstraint,
    writeBatch,
    onSnapshot,
    orderBy
} from 'firebase/firestore';
import { db as firestore } from '../firebase';

// Define generic types to replace MongoDB driver types
export type Document = Record<string, any>;
export type Filter<T> = Record<string, any>;
export type UpdateFilter<T> = Record<string, any>;
export type OptionalId<T> = T & { _id?: string };

/**
 * Frontend Database Service
 * Replaces direct MongoDB connection with Firebase Firestore SDK
 */
class DatabaseService {
    /**
     * Clean document data by removing undefined values (unsupported by Firestore)
     */
    private cleanData(data: Record<string, any>): Record<string, any> {
        const cleaned: Record<string, any> = {};
        Object.entries(data).forEach(([key, value]) => {
            if (value !== undefined) {
                // Also clean nested objects recursively if they are plain objects
                if (typeof value === 'object' && value !== null && !Array.isArray(value) && !(value instanceof Date)) {
                    cleaned[key] = this.cleanData(value);
                } else {
                    cleaned[key] = value;
                }
            }
        });
        return cleaned;
    }

    /**
     * Find multiple documents in a collection
     */
    async find<T extends Document>(
        collectionName: string,
        filter: Filter<T> = {},
        options: {
            sort?: Record<string, 1 | -1>;
            limit?: number;
            skip?: number; // Firestore doesn't support skip efficiently, we might need to ignore or use cursors
        } = {}
    ): Promise<T[]> {
        try {
            const constraints: QueryConstraint[] = [];
            let hasInFilter = false;
            let inKey = '';
            let inValues: any[] = [];

            // Apply filters with MongoDB-style operator support
            Object.entries(filter).forEach(([key, value]) => {
                if (value !== undefined) {
                    // Check if value is an object with operators
                    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
                        Object.entries(value).forEach(([operator, operand]) => {
                            switch (operator) {
                                case '$in':
                                    if (Array.isArray(operand)) {
                                        // Validate non-empty array
                                        if (operand.length === 0) {
                                            // Return empty result early if $in array is empty
                                            console.warn(`Empty array for $in filter on field '${key}', returning empty results`);
                                            hasInFilter = true;
                                            inValues = [];
                                        } else if (operand.length > 30) {
                                            // Firestore limit: max 30 values per 'in' query
                                            // We'll need to batch this
                                            hasInFilter = true;
                                            inKey = key;
                                            inValues = operand;
                                        } else {
                                            constraints.push(where(key, 'in', operand));
                                        }
                                    }
                                    break;
                                case '$lte':
                                    constraints.push(where(key, '<=', operand));
                                    break;
                                case '$gte':
                                    constraints.push(where(key, '>=', operand));
                                    break;
                                case '$lt':
                                    constraints.push(where(key, '<', operand));
                                    break;
                                case '$gt':
                                    constraints.push(where(key, '>', operand));
                                    break;
                                case '$ne':
                                    constraints.push(where(key, '!=', operand));
                                    break;
                                default:
                                    // Unknown operator, treat as equality
                                    constraints.push(where(key, '==', value));
                            }
                        });
                    } else {
                        // Simple equality
                        constraints.push(where(key, '==', value));
                    }
                }
            });

            // Handle empty $in array early
            if (hasInFilter && inValues.length === 0) {
                return [];
            }

            // Handle large $in arrays (> 30 items) by batching
            if (hasInFilter && inValues.length > 30) {
                const results: T[] = [];
                const batches = Math.ceil(inValues.length / 30);

                for (let i = 0; i < batches; i++) {
                    const batchValues = inValues.slice(i * 30, (i + 1) * 30);
                    const batchConstraints = [...constraints, where(inKey, 'in', batchValues)];

                    if (options.limit) {
                        batchConstraints.push(limit(options.limit));
                    }

                    const q = query(collection(firestore, collectionName), ...batchConstraints);
                    const querySnapshot = await getDocs(q);

                    querySnapshot.docs.forEach(doc => {
                        results.push({
                            id: doc.id,
                            ...doc.data()
                        } as unknown as T);
                    });

                    // If we've hit the limit, stop
                    if (options.limit && results.length >= options.limit) {
                        break;
                    }
                }

                // Apply limit if specified
                return options.limit ? results.slice(0, options.limit) : results;
            }

            // Apply sort
            // NOTE: Server-side sorting disabled to avoid Firestore index requirements.
            // Sorting should be handled client-side after fetching data.
            // if (options.sort) {
            //     Object.entries(options.sort).forEach(([key, direction]) => {
            //         constraints.push(orderBy(key, direction === 1 ? 'asc' : 'desc'));
            //     });
            // }

            // Apply limit
            if (options.limit) {
                constraints.push(limit(options.limit));
            }

            // Note: 'skip' is not directly supported in Firestore in the same way as MongoDB.
            // For now, we'll ignore it or handle pagination differently in the UI if needed.

            const q = query(collection(firestore, collectionName), ...constraints);
            const querySnapshot = await getDocs(q);

            return querySnapshot.docs.map(doc => ({
                id: doc.id,
                ...doc.data()
            })) as unknown as T[];
        } catch (error) {
            console.error(`Error finding documents in ${collectionName}:`, error);
            return [];
        }
    }

    /**
     * Find a single document in a collection
     */
    async findOne<T extends Document>(
        collectionName: string,
        filter: Filter<T>
    ): Promise<T | null> {
        const results = await this.find<T>(collectionName, filter, { limit: 1 });
        return results[0] || null;
    }

    /**
     * Find a document by ID
     */
    async findById<T extends Document>(
        collectionName: string,
        id: string
    ): Promise<T | null> {
        try {
            const docRef = doc(firestore, collectionName, id);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                return {
                    id: docSnap.id,
                    ...docSnap.data()
                } as unknown as T;
            } else {
                return null;
            }
        } catch (error) {
            console.error(`Error finding document by ID in ${collectionName}:`, error);
            return null;
        }
    }

    /**
     * Insert a single document
     */
    async insertOne<T extends Document>(
        collectionName: string,
        document: OptionalId<T>
    ): Promise<T> {
        try {
            // If document has an ID, use setDoc, otherwise addDoc
            const { _id, id, ...data } = document as any;
            const docId = id || _id;
            const cleanedData = this.cleanData(data);

            if (docId) {
                await setDoc(doc(firestore, collectionName, docId), cleanedData);
                return { id: docId, ...cleanedData } as unknown as T;
            } else {
                const docRef = await addDoc(collection(firestore, collectionName), cleanedData);
                return { id: docRef.id, ...cleanedData } as unknown as T;
            }
        } catch (error) {
            console.error(`Error inserting document into ${collectionName}:`, error);
            throw error;
        }
    }

    /**
     * Insert multiple documents
     */
    async insertMany<T extends Document>(
        collectionName: string,
        documents: OptionalId<T>[]
    ): Promise<T[]> {
        try {
            const batch = writeBatch(firestore);
            const results: T[] = [];

            documents.forEach(docData => {
                const { _id, id, ...data } = docData as any;
                const docId = id || _id;
                const cleanedData = this.cleanData(data);

                let docRef;
                if (docId) {
                    docRef = doc(firestore, collectionName, docId);
                } else {
                    docRef = doc(collection(firestore, collectionName));
                }

                batch.set(docRef, cleanedData);
                results.push({ id: docRef.id, ...cleanedData } as unknown as T);
            });

            await batch.commit();
            return results;
        } catch (error) {
            console.error(`Error inserting multiple documents into ${collectionName}:`, error);
            throw error;
        }
    }

    /**
     * Update a document by ID
     */
    async updateById<T extends Document>(
        collectionName: string,
        id: string,
        update: Partial<T>
    ): Promise<boolean> {
        try {
            const docRef = doc(firestore, collectionName, id);
            const cleanedUpdate = this.cleanData(update as DocumentData);
            await updateDoc(docRef, cleanedUpdate);
            return true;
        } catch (error) {
            console.error(`Error updating document ${id} in ${collectionName}:`, error);
            return false;
        }
    }

    /**
     * Delete a document by ID
     */
    async deleteById(collectionName: string, id: string): Promise<boolean> {
        try {
            await deleteDoc(doc(firestore, collectionName, id));
            return true;
        } catch (error) {
            console.error(`Error deleting document ${id} from ${collectionName}:`, error);
            return false;
        }
    }

    /**
     * Delete multiple documents
     */
    async deleteMany<T extends Document>(
        collectionName: string,
        filter: Filter<T>
    ): Promise<boolean> {
        try {
            const items = await this.find<T>(collectionName, filter);
            if (items.length === 0) return true;

            const batch = writeBatch(firestore);
            items.forEach(item => {
                const id = (item as any).id || (item as any)._id;
                if (id) {
                    batch.delete(doc(firestore, collectionName, id));
                }
            });

            await batch.commit();
            return true;
        } catch (error) {
            console.error(`Error deleting multiple documents from ${collectionName}:`, error);
            return false;
        }
    }

    /**
     * Count documents
     */
    async count<T extends Document>(
        collectionName: string,
        filter: Filter<T> = {}
    ): Promise<number> {
        try {
            const constraints: QueryConstraint[] = [];
            let hasEmptyInFilter = false;
            let inKey = '';
            let inValues: any[] = [];
            let hasInFilter = false;

            // Apply filters with MongoDB-style operator support
            Object.entries(filter).forEach(([key, value]) => {
                if (value !== undefined) {
                    // Check if value is an object with operators
                    if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
                        Object.entries(value).forEach(([operator, operand]) => {
                            switch (operator) {
                                case '$in':
                                    if (Array.isArray(operand)) {
                                        // Validate non-empty array
                                        if (operand.length === 0) {
                                            console.warn(`Empty array for $in filter on field '${key}', returning 0 count`);
                                            hasEmptyInFilter = true;
                                        } else if (operand.length > 30) {
                                            // Firestore has 30-item limit, need to batch
                                            hasInFilter = true;
                                            inKey = key;
                                            inValues = operand;
                                        } else {
                                            constraints.push(where(key, 'in', operand));
                                        }
                                    }
                                    break;
                                case '$lte':
                                    constraints.push(where(key, '<=', operand));
                                    break;
                                case '$gte':
                                    constraints.push(where(key, '>=', operand));
                                    break;
                                case '$lt':
                                    constraints.push(where(key, '<', operand));
                                    break;
                                case '$gt':
                                    constraints.push(where(key, '>', operand));
                                    break;
                                case '$ne':
                                    constraints.push(where(key, '!=', operand));
                                    break;
                                default:
                                    // Unknown operator, treat as equality
                                    constraints.push(where(key, '==', value));
                            }
                        });
                    } else {
                        // Simple equality
                        constraints.push(where(key, '==', value));
                    }
                }
            });

            // Return 0 if empty $in array
            if (hasEmptyInFilter) {
                return 0;
            }

            // Handle large $in arrays (> 30 items) by batching
            if (hasInFilter && inValues.length > 30) {
                let totalCount = 0;
                const batches = Math.ceil(inValues.length / 30);

                for (let i = 0; i < batches; i++) {
                    const batchValues = inValues.slice(i * 30, (i + 1) * 30);
                    const batchConstraints = [...constraints, where(inKey, 'in', batchValues)];

                    const q = query(collection(firestore, collectionName), ...batchConstraints);
                    const snapshot = await getCountFromServer(q);
                    totalCount += snapshot.data().count;
                }

                return totalCount;
            }

            const q = query(collection(firestore, collectionName), ...constraints);
            const snapshot = await getCountFromServer(q);
            return snapshot.data().count;
        } catch (error) {
            console.error(`Error counting documents in ${collectionName}:`, error);
            return 0;
        }
    }

    /**
     * Upsert a document
     */
    async upsert<T extends Document>(
        collectionName: string,
        filter: Filter<T>,
        document: Partial<T>
    ): Promise<T> {
        try {
            const existing = await this.findOne<T>(collectionName, filter);
            if (existing) {
                const id = (existing as any).id || (existing as any)._id;
                await this.updateById(collectionName, id, document);
                return { ...existing, ...document };
            } else {
                return await this.insertOne(collectionName, document as any);
            }
        } catch (error) {
            console.error(`Error upserting document in ${collectionName}:`, error);
            throw error;
        }
    }

    /**
     * Aggregate (simulated via find)
     */
    async aggregate<T extends Document>(
        collectionName: string,
        _pipeline: any[]
    ): Promise<T[]> {
        console.warn('Aggregation not fully supported in Firestore client. Using find fallback.');
        // Fallback: fetch all and let the caller handle logic (inefficient but safe for small datasets)
        return this.find<T>(collectionName, {});
    }

    /**
     * Subscribe to real-time updates
     */
    subscribe<T extends Document>(
        collectionName: string,
        filter: Filter<T>,
        callback: (data: T[]) => void,
        options: {
            sort?: Record<string, 1 | -1>;
            limit?: number;
        } = {}
    ): () => void {
        try {
            const constraints: QueryConstraint[] = [];

            // Apply filters
            Object.entries(filter).forEach(([key, value]) => {
                if (value !== undefined) {
                    constraints.push(where(key, '==', value));
                }
            });

            // Apply sort
            if (options.sort) {
                Object.entries(options.sort).forEach(([key, direction]) => {
                    constraints.push(orderBy(key, direction === 1 ? 'asc' : 'desc'));
                });
            }

            // Apply limit
            if (options.limit) {
                constraints.push(limit(options.limit));
            }

            const q = query(collection(firestore, collectionName), ...constraints);

            return onSnapshot(q, (snapshot) => {
                const results = snapshot.docs.map(doc => ({
                    id: doc.id,
                    ...doc.data()
                })) as unknown as T[];
                callback(results);
            }, (error) => {
                console.error(`Error subscribing to ${collectionName}:`, error);
            });
        } catch (error) {
            console.error(`Error setting up subscription for ${collectionName}:`, error);
            return () => { };
        }
    }

    // Convenience aliases
    async create<T extends Document>(collectionName: string, data: any): Promise<T> {
        return this.insertOne<T>(collectionName, data);
    }

    async update<T extends Document>(collectionName: string, id: string, data: Partial<T>): Promise<boolean> {
        return this.updateById<T>(collectionName, id, data);
    }

    async updateOne<T extends Document>(collectionName: string, id: string, data: Partial<T>): Promise<boolean> {
        return this.updateById<T>(collectionName, id, data);
    }

    async delete(collectionName: string, id: string): Promise<boolean> {
        return this.deleteById(collectionName, id);
    }

    // Activity logging
    async logActivity(data: {
        user_id: string;
        user_name: string;
        user_role: string;
        action: string;
        view?: string;
        details?: string;
        school_id?: string;
    }): Promise<void> {
        try {
            await this.insertOne('activity_logs', {
                ...data,
                created_at: new Date().toISOString()
            });
        } catch (error) {
            console.error('Error logging activity:', error);
        }
    }
}

export const db = new DatabaseService();

/**
 * Gemini AI Service for Followup Sentiment Analysis
 * Uses Google's Gemini 2.0 Flash model for intelligent comment analysis
 */

const GEMINI_API_KEY = import.meta.env.VITE_GEMINI_API_KEY;
const GEMINI_API_URL = 'https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent';

// Debug log
console.log('Gemini API Key loaded:', GEMINI_API_KEY ? 'Yes (hidden)' : 'No');

export interface SentimentResult {
    original: string;
    sentiment: 'positive' | 'neutral' | 'critical';
    category: string;
    summary: string;
}

export interface AnalysisResponse {
    results: SentimentResult[];
    overallHealth: 'healthy' | 'at_risk' | 'critical';
    topIssues: string[];
    recommendations: string[];
}

/**
 * Analyzes followup comments using Gemini AI
 * @param comments Array of followup comment strings
 * @returns Promise with sentiment analysis results
 */
export async function analyzeFollowupSentiments(
    comments: { id: string; comment: string; schoolName: string; employeeName: string; date: string }[]
): Promise<AnalysisResponse> {
    if (!GEMINI_API_KEY) {
        console.warn('Gemini API key not configured, falling back to keyword analysis');
        return fallbackAnalysis(comments);
    }

    if (comments.length === 0) {
        return {
            results: [],
            overallHealth: 'healthy',
            topIssues: [],
            recommendations: []
        };
    }

    const prompt = `You are an education management system analyst. Analyze these school followup comments from field employees and provide sentiment analysis.

For each comment, determine:
1. Sentiment: "positive" (good progress, no issues), "neutral" (routine update), or "critical" (problems, delays, complaints)
2. Category: One of "Books/Orders", "Training/Academics", "Management/Admin", "Payments/Fees", "Infrastructure", or "General"
3. Summary: A brief 5-10 word summary of the key point

Also provide:
- Overall health status of the school relationships
- Top 3 issues that need attention (if any)
- 2-3 actionable recommendations

IMPORTANT: Comments like "No issues", "Everything is fine", "Going smoothly" should be marked as POSITIVE, not critical.

Comments to analyze:
${comments.map((c, i) => `${i + 1}. [${c.schoolName}] (${c.date}): "${c.comment}"`).join('\n')}

Respond in this exact JSON format:
{
  "results": [
    {"index": 0, "sentiment": "positive|neutral|critical", "category": "...", "summary": "..."},
    ...
  ],
  "overallHealth": "healthy|at_risk|critical",
  "topIssues": ["issue1", "issue2", "issue3"],
  "recommendations": ["rec1", "rec2"]
}`;

    try {
        const response = await fetch(`${GEMINI_API_URL}?key=${GEMINI_API_KEY}`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                contents: [{ parts: [{ text: prompt }] }],
                generationConfig: {
                    temperature: 0.2,
                    maxOutputTokens: 2048,
                }
            })
        });

        if (!response.ok) {
            console.error('Gemini API error:', response.status, await response.text());
            return fallbackAnalysis(comments);
        }

        const data = await response.json();
        const textResponse = data.candidates?.[0]?.content?.parts?.[0]?.text || '';

        // Extract JSON from response (handle markdown code blocks)
        let jsonStr = textResponse;
        const jsonMatch = textResponse.match(/```json\n?([\s\S]*?)\n?```/);
        if (jsonMatch) {
            jsonStr = jsonMatch[1];
        } else {
            // Try to find raw JSON
            const startIdx = textResponse.indexOf('{');
            const endIdx = textResponse.lastIndexOf('}');
            if (startIdx !== -1 && endIdx !== -1) {
                jsonStr = textResponse.substring(startIdx, endIdx + 1);
            }
        }

        const parsed = JSON.parse(jsonStr);

        // Map results back to original comments
        const results: SentimentResult[] = comments.map((c, i) => {
            const aiResult = parsed.results?.find((r: any) => r.index === i) || parsed.results?.[i];
            return {
                original: c.comment,
                sentiment: aiResult?.sentiment || 'neutral',
                category: aiResult?.category || 'General',
                summary: aiResult?.summary || c.comment.substring(0, 50)
            };
        });

        return {
            results,
            overallHealth: parsed.overallHealth || 'healthy',
            topIssues: parsed.topIssues || [],
            recommendations: parsed.recommendations || []
        };

    } catch (error) {
        console.error('Gemini analysis failed:', error);
        return fallbackAnalysis(comments);
    }
}

/**
 * Fallback keyword-based analysis when AI is unavailable
 */
function fallbackAnalysis(
    comments: { id: string; comment: string; schoolName: string; employeeName: string; date: string }[]
): AnalysisResponse {
    const CRITICAL_KEYWORDS = ['urgent', 'critical', 'problem', 'complaint', 'delay', 'issue', 'bad', 'angry', 'rejection', 'quit', 'stop', 'serious', 'negative'];
    const POSITIVE_KEYWORDS = ['no issues', 'going on', 'smooth', 'everything ok', 'good', 'satisfied', 'positive', 'happy', 'resolved', 'fine'];
    const EXCLUSION_PHRASES = ['no issues', 'no problem', 'issue resolved'];

    const results: SentimentResult[] = comments.map(c => {
        const text = c.comment.toLowerCase();

        const isCritical = CRITICAL_KEYWORDS.some(k => text.includes(k)) &&
            !EXCLUSION_PHRASES.some(p => text.includes(p));
        const isPositive = POSITIVE_KEYWORDS.some(k => text.includes(k));

        return {
            original: c.comment,
            sentiment: isCritical ? 'critical' : isPositive ? 'positive' : 'neutral',
            category: 'General',
            summary: c.comment.substring(0, 50) + (c.comment.length > 50 ? '...' : '')
        };
    });

    const criticalCount = results.filter(r => r.sentiment === 'critical').length;
    const overallHealth = criticalCount > results.length * 0.3 ? 'critical' :
        criticalCount > 0 ? 'at_risk' : 'healthy';

    return {
        results,
        overallHealth,
        topIssues: [],
        recommendations: ['Enable Gemini AI for detailed analysis']
    };
}
